{
  "name": "UberClone Pro - Multimodal Transport System",
  "description": "A sophisticated Uber clone featuring specialized dashboards for Admins, Drivers, and Riders, including real-time ride tracking, earnings management, and AI-powered route insights.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  DRIVER = 'DRIVER',
  RIDER = 'RIDER'
}

export enum RideStatus {
  REQUESTED = 'REQUESTED',
  ACCEPTED = 'ACCEPTED',
  PICKUP = 'PICKUP',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
  // Driver specific
  licensePlate?: string;
  vehicleModel?: string;
  rating?: number;
  earnings?: number;
  isOnline?: boolean;
}

export interface Location {
  lat: number;
  lng: number;
  address: string;
}

export interface Ride {
  id: string;
  riderId: string;
  driverId?: string;
  origin: Location;
  destination: Location;
  status: RideStatus;
  price: number;
  timestamp: string;
  distance: string; // e.g., "5.2 km"
}

export interface AppState {
  currentUser: UserProfile | null;
  rides: Ride[];
  users: UserProfile[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getRideInsight = async (origin: string, destination: string, price: number) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide a very short, witty explanation of why a ride from ${origin} to ${destination} costs $${price.toFixed(2)}. Mention one imaginary local landmark or traffic condition in Brazil context. Keep it under 20 words.`,
      config: {
        temperature: 0.7,
      }
    });
    return response.text || "Traffic is light, enjoy the ride!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Route optimized for safety and speed.";
  }
};

export const getAdminBriefing = async (activeRides: number, totalRevenue: number) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are a logistics consultant. Briefly summarize performance: ${activeRides} active rides and $${totalRevenue} revenue. Suggest one growth tip.`,
      config: {
        temperature: 0.8,
      }
    });
    return response.text || "Operations are stable. Consider peak hour incentives.";
  } catch (error) {
    return "Operations running smoothly.";
  }
};

import React from 'react';

interface MapMockProps {
  className?: string;
  origin?: string;
  destination?: string;
  markers?: Array<{ lat: number, lng: number, type: 'driver' | 'rider' }>;
}

const MapMock: React.FC<MapMockProps> = ({ className, origin, destination, markers }) => {
  return (
    <div className={`relative overflow-hidden bg-slate-200 rounded-xl border border-slate-300 ${className}`}>
      {/* Visual Mock Map Background */}
      <div className="absolute inset-0 opacity-20 pointer-events-none">
        <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
              <path d="M 40 0 L 0 0 0 40" fill="none" stroke="gray" strokeWidth="0.5"/>
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#grid)" />
        </svg>
      </div>

      {/* Mock Roads */}
      <div className="absolute top-1/2 left-0 w-full h-8 bg-white/50 -rotate-12 border-y border-slate-400/20" />
      <div className="absolute top-0 left-1/3 w-8 h-full bg-white/50 rotate-6 border-x border-slate-400/20" />

      {/* Static Markers if locations provided */}
      {origin && (
        <div className="absolute top-1/4 left-1/4 flex flex-col items-center">
          <i className="fas fa-map-marker-alt text-red-500 text-2xl drop-shadow-md"></i>
          <span className="text-[10px] bg-white px-1 rounded border shadow-sm mt-1 whitespace-nowrap">{origin}</span>
        </div>
      )}
      {destination && (
        <div className="absolute bottom-1/4 right-1/4 flex flex-col items-center">
          <i className="fas fa-flag-checkered text-black text-2xl drop-shadow-md"></i>
          <span className="text-[10px] bg-white px-1 rounded border shadow-sm mt-1 whitespace-nowrap">{destination}</span>
        </div>
      )}

      {/* Dynamic Markers */}
      {markers?.map((m, idx) => (
        <div 
          key={idx}
          className="absolute transition-all duration-1000"
          style={{ top: `${m.lat}%`, left: `${m.lng}%` }}
        >
          <div className={`p-2 rounded-full shadow-lg ${m.type === 'driver' ? 'bg-black text-white' : 'bg-blue-500 text-white'}`}>
            <i className={`fas ${m.type === 'driver' ? 'fa-car' : 'fa-user'}`}></i>
          </div>
        </div>
      ))}

      <div className="absolute bottom-4 left-4 right-4 bg-white/90 p-2 rounded-lg text-xs font-medium text-slate-500 border border-slate-200 shadow-sm flex items-center justify-between">
        <span><i className="fas fa-satellite mr-2 text-indigo-500"></i> Localização via GPS ativa</span>
        <span className="bg-green-100 text-green-700 px-2 py-0.5 rounded-full">Sinal Forte</span>
      </div>
    </div>
  );
};

export default MapMock;

import React, { useState, useEffect, useCallback } from 'react';
import { UserRole, UserProfile, Ride, RideStatus } from './types';
import Login from './pages/Login';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';

const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true },
  { id: 'd2', name: 'Ana Oliveira', email: 'ana@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d2/200', licensePlate: 'XYZ-9876', vehicleModel: 'Honda Civic', earnings: 840.20, rating: 4.9, isOnline: true },
];

const MOCK_RIDERS: UserProfile[] = [
  { id: 'r1', name: 'João Paulo', email: 'joao@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200' },
  { id: 'r2', name: 'Mariana Costa', email: 'mariana@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r2/200' },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([...MOCK_DRIVERS, ...MOCK_RIDERS]);
  const [rides, setRides] = useState<Ride[]>([]);

  // Simulation logic for a new ride request
  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, status: newStatus, driverId: driverId || ride.driverId } : ride
    ));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'New User',
      email: userData.email || '',
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} onRegister={handleRegister} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Global Header */}
      <header className="bg-black text-white px-6 py-4 flex items-center justify-between shadow-lg sticky top-0 z-50">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 bg-white rounded flex items-center justify-center">
            <span className="text-black font-bold text-xl">U</span>
          </div>
          <h1 className="text-xl font-bold tracking-tight">UberClone <span className="text-slate-400 font-normal">Pro</span></h1>
        </div>

        <div className="flex items-center space-x-4">
          <div className="text-right hidden sm:block">
            <p className="text-sm font-medium">{currentUser.name}</p>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest">{currentUser.role}</p>
          </div>
          <button 
            onClick={handleLogout}
            className="w-10 h-10 rounded-full border border-slate-700 flex items-center justify-center hover:bg-slate-800 transition-colors"
          >
            <i className="fas fa-sign-out-alt"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
        {currentUser.role === UserRole.ADMIN && (
          <AdminDashboard 
            users={users} 
            rides={rides} 
          />
        )}

        {currentUser.role === UserRole.DRIVER && (
          <DriverDashboard 
            driver={currentUser} 
            rides={rides} 
            onUpdateStatus={handleUpdateRideStatus}
          />
        )}

        {currentUser.role === UserRole.RIDER && (
          <RiderDashboard 
            rider={currentUser} 
            rides={rides} 
            onRequestRide={handleRequestRide}
            availableDrivers={users.filter(u => u.role === UserRole.DRIVER && u.isOnline)}
          />
        )}
      </main>

      {/* Role Switcher (Mock purposes) */}
      <div className="fixed bottom-4 left-4 flex space-x-2 bg-white p-2 rounded-full shadow-2xl border border-slate-200 z-[60]">
        <span className="text-[10px] self-center px-2 text-slate-400 font-bold uppercase">Debug:</span>
        {[UserRole.ADMIN, UserRole.DRIVER, UserRole.RIDER].map(role => (
          <button
            key={role}
            onClick={() => setCurrentUser({ ...users.find(u => u.role === role) || users[0], role })}
            className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${currentUser.role === role ? 'bg-black text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
          >
            {role}
          </button>
        ))}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, UserProfile } from '../types';

interface LoginProps {
  onLogin: (user: UserProfile) => void;
  onRegister: (data: Partial<UserProfile>) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [role, setRole] = useState<UserRole>(UserRole.RIDER);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    licensePlate: '',
    vehicleModel: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isRegistering) {
      onRegister({ ...formData, role });
    } else {
      // Mock login as the first user of that role for demo
      onLogin({
        id: 'u-login',
        name: formData.email.split('@')[0],
        email: formData.email,
        role: role,
        avatar: 'https://picsum.photos/seed/login/200'
      } as UserProfile);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-100 p-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden">
        <div className="p-8 bg-black text-white text-center">
          <div className="w-16 h-16 bg-white rounded-xl mx-auto mb-4 flex items-center justify-center">
            <span className="text-black font-bold text-4xl">U</span>
          </div>
          <h2 className="text-2xl font-bold">Bem-vindo ao UberClone</h2>
          <p className="text-slate-400 mt-2 text-sm">
            {isRegistering ? 'Crie sua conta para começar' : 'Acesse seu painel administrativo ou de usuário'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-lg mb-6">
            {[UserRole.RIDER, UserRole.DRIVER, UserRole.ADMIN].map(r => (
              <button
                key={r}
                type="button"
                onClick={() => setRole(r)}
                className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${role === r ? 'bg-white shadow-sm text-black' : 'text-slate-500 hover:text-slate-700'}`}
              >
                {r === UserRole.RIDER ? 'Passageiro' : r === UserRole.DRIVER ? 'Motorista' : 'Admin'}
              </button>
            ))}
          </div>

          {isRegistering && (
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nome Completo</label>
              <input 
                required
                type="text" 
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-black outline-none transition-all"
                placeholder="Ex: João Silva"
              />
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Email</label>
            <input 
              required
              type="email" 
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-black outline-none transition-all"
              placeholder="seu@email.com"
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Senha</label>
            <input 
              required
              type="password" 
              value={formData.password}
              onChange={e => setFormData({...formData, password: e.target.value})}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-black outline-none transition-all"
              placeholder="••••••••"
            />
          </div>

          {isRegistering && role === UserRole.DRIVER && (
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Placa</label>
                <input 
                  required
                  type="text" 
                  value={formData.licensePlate}
                  onChange={e => setFormData({...formData, licensePlate: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-black outline-none transition-all"
                  placeholder="ABC-1234"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Modelo</label>
                <input 
                  required
                  type="text" 
                  value={formData.vehicleModel}
                  onChange={e => setFormData({...formData, vehicleModel: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-black outline-none transition-all"
                  placeholder="Civic / Corolla"
                />
              </div>
            </div>
          )}

          <button 
            type="submit"
            className="w-full bg-black text-white py-4 rounded-xl font-bold text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 mt-4"
          >
            {isRegistering ? 'Criar Conta' : 'Entrar'}
          </button>

          <p className="text-center text-sm text-slate-500 mt-4">
            {isRegistering ? 'Já tem uma conta?' : 'Não tem conta?'}
            <button 
              type="button"
              onClick={() => setIsRegistering(!isRegistering)}
              className="ml-1 text-black font-bold hover:underline"
            >
              {isRegistering ? 'Faça Login' : 'Cadastre-se'}
            </button>
          </p>
        </form>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { UserProfile, Ride, RideStatus, Location } from '../types';
import MapMock from '../components/MapMock';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  availableDrivers: UserProfile[];
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ rider, rides, onRequestRide, availableDrivers }) => {
  const [destination, setDestination] = useState('');
  const [origin] = useState('Sua Localização Atual');
  const [isRequesting, setIsRequesting] = useState(false);
  const [aiInsight, setAiInsight] = useState("");
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');

  const activeRide = rides.find(r => r.riderId === rider.id && r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);

  const pricing = {
    UberX: 18.50,
    UberComfort: 24.90,
    UberBlack: 42.00
  };

  useEffect(() => {
    if (destination.length > 5) {
      const fetchInsight = async () => {
        const insight = await getRideInsight(origin, destination, pricing[selectedService]);
        setAiInsight(insight);
      };
      fetchInsight();
    }
  }, [destination, selectedService]);

  const handleConfirmRide = () => {
    if (!destination) return;
    onRequestRide({
      riderId: rider.id,
      origin: { lat: 0, lng: 0, address: origin },
      destination: { lat: 0, lng: 0, address: destination },
      price: pricing[selectedService],
      distance: '4.8 km'
    });
    setIsRequesting(false);
    setDestination('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in">
      {!activeRide ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
          {/* Ride Request Panel */}
          <div className="bg-white p-8 rounded-2xl shadow-xl border border-slate-200">
            <h2 className="text-3xl font-bold mb-8">Para onde vamos?</h2>

            <div className="space-y-4">
              <div className="relative">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 w-2 h-2 rounded-full bg-slate-300"></div>
                <input 
                  disabled
                  value={origin}
                  className="w-full pl-10 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl text-slate-500 font-medium"
                />
              </div>

              <div className="relative">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 w-2 h-2 bg-black"></div>
                <input 
                  autoFocus
                  placeholder="Informe o destino"
                  value={destination}
                  onChange={e => setDestination(e.target.value)}
                  className="w-full pl-10 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl font-bold focus:ring-2 focus:ring-black outline-none transition-all"
                />
              </div>

              {destination && (
                <div className="space-y-4 pt-6 animate-slide-up">
                  <h4 className="font-bold text-sm text-slate-500 uppercase tracking-widest">Escolha o serviço</h4>

                  {(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                    <button
                      key={service}
                      onClick={() => setSelectedService(service)}
                      className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all ${selectedService === service ? 'border-black bg-slate-50' : 'border-slate-100 hover:border-slate-200'}`}
                    >
                      <div className="flex items-center space-x-4">
                        <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${service === 'UberBlack' ? 'bg-black text-white' : 'bg-slate-200'}`}>
                          <i className={`fas ${service === 'UberBlack' ? 'fa-gem' : 'fa-car'}`}></i>
                        </div>
                        <div className="text-left">
                          <p className="font-bold">{service}</p>
                          <p className="text-xs text-slate-500">4 min • 12:45 chegada</p>
                        </div>
                      </div>
                      <p className="font-bold text-lg">R$ {pricing[service].toFixed(2)}</p>
                    </button>
                  ))}

                  {aiInsight && (
                    <div className="p-4 bg-indigo-50 rounded-xl text-xs text-indigo-700 flex items-start space-x-3 border border-indigo-100">
                      <i className="fas fa-sparkles mt-0.5 shrink-0"></i>
                      <p className="italic">"{aiInsight}"</p>
                    </div>
                  )}

                  <button 
                    onClick={handleConfirmRide}
                    className="w-full bg-black text-white py-5 rounded-xl font-bold text-xl hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
                  >
                    Confirmar {selectedService}
                  </button>
                </div>
              )}
            </div>
          </div>

          <MapMock className="h-[500px] hidden lg:block" />
        </div>
      ) : (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h3 className="text-xl font-bold">Acompanhando Viagem</h3>
            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${activeRide.status === RideStatus.COMPLETED ? 'bg-green-100 text-green-700' : 'bg-indigo-100 text-indigo-700'}`}>
              {activeRide.status === RideStatus.REQUESTED ? 'Aguardando Motorista' : 
               activeRide.status === RideStatus.ACCEPTED ? 'Motorista a Caminho' :
               activeRide.status === RideStatus.PICKUP ? 'No Ponto de Encontro' : 'Em Viagem'}
            </span>
          </div>

          <MapMock 
            className="h-[400px]" 
            origin={activeRide.origin.address} 
            destination={activeRide.destination.address}
            markers={activeRide.driverId ? [{ lat: 35, lng: 35, type: 'driver' }, { lat: 25, lng: 25, type: 'rider' }] : [{ lat: 25, lng: 25, type: 'rider' }]}
          />

          <div className="p-8">
            {activeRide.status === RideStatus.REQUESTED ? (
              <div className="text-center py-8">
                <div className="relative inline-block mb-6">
                  <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center">
                    <i className="fas fa-user-clock text-slate-400 text-3xl"></i>
                  </div>
                  <div className="absolute inset-0 w-20 h-20 border-4 border-slate-100 border-t-indigo-500 rounded-full animate-spin"></div>
                </div>
                <h4 className="text-2xl font-bold">Buscando Motorista...</h4>
                <p className="text-slate-500 mt-2">Estamos localizando o parceiro mais próximo de você.</p>
              </div>
            ) : (
              <div className="flex flex-col md:flex-row items-center justify-between gap-8">
                <div className="flex items-center space-x-6 w-full md:w-auto">
                  <div className="relative">
                    <img src="https://picsum.photos/seed/driver/200" className="w-20 h-20 rounded-full border-4 border-slate-50" />
                    <div className="absolute -bottom-1 -right-1 bg-white p-1 rounded-lg border shadow-sm">
                      <p className="text-[10px] font-bold">ABC-1234</p>
                    </div>
                  </div>
                  <div>
