interface DriverDashboardProps {
  driver: UserProfile;
  rides: Ride[];
  onUpdateStatus: (rideId: string, status: RideStatus, driverId: string) => void;
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
}

const DriverDashboard: React.FC<DriverDashboardProps> = ({ driver, rides, onUpdateStatus, onRateRide }) => {
  const [isOnline, setIsOnline] = useState(driver.isOnline || false);
  const [pendingRating, setPendingRating] = useState(0);

  // Pending rides waiting for any driver
  const pendingRides = rides.filter(r => r.status === RideStatus.REQUESTED);

  // My active ride (including completed but not yet rated by driver)
  const myActiveRide = rides.find(r => 
    r.driverId === driver.id && 
    (r.status !== RideStatus.COMPLETED || !r.ratingToRider) &&
    r.status !== RideStatus.CANCELLED
  );

  const earningsThisMonth = driver.earnings || 0;
  const rating = driver.rating || 5.0;

  const handleRatingSubmit = (rideId: string) => {
    if (pendingRating > 0) {
      onRateRide(rideId, pendingRating, UserRole.DRIVER);
      setPendingRating(0);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Driver Status Card */}
