              <i className="fas fa-power-off text-4xl mb-4 opacity-20"></i>
              <p className="font-medium">Você está offline</p>
              <p className="text-xs mt-1">Fique online para receber chamadas de passageiros.</p>
            </div>
          )}

          {isOnline && !myActiveRide && (
            <div className="space-y-4">
              <h4 className="font-bold text-lg">Solicitações Disponíveis</h4>
              {pendingRides.length === 0 ? (
                <div className="bg-white border border-slate-200 rounded-2xl p-12 text-center animate-pulse">
                  <i className="fas fa-satellite-dish text-indigo-500 text-3xl mb-4"></i>
