                        <p className="text-xs text-slate-500">{ride.distance} • {ride.origin.address.substring(0, 30)}...</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => onUpdateStatus(ride.id, RideStatus.ACCEPTED, driver.id)}
                      className="w-full md:w-auto bg-black text-white px-8 py-3 rounded-xl font-bold hover:bg-slate-800 transition-colors"
                    >
                      Aceitar Corrida
                    </button>
                  </div>
