                  disabled
                  value={origin}
                  className="w-full pl-10 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl text-slate-500 font-medium"
                />
              </div>

              <div className="relative">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 w-2 h-2 bg-black"></div>
                <input 
                  autoFocus
                  placeholder="Informe o destino"
                  value={destination}
                  onChange={e => setDestination(e.target.value)}
                  className="w-full pl-10 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl font-bold focus:ring-2 focus:ring-black outline-none transition-all"
                />
              </div>

              {destination && (
                <div className="space-y-4 pt-6 animate-slide-up">
                  <h4 className="font-bold text-sm text-slate-500 uppercase tracking-widest">Escolha o serviço</h4>

                  {(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                    <button
                      key={service}
                      onClick={() => setSelectedService(service)}
                      className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all ${selectedService === service ? 'border-black bg-slate-50 shadow-md' : 'border-slate-100 hover:border-slate-200'}`}
                    >
                      <div className="flex items-center space-x-4">
