                        <div className="text-left">
                          <p className="font-bold">{service}</p>
                          <p className="text-xs text-slate-500">4 min • {new Date(Date.now() + 4*60000).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} chegada</p>
                        </div>
                      </div>
                      <p className="font-bold text-lg">R$ {pricing[service].toFixed(2)}</p>
                    </button>
                  ))}

                  {aiInsight && (
