            <span className={`px-4 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider ${activeRide.status === RideStatus.COMPLETED ? 'bg-green-100 text-green-700' : 'bg-indigo-100 text-indigo-700'}`}>
              {activeRide.status === RideStatus.REQUESTED ? 'Procurando Motorista' : 
               activeRide.status === RideStatus.ACCEPTED ? 'Motorista a Caminho' :
               activeRide.status === RideStatus.PICKUP ? 'Embarque Próximo' : 
               activeRide.status === RideStatus.IN_PROGRESS ? 'Em Viagem' : 'Finalizada'}
            </span>
          </div>

          {activeRide.status === RideStatus.COMPLETED ? (
            <div className="p-12 text-center space-y-8 animate-fade-in">
              <div className="w-24 h-24 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto text-4xl shadow-sm border border-green-100">
                <i className="fas fa-check-circle"></i>
              </div>
              <div>
                <h3 className="text-3xl font-bold">Como foi sua viagem?</h3>
                <p className="text-slate-500 mt-2">Avalie o motorista {assignedDriver?.name || 'Carlos Silva'}</p>
              </div>

              <div className="flex justify-center space-x-6">
                {[1, 2, 3, 4, 5].map(star => (
                  <button 
                    key={star} 
                    onClick={() => setPendingRating(star)}
                    className={`text-4xl transition-all ${star <= pendingRating ? 'text-amber-500 scale-125' : 'text-slate-200 hover:text-amber-200'}`}
                  >
                    <i className="fas fa-star"></i>
                  </button>
                ))}
              </div>

              <div className="pt-4">
                <button 
                  disabled={pendingRating === 0}
                  onClick={() => handleRatingSubmit(activeRide.id)}
                  className={`w-full max-w-sm py-5 rounded-2xl font-bold text-lg transition-all shadow-xl ${pendingRating > 0 ? 'bg-black text-white hover:bg-slate-800 shadow-slate-200' : 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none'}`}
                >
                  Enviar Avaliação
