import React from 'react';
import { UserRole, UserProfile } from '../types';

interface LayoutProps {
  user: UserProfile;
  onLogout: () => void;
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ user, onLogout, children }) => {
  const getRoleColor = () => {
    switch (user.role) {
      case UserRole.ADMIN: return 'bg-indigo-600';
      case UserRole.DRIVER: return 'bg-slate-900';
      case UserRole.RIDER: return 'bg-black';
      default: return 'bg-black';
    }
  };

  const getNavLinks = () => {
    switch (user.role) {
      case UserRole.ADMIN:
        return [
          { icon: 'fa-chart-pie', label: 'Dashboard' },
