import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Ride, RideStatus, UserRole } from '../types';
import MapMock from '../components/MapMock';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ rider, rides, onRequestRide, availableDrivers, onRateRide }) => {
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [aiInsight, setAiInsight] = useState("");
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [pendingRating, setPendingRating] = useState(0);
  const [eta, setEta] = useState<number | null>(null);

  // Real-time tracking simulation state
  const [driverPos, setDriverPos] = useState({ lat: 10, lng: 85 });
  const movementRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    (r.status !== RideStatus.COMPLETED || !r.ratingToDriver) && 
    r.status !== RideStatus.CANCELLED
  );

  const assignedDriver = activeRide?.driverId 
    ? availableDrivers.find(d => d.id === activeRide.driverId) || { name: 'Carlos Silva', avatar: 'https://picsum.photos/seed/driver/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', rating: 4.8 } as UserProfile
    : null;

  const pricing = {
    UberX: 18.50,
    UberComfort: 24.90,
    UberBlack: 42.00
  };

  useEffect(() => {
    if (destination.length > 5) {
      const fetchInsight = async () => {
        const insight = await getRideInsight(origin, destination, pricing[selectedService]);
        setAiInsight(insight);
      };
      fetchInsight();
    }
  }, [destination, selectedService]);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.COMPLETED && activeRide.status !== RideStatus.REQUESTED) {
      if (eta === null) setEta(Math.floor(Math.random() * 8) + 2);
      const timer = setInterval(() => setEta(prev => (prev && prev > 1 ? prev - 1 : 1)), 60000);
      return () => clearInterval(timer);
    } else {
      setEta(null);
    }
  }, [activeRide?.status]);

  // Real-time tracking simulation loop
  useEffect(() => {
    if (!activeRide || activeRide.status === RideStatus.REQUESTED || activeRide.status === RideStatus.COMPLETED) {
      if (movementRef.current) clearInterval(movementRef.current);
      // Reset position for next time
      setDriverPos({ lat: 10, lng: 85 });
      return;
    }

    const moveDriver = () => {
      setDriverPos(prev => {
        let targetLat = 25; // Default target is Rider/Origin
        let targetLng = 25;

        if (activeRide.status === RideStatus.IN_PROGRESS) {
          targetLat = 75; // Destination
          targetLng = 75;
        }

        const step = 0.5; // Smooth incremental step
        const dLat = targetLat - prev.lat;
        const dLng = targetLng - prev.lng;
        const distance = Math.sqrt(dLat * dLat + dLng * dLng);

        if (distance < step) return { lat: targetLat, lng: targetLng };

        return {
          lat: prev.lat + (dLat / distance) * step,
          lng: prev.lng + (dLng / distance) * step,
        };
      });
    };

    movementRef.current = window.setInterval(moveDriver, 1000);
    return () => {
      if (movementRef.current) clearInterval(movementRef.current);
    };
  }, [activeRide?.status]);

  const handleConfirmRide = () => {
    if (!destination) return;
    onRequestRide({
      riderId: rider.id,
      origin: { lat: 25, lng: 25, address: origin },
      destination: { lat: 75, lng: 75, address: destination },
      price: pricing[selectedService],
      distance: '4.8 km'
    });
    setDestination('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {!activeRide ? (
        <div className="grid grid-cols-1 lg:grid-cols-1 gap-8 items-start">
          <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
            <h2 className="text-4xl font-black mb-10 text-slate-900 tracking-tighter">Para onde vamos?</h2>

            <div className="space-y-6">
              <div className="relative group">
                <div className="absolute left-5 top-1/2 -translate-y-1/2 w-2.5 h-2.5 rounded-full border-2 border-slate-300 group-focus-within:border-black transition-colors"></div>
                <input 
                  disabled
                  value={origin}
                  className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-400 font-bold text-lg"
                />
              </div>

              <div className="relative group">
                <div className="absolute left-5 top-1/2 -translate-y-1/2 w-2.5 h-2.5 bg-black rounded-sm shadow-sm"></div>
                <input 
                  autoFocus
                  placeholder="Inserir destino"
                  value={destination}
                  onChange={e => setDestination(e.target.value)}
                  className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-black outline-none transition-all placeholder:text-slate-300"
                />
              </div>

              {destination && (
                <div className="space-y-6 pt-10 animate-slide-up">
                  <h4 className="font-black text-xs text-slate-400 uppercase tracking-[0.2em]">Selecione sua categoria</h4>

                  <div className="grid gap-3">
                    {(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                      <button
                        key={service}
                        onClick={() => setSelectedService(service)}
                        className={`w-full flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-black bg-slate-50 shadow-md ring-4 ring-black/5' : 'border-slate-100 hover:border-slate-200'}`}
                      >
                        <div className="flex items-center space-x-6">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-xl ${service === 'UberBlack' ? 'bg-black text-white' : 'bg-slate-200 text-slate-600'}`}>
                            <i className={`fas ${service === 'UberBlack' ? 'fa-crown' : 'fa-car-side'}`}></i>
                          </div>
                          <div className="text-left">
                            <p className="font-black text-slate-900 text-lg">{service}</p>
                            <p className="text-xs font-bold text-slate-400">Chegada em 4 min</p>
                          </div>
                        </div>
                        <div className="text-right">
                           <p className="font-black text-xl text-slate-900">R$ {pricing[service].toFixed(2)}</p>
                        </div>
                      </button>
                    ))}
                  </div>

                  {aiInsight && (
                    <div className="p-6 bg-indigo-50/50 rounded-3xl text-xs text-indigo-700 flex items-start space-x-4 border border-indigo-100/50">
                      <div className="w-8 h-8 bg-indigo-100 rounded-full flex items-center justify-center shrink-0">
                        <i className="fas fa-sparkles"></i>
                      </div>
                      <p className="italic font-medium leading-relaxed">"{aiInsight}"</p>
                    </div>
                  )}

                  <button 
                    onClick={handleConfirmRide}
                    className="w-full bg-black text-white py-6 rounded-[2rem] font-black text-xl hover:bg-slate-800 transition-all shadow-2xl shadow-slate-300 mt-4 active:scale-95"
                  >
                    CONFIRMAR {selectedService.toUpperCase()}
                  </button>
                </div>
              )}
            </div>
          </div>

          <MapMock className="h-64 md:h-96 rounded-[2.5rem]" />
        </div>
      ) : (
        <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-200 overflow-hidden">
          <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10">
            <div>
              <h3 className="text-2xl font-black text-slate-900">
                {activeRide.status === RideStatus.COMPLETED ? 'Viagem Finalizada' : 'Motorista a caminho'}
              </h3>
              {eta !== null && activeRide.status !== RideStatus.COMPLETED && (
                <p className="text-indigo-600 text-sm font-black flex items-center mt-1 uppercase tracking-widest">
                  <i className="fas fa-bolt mr-2 animate-pulse"></i>
                  Chegada em {eta} min
                </p>
              )}
            </div>
            <div className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] ${activeRide.status === RideStatus.COMPLETED ? 'bg-green-100 text-green-700' : 'bg-indigo-100 text-indigo-700'}`}>
              {activeRide.status === RideStatus.REQUESTED ? 'Procurando...' : 
               activeRide.status === RideStatus.ACCEPTED ? 'Aceito' :
               activeRide.status === RideStatus.PICKUP ? 'No local' : 
               activeRide.status === RideStatus.IN_PROGRESS ? 'Em curso' : 'Concluído'}
            </div>
          </div>

          {activeRide.status === RideStatus.COMPLETED ? (
            <div className="p-16 text-center space-y-10 animate-fade-in">
              <div className="w-28 h-28 bg-green-50 text-green-500 rounded-[2.5rem] flex items-center justify-center mx-auto text-5xl shadow-sm border border-green-100">
                <i className="fas fa-check-circle"></i>
              </div>
              <div className="max-w-xs mx-auto">
                <h3 className="text-3xl font-black text-slate-900">Valeu pela viagem!</h3>
                <p className="text-slate-500 font-medium mt-3 leading-relaxed">Avalie o atendimento do parceiro para mantermos a qualidade.</p>
              </div>

              <div className="flex justify-center space-x-6">
                {[1, 2, 3, 4, 5].map(star => (
                  <button 
                    key={star} 
                    onClick={() => setPendingRating(star)}
                    className={`text-4xl transition-all duration-300 ${star <= pendingRating ? 'text-amber-500 scale-125' : 'text-slate-200 hover:text-amber-200'}`}
                  >
                    <i className="fas fa-star"></i>
                  </button>
                ))}
              </div>

              <div className="pt-6">
                <button 
                  disabled={pendingRating === 0}
                  onClick={() => {
                    onRateRide(activeRide.id, pendingRating, UserRole.RIDER);
                    setPendingRating(0);
                  }}
                  className={`w-full max-w-sm py-6 rounded-[2rem] font-black text-lg transition-all shadow-2xl ${pendingRating > 0 ? 'bg-black text-white hover:bg-slate-800 shadow-slate-300' : 'bg-slate-100 text-slate-400 cursor-not-allowed shadow-none'}`}
                >
                  Confirmar Avaliação
                </button>
              </div>
            </div>
          ) : (
            <>
              <MapMock 
                className="h-[450px]" 
                origin={activeRide.origin.address} 
                destination={activeRide.destination.address}
                markers={assignedDriver ? [
                  { lat: driverPos.lat, lng: driverPos.lng, type: 'driver' }, 
                  { lat: 25, lng: 25, type: 'rider' }
                ] : [
                  { lat: 25, lng: 25, type: 'rider' }
                ]}
              />

              <div className="p-8 md:p-10 bg-slate-50/30">
                {activeRide.status === RideStatus.REQUESTED ? (
                  <div className="text-center py-12">
                    <div className="relative inline-block mb-8">
                      <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center shadow-md">
                        <i className="fas fa-map-pin text-slate-300 text-4xl"></i>
