                  <div className="flex flex-col md:flex-row items-center justify-between gap-10">
                    <div className="flex items-center space-x-8 w-full md:w-auto">
                      <div className="relative group">
                        <img 
                          src={assignedDriver?.avatar} 
                          className="w-24 h-24 rounded-3xl border-4 border-white shadow-xl object-cover transition-transform group-hover:scale-105" 
                        />
                        <div className="absolute -bottom-3 -right-3 bg-black text-white px-3 py-1.5 rounded-xl border-4 border-white shadow-lg">
                          <p className="text-[10px] font-black tracking-tighter uppercase">{assignedDriver?.licensePlate}</p>
