import React, { useState } from 'react';
import { UserProfile, Ride, RideStatus, UserRole } from '../types';
import MapMock from '../components/MapMock';

interface DriverDashboardProps {
  driver: UserProfile;
  rides: Ride[];
  platformCommission: number;
  onUpdateStatus: (rideId: string, status: RideStatus, driverId: string) => void;
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
}

const DriverDashboard: React.FC<DriverDashboardProps> = ({ driver, rides, platformCommission, onUpdateStatus, onRateRide }) => {
  const [isOnline, setIsOnline] = useState(driver.isOnline || false);
  const pendingRides = rides.filter(r => r.status === RideStatus.REQUESTED);
  const myActiveRide = rides.find(r => r.driverId === driver.id && r.status !== RideStatus.COMPLETED);

  const calculateGain = (total: number) => total * (1 - (platformCommission / 100));

  return (
    <div className="space-y-6 animate-fade-in max-w-5xl mx-auto pb-20">
      <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 flex items-center justify-between">
        <div>
          <h3 className="text-2xl font-black">{driver.name}</h3>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Saldo acumulado: R$ {driver.earnings?.toFixed(2)}</p>
        </div>
        <button 
          onClick={() => setIsOnline(!isOnline)}
          className={`px-10 py-4 rounded-2xl font-black text-sm uppercase transition-all ${isOnline ? 'bg-red-50 text-red-600' : 'bg-indigo-600 text-white shadow-xl'}`}
        >
          {isOnline ? 'Sair do GPS' : 'Ficar Online'}
        </button>
      </div>

      {!isOnline ? (
        <div className="py-24 text-center text-slate-300">
           <i className="fas fa-moon text-6xl mb-4 opacity-20"></i>
           <p className="font-black uppercase tracking-[0.2em]">Você está offline</p>
        </div>
      ) : myActiveRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-xl overflow-hidden border border-slate-200">
           <div className="p-8 bg-black text-white flex justify-between items-center">
              <div>
                 <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Você receberá nesta corrida</p>
                 <h4 className="text-4xl font-black">R$ {calculateGain(myActiveRide.price).toFixed(2)}</h4>
                 <p className="text-xs font-medium opacity-40">Valor total do passageiro: R$ {myActiveRide.price.toFixed(2)}</p>
              </div>
              <div className="text-right">
                 <p className="text-[10px] font-black uppercase opacity-60">Pagamento</p>
                 <span className="font-bold">{myActiveRide.paymentMethod}</span>
              </div>
           </div>
           <div className="p-8 space-y-6">
              <MapMock className="h-72" />
              <button 
                onClick={() => onUpdateStatus(myActiveRide.id, RideStatus.COMPLETED, driver.id)}
                className="w-full bg-green-600 text-white py-6 rounded-2xl font-black text-xl shadow-lg"
              >
                FINALIZAR CORRIDA
              </button>
           </div>
        </div>
      ) : (
        <div className="space-y-4">
          <h4 className="font-black text-xl px-2">Chamadas Disponíveis</h4>
          {pendingRides.length === 0 ? (
            <div className="p-16 text-center bg-white rounded-[2.5rem] border border-slate-200">
              <i className="fas fa-radar animate-ping text-indigo-100 text-4xl mb-4"></i>
              <p className="text-slate-400 font-bold uppercase text-xs">Aguardando solicitações...</p>
            </div>
          ) : (
            pendingRides.map(ride => (
              <div key={ride.id} className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 flex items-center justify-between hover:border-black transition-all group">
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ganhos líquidos</p>
                   <h3 className="text-2xl font-black text-indigo-600">R$ {calculateGain(ride.price).toFixed(2)}</h3>
                   <p className="text-xs font-bold text-slate-500 mt-1">{ride.distance} • Pagamento em {ride.paymentMethod}</p>
                </div>
                <button 
                  onClick={() => onUpdateStatus(ride.id, RideStatus.ACCEPTED, driver.id)}
                  className="bg-black text-white px-8 py-4 rounded-xl font-black uppercase text-xs group-hover:bg-indigo-600 transition-colors"
                >
                  Aceitar
                </button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

