import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod } from '../types';
import MapMock from '../components/MapMock';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ rider, rides, onRequestRide, availableDrivers, onRateRide }) => {
  const [view, setView] = useState<'request' | 'history'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [aiInsight, setAiInsight] = useState("");
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [driverPos, setDriverPos] = useState({ lat: 10, lng: 85 });
  const movementRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  const pricing = { UberX: 18.50, UberComfort: 24.90, UberBlack: 42.00 };

  useEffect(() => {
    if (destination.length > 5) {
      const fetchInsight = async () => {
        const insight = await getRideInsight(origin, destination, pricing[selectedService]);
        setAiInsight(insight);
      };
      fetchInsight();
    }
  }, [destination, selectedService]);

  useEffect(() => {
    if (!activeRide || activeRide.status === RideStatus.REQUESTED) {
      if (movementRef.current) clearInterval(movementRef.current);
      setDriverPos({ lat: 10, lng: 85 });
      return;
    }
    const moveDriver = () => {
      setDriverPos(prev => {
        let targetLat = 25; let targetLng = 25;
        if (activeRide.status === RideStatus.IN_PROGRESS) { targetLat = 75; targetLng = 75; }
        const step = 0.5;
        const dLat = targetLat - prev.lat; const dLng = targetLng - prev.lng;
        const distance = Math.sqrt(dLat * dLat + dLng * dLng);
        if (distance < step) return { lat: targetLat, lng: targetLng };
        return { lat: prev.lat + (dLat / distance) * step, lng: prev.lng + (dLng / distance) * step };
      });
    };
    movementRef.current = window.setInterval(moveDriver, 1000);
    return () => { if (movementRef.current) clearInterval(movementRef.current); };
  }, [activeRide?.status]);

  const handleConfirmRide = () => {
    if (!destination) return;
    onRequestRide({
      riderId: rider.id,
      origin: { lat: 25, lng: 25, address: origin },
      destination: { lat: 75, lng: 75, address: destination },
      price: pricing[selectedService],
      paymentMethod: selectedPayment,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const findDriverInfo = (driverId?: string) => {
    return availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista Duarte',
      avatar: 'https://picsum.photos/seed/unknown/200',
      vehicleModel: 'Veículo Padrão',
      licensePlate: 'BRA-2025'
    };
  };

  const paymentOptions = [
    { id: PaymentMethod.CARD, label: 'Cartão', icon: 'fa-credit-card', color: 'text-blue-600' },
    { id: PaymentMethod.PIX, label: 'Pix', icon: 'fa-qrcode', color: 'text-teal-500' },
    { id: PaymentMethod.PREPAID, label: `Pré-pago`, icon: 'fa-wallet', color: 'text-indigo-600' },
    { id: PaymentMethod.CASH, label: 'Dinheiro', icon: 'fa-money-bill-wave', color: 'text-green-600' },
  ];

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {/* Seletor de Abas */}
      {!activeRide && (
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit mx-auto md:mx-0">
          <button 
            onClick={() => setView('request')}
            className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'request' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            Pedir Agora
          </button>
          <button 
            onClick={() => setView('history')}
            className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            Histórico
          </button>
        </div>
      )}

      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-indigo-950">Viagem em Curso</h3>
                <p className="text-xs font-bold text-slate-400 uppercase">Pagamento via {activeRide.paymentMethod}</p>
              </div>
              <span className="text-2xl font-black text-indigo-950">R$ {activeRide.price.toFixed(2)}</span>
           </div>
           <MapMock className="h-96" markers={[{ lat: driverPos.lat, lng: driverPos.lng, type: 'driver' }, { lat: 25, lng: 25, type: 'rider' }]} />
           <div className="p-8 bg-indigo-50 border-t border-indigo-100 flex items-center space-x-4">
              <img src={findDriverInfo(activeRide.driverId).avatar} className="w-12 h-12 rounded-2xl border-2 border-white shadow-md" alt="" />
              <div>
                <p className="text-xs font-black text-indigo-950 uppercase tracking-tight">{findDriverInfo(activeRide.driverId).name}</p>
                <p className="text-[10px] font-bold text-indigo-400 uppercase">{findDriverInfo(activeRide.driverId).vehicleModel} • {findDriverInfo(activeRide.driverId).licensePlate}</p>
              </div>
           </div>
        </div>
      ) : view === 'request' ? (
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
          <h2 className="text-4xl font-black mb-10 text-indigo-950 tracking-tighter">Para onde vamos?</h2>

          <div className="space-y-6">
            <div className="relative">
              <div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rounded-full"></div>
              <input disabled value={origin} className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-400 font-bold text-lg" />
            </div>

            <div className="relative">
              <div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-indigo-600 rounded-full"></div>
              <input autoFocus placeholder="Inserir destino" value={destination} onChange={e => setDestination(e.target.value)} className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 shadow-sm" />
            </div>

            {destination && (
              <div className="space-y-6 pt-10 animate-slide-up">
                <h4 className="font-black text-xs text-slate-400 uppercase tracking-widest">Serviço disponível</h4>
                <div className="grid gap-3">
                  {(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                    <button key={service} onClick={() => setSelectedService(service)} className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-indigo-950 bg-indigo-50 shadow-md ring-4 ring-indigo-950/5' : 'border-slate-100'}`}>
                      <span className={`font-black text-lg ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>{service}</span>
                      <span className={`font-black text-xl ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>R$ {pricing[service].toFixed(2)}</span>
                    </button>
                  ))}
                </div>

                <h4 className="font-black text-xs text-slate-400 uppercase tracking-widest pt-4">Método de Pagamento</h4>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                  {paymentOptions.map(opt => (
                    <button key={opt.id} onClick={() => setSelectedPayment(opt.id)} className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all ${selectedPayment === opt.id ? 'border-indigo-950 bg-indigo-50' : 'border-slate-100'}`}>
                      <i className={`fas ${opt.icon} ${opt.color} mb-2`}></i>
                      <span className={`text-[9px] font-black uppercase tracking-tight ${selectedPayment === opt.id ? 'text-indigo-950' : 'text-slate-400'}`}>{opt.label}</span>
                    </button>
                  ))}
                </div>

                <button onClick={handleConfirmRide} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl hover:bg-indigo-900 transition-all shadow-2xl mt-4 active:scale-95">
                  SOLICITAR AGORA
                </button>
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="space-y-4">
          <h2 className="text-3xl font-black text-indigo-950 px-2 tracking-tighter">Minhas Viagens</h2>
          {completedRides.length === 0 ? (
            <div className="p-20 text-center bg-white rounded-[2.5rem] border border-slate-200">
               <i className="fas fa-history text-slate-100 text-6xl mb-4"></i>
               <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">Você ainda não realizou viagens</p>
            </div>
          ) : (
            <div className="grid gap-4">
              {completedRides.map(ride => {
                const drv = findDriverInfo(ride.driverId);
                return (
