import React, { useEffect, useRef, useState } from 'react';

declare const L: any;

interface RealMapProps {
  className?: string;
  driverLocation?: { lat: number, lng: number };
  riderLocation?: { lat: number, lng: number };
}

const RealMap: React.FC<RealMapProps> = ({ className, driverLocation, riderLocation }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const riderMarkerRef = useRef<any>(null);
  const driverMarkerRef = useRef<any>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    // Initialize map if not already done
    if (!mapRef.current) {
      mapRef.current = L.map(mapContainerRef.current, {
        zoomControl: false,
        attributionControl: false
      }).setView([-23.5505, -46.6333], 13); // Default to São Paulo

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19,
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Handle Rider Location
  useEffect(() => {
    if (!mapRef.current) return;

    if (riderLocation) {
      const pos = [riderLocation.lat, riderLocation.lng];
      if (!riderMarkerRef.current) {
        const icon = L.divIcon({
          className: 'custom-div-icon',
          html: `<div class="w-6 h-6 bg-blue-600 rounded-full border-4 border-white shadow-lg flex items-center justify-center text-white text-[10px]"><i class="fas fa-user"></i></div>`,
          iconSize: [24, 24],
          iconAnchor: [12, 12]
        });
        riderMarkerRef.current = L.marker(pos, { icon }).addTo(mapRef.current);
        mapRef.current.setView(pos, 15);
      } else {
        riderMarkerRef.current.setLatLng(pos);
      }
    }
  }, [riderLocation]);

  // Handle Driver Location
  useEffect(() => {
    if (!mapRef.current || !driverLocation) return;

    const pos = [driverLocation.lat, driverLocation.lng];
    if (!driverMarkerRef.current) {
      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div class="w-8 h-8 bg-indigo-950 rounded-xl border-2 border-white shadow-xl flex items-center justify-center text-white text-xs"><i class="fas fa-car-side"></i></div>`,
        iconSize: [32, 32],
        iconAnchor: [16, 16]
      });
      driverMarkerRef.current = L.marker(pos, { icon }).addTo(mapRef.current);
    } else {
      driverMarkerRef.current.setLatLng(pos);
    }

    // Auto-fit bounds if both are present
    if (riderLocation && driverLocation) {
      const bounds = L.latLngBounds([
        [riderLocation.lat, riderLocation.lng],
        [driverLocation.lat, driverLocation.lng]
      ]);
      mapRef.current.fitBounds(bounds, { padding: [50, 50] });
    }
  }, [driverLocation, riderLocation]);

  return (
    <div className={`relative overflow-hidden rounded-[2.5rem] border border-slate-200 shadow-inner ${className}`}>
      <div ref={mapContainerRef} className="w-full h-full" />
      {error && (
        <div className="absolute top-4 left-4 right-4 z-[1000] bg-red-50 text-red-600 p-3 rounded-xl text-xs font-bold border border-red-100 flex items-center">
          <i className="fas fa-exclamation-triangle mr-2"></i>
          {error}
        </div>
      )}
      <div className="absolute bottom-4 left-4 z-[1000] bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 border border-slate-200 shadow-xl flex items-center">
        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse mr-2"></div>
        Satélite Ativo
      </div>
    </div>
  );
};

