export default RiderDashboard;

export enum UserRole {
  ADMIN = 'ADMIN',
  DRIVER = 'DRIVER',
  RIDER = 'RIDER'
}

export enum RideStatus {
  REQUESTED = 'REQUESTED',
  ACCEPTED = 'ACCEPTED',
  PICKUP = 'PICKUP',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum PaymentMethod {
  CARD = 'CARD',
  PIX = 'PIX',
  CASH = 'CASH',
  PREPAID = 'PREPAID'
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
  walletBalance?: number;
  // Driver specific
  licensePlate?: string;
  vehicleModel?: string;
  rating?: number;
  earnings?: number;
  isOnline?: boolean;
}

export interface Location {
  lat: number;
  lng: number;
  address: string;
}

export interface Ride {
  id: string;
  riderId: string;
  driverId?: string;
  origin: Location;
  destination: Location;
  status: RideStatus;
  price: number;
  paymentMethod: PaymentMethod;
  timestamp: string;
  distance: string;
  ratingToDriver?: number;
  ratingToRider?: number;
  messages?: ChatMessage[];
}

export interface PaymentSettings {
  apiKey: string;
  provider: 'Stripe' | 'MercadoPago' | 'PayPal';
  platformCommission: number; // Porcentagem (ex: 20 para 20%)
}

export interface AppState {
  currentUser: UserProfile | null;
  rides: Ride[];
  users: UserProfile[];
  paymentSettings: PaymentSettings;
}

import React, { useState, useCallback, useMemo } from 'react';
import { UserRole, UserProfile, Ride, RideStatus, PaymentMethod, PaymentSettings, ChatMessage } from './types';
import Login from './pages/Login';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';
import Layout from './components/Layout';

const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true },
  { id: 'd2', name: 'Ana Oliveira', email: 'ana@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d2/200', licensePlate: 'XYZ-9876', vehicleModel: 'Honda Civic', earnings: 840.20, rating: 4.9, isOnline: true },
];

const MOCK_RIDERS: UserProfile[] = [
  { id: 'r1', name: 'João Paulo', email: 'joao@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200', walletBalance: 50.00 },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isAdminPortal, setIsAdminPortal] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>([...MOCK_DRIVERS, ...MOCK_RIDERS]);
  const [rides, setRides] = useState<Ride[]>([]);
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    apiKey: 'sk_test_51Mz...',
    provider: 'Stripe',
    platformCommission: 15
  });

  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
      messages: []
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleSendMessage = useCallback((rideId: string, text: string) => {
    if (!currentUser) return;
    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      senderId: currentUser.id,
      text,
      timestamp: new Date().toISOString()
    };
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, messages: [...(ride.messages || []), newMessage] } : ride
    ));
  }, [currentUser]);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, status: newStatus, driverId: driverId || ride.driverId } : ride
    ));

    if (newStatus === RideStatus.COMPLETED) {
      setRides(prev => {
        const ride = prev.find(r => r.id === rideId);
        if (ride && ride.driverId) {
          const driverGain = ride.price * (1 - (paymentSettings.platformCommission / 100));
          setUsers(currentUsers => currentUsers.map(u => 
            u.id === ride.driverId ? { ...u, earnings: (u.earnings || 0) + driverGain } : u
          ));
        }
        return prev;
      });
    }
  }, [paymentSettings.platformCommission]);

  const handleRateRide = useCallback((rideId: string, rating: number, role: UserRole) => {
    setRides(prev => prev.map(ride => {
      if (ride.id === rideId) {
        return role === UserRole.RIDER 
          ? { ...ride, ratingToDriver: rating } 
          : { ...ride, ratingToRider: rating };
      }
      return ride;
    }));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      walletBalance: 0,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAdminPortal(false);
  };

  const driverRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.DRIVER) return [];
    return rides.filter(r => r.status === RideStatus.REQUESTED || r.driverId === currentUser.id);
  }, [rides, currentUser]);

  const riderRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.RIDER) return [];
    return rides.filter(r => r.riderId === currentUser.id);
  }, [rides, currentUser]);

  const availableDrivers = useMemo(() => 
    users.filter(u => u.role === UserRole.DRIVER && u.isOnline), 
    [users]
  );

  if (!currentUser) {
    if (isAdminPortal) {
      return (
        <AdminLogin 
          onLogin={(user) => setCurrentUser(user)} 
          onBackToPublic={() => setIsAdminPortal(false)} 
        />
      );
    }
    return (
      <Login 
        onLogin={(user) => {
          const existing = users.find(u => u.email === user.email && u.role === user.role);
          setCurrentUser(existing || user);
        }} 
        onRegister={handleRegister}
        onGoToAdmin={() => setIsAdminPortal(true)}
      />
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.ADMIN && (
        <AdminDashboard 
          users={users} 
          rides={rides} 
          paymentSettings={paymentSettings}
          onUpdateSettings={setPaymentSettings}
        />
      )}

      {currentUser.role === UserRole.DRIVER && (
        <DriverDashboard 
          driver={users.find(u => u.id === currentUser.id) || currentUser} 
          rides={driverRides} 
          platformCommission={paymentSettings.platformCommission}
          onUpdateStatus={handleUpdateRideStatus}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}

      {currentUser.role === UserRole.RIDER && (
        <RiderDashboard 
          rider={users.find(u => u.id === currentUser.id) || currentUser} 
          rides={riderRides} 
          onRequestRide={handleRequestRide}
          availableDrivers={availableDrivers}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}
    </Layout>
  );
};

export default App;

