    };
    fetchBriefing();
  }, [activeRides.length, totalRevenue]);

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings(tempSettings);
    alert('Configurações de pagamento atualizadas com sucesso!');
  };

  const getDriverRideCount = (driverId: string) => {
    return rides.filter(r => r.driverId === driverId && r.status === RideStatus.COMPLETED).length;
  };

  return (
    <div className="space-y-8 animate-fade-in pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Portal do Administrador</h2>
          <p className="text-slate-500 font-medium">Controle total do ecossistema Duarte Entregas.</p>
        </div>
