                  <div className="flex items-center justify-between md:text-right border-t md:border-t-0 pt-4 md:pt-0">
                    <div className="md:mr-8"><p className="text-[10px] font-black text-slate-300 uppercase">Valor Pago</p><p className="text-xl font-black text-indigo-950">R$ {ride.price.toFixed(2)}</p></div>
