import React, { useState, useEffect } from 'react';
import { UserProfile, Ride, UserRole, RideStatus, PaymentSettings } from '../types';
import { getAdminBriefing } from '../services/geminiService';

interface AdminDashboardProps {
  users: UserProfile[];
  rides: Ride[];
  paymentSettings: PaymentSettings;
  onUpdateSettings: (settings: PaymentSettings) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, rides, paymentSettings, onUpdateSettings }) => {
  const [aiBriefing, setAiBriefing] = useState("Analisando operações...");
  const [view, setView] = useState<'overview' | 'users' | 'rides' | 'settings'>('overview');
  const [tempSettings, setTempSettings] = useState(paymentSettings);

  const drivers = users.filter(u => u.role === UserRole.DRIVER);
  const riders = users.filter(u => u.role === UserRole.RIDER);
  const activeRides = rides.filter(r => r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);
  const totalRevenue = rides.reduce((acc, r) => acc + r.price, 0);
  const platformEarnings = rides.filter(r => r.status === RideStatus.COMPLETED).reduce((acc, r) => acc + (r.price * (paymentSettings.platformCommission / 100)), 0);

  useEffect(() => {
    const fetchBriefing = async () => {
      const briefing = await getAdminBriefing(activeRides.length, totalRevenue);
      setAiBriefing(briefing);
    };
    fetchBriefing();
  }, [activeRides.length, totalRevenue]);

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings(tempSettings);
    alert('Configurações de pagamento atualizadas com sucesso! O sistema de Pré-pago está agora habilitado para os usuários.');
  };

  const getDriverRideCount = (driverId: string) => {
    return rides.filter(r => r.driverId === driverId && r.status === RideStatus.COMPLETED).length;
  };

  return (
    <div className="space-y-8 animate-fade-in pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Portal do Administrador</h2>
          <p className="text-slate-500 font-medium">Controle total do ecossistema Duarte Entregas.</p>
        </div>
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200">
          {(['overview', 'users', 'rides', 'settings'] as const).map(v => (
            <button 
              key={v}
              onClick={() => setView(v)}
              className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === v ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              {v === 'overview' ? 'Geral' : v === 'users' ? 'Usuários' : v === 'rides' ? 'Viagens' : 'Config'}
            </button>
          ))}
        </div>
      </div>

      {view === 'overview' && (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {[
              { icon: 'fa-users', color: 'blue', label: 'Base de Usuários', val: users.length, diff: `${riders.length} Passageiros` },
              { icon: 'fa-car', color: 'amber', label: 'Frota de Parceiros', val: drivers.length, diff: `${drivers.filter(d => d.isOnline).length} Online` },
              { icon: 'fa-route', color: 'indigo', label: 'Tráfego do Dia', val: rides.length, diff: `${activeRides.length} em curso` },
              { icon: 'fa-wallet', color: 'green', label: 'Lucro Plataforma', val: `R$ ${platformEarnings.toLocaleString()}`, diff: `${paymentSettings.platformCommission}% de taxa` }
            ].map((stat, i) => (
              <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
                <div className="flex items-center justify-between mb-4">
                  <div className={`w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center`}>
                    <i className={`fas ${stat.icon} text-xl`}></i>
                  </div>
                </div>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</p>
                <h3 className="text-2xl font-black text-slate-900 mt-1">{stat.val}</h3>
                <p className={`text-indigo-600 text-[10px] font-bold mt-2`}>{stat.diff}</p>
              </div>
            ))}
          </div>

          <div className="bg-indigo-600 rounded-[2rem] p-8 text-white flex flex-col md:flex-row items-start md:items-center space-y-4 md:space-y-0 md:space-x-6 shadow-xl shadow-indigo-200 relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 transition-transform group-hover:scale-110">
              <i className="fas fa-brain text-9xl"></i>
            </div>
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center shrink-0 backdrop-blur-md">
              <i className="fas fa-robot text-2xl"></i>
            </div>
            <div className="relative z-10">
              <h4 className="font-black text-xl tracking-tight mb-1">Análise Estratégica Duarte AI</h4>
