              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Taxa da Plataforma (%)</label>
                  <div className="relative">
                    <input 
                      type="number"
                      value={tempSettings.platformCommission}
                      onChange={e => setTempSettings({...tempSettings, platformCommission: Number(e.target.value)})}
                      className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-950 outline-none font-bold"
                      min="0"
                      max="100"
                    />
                    <span className="absolute right-6 top-1/2 -translate-y-1/2 font-black text-slate-400">%</span>
                  </div>
                </div>

                <div className="pt-6">
                  <button 
                    type="submit"
                    className="w-full bg-indigo-950 text-white py-6 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-900 transition-all shadow-xl"
                  >
                    SALVAR CONFIGURAÇÕES
                  </button>
                </div>
              </div>
           </form>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, availableDrivers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings 
}) => {
  const [view, setView] = useState<'request' | 'history' | 'wallet'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [selectedRideReceipt, setSelectedRideReceipt] = useState<Ride | null>(null);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('20.00');
  const [showPixKey, setShowPixKey] = useState(false);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);
  const pricing = { UberX: 18.50, UberComfort: 24.90, UberBlack: 42.00 };

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude });
        },
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const targetLat = userPos.lat;
          const targetLng = userPos.lng;
          if (!prev) return { lat: targetLat + 0.01, lng: targetLng + 0.01 };
          const step = 0.0001;
          const dLat = targetLat - prev.lat;
          const dLng = targetLng - prev.lng;
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;
          return { lat: prev.lat + (dLat > 0 ? step : -step), lng: prev.lng + (dLng > 0 ? step : -step) };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
  }, [activeRide?.status, userPos]);

  const handleConfirmRide = () => {
    if (!destination || !userPos) return;

    // Validar saldo se for pré-pago
    if (selectedPayment === PaymentMethod.PREPAID) {
      const cost = pricing[selectedService];
      if ((rider.walletBalance || 0) < cost) {
        alert("Saldo insuficiente na carteira. Por favor, recarregue seu saldo ou escolha outro método.");
        return;
      }
    }

    onRequestRide({
      riderId: rider.id,
      origin: { lat: userPos.lat, lng: userPos.lng, address: origin },
      destination: { lat: userPos.lat + 0.02, lng: userPos.lng + 0.02, address: destination },
      price: pricing[selectedService],
      paymentMethod: selectedPayment,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const handleTopUp = () => {
    if (paymentSettings.apiKey) {
      if (paymentSettings.provider === 'MercadoPago') {
        setShowPixKey(true);
      } else {
        // Simular pagamento por cartão para Stripe/PayPal
        onUpdateBalance(rider.id, parseFloat(topUpAmount));
        setIsAddingFunds(false);
        alert("Recarga efetuada com sucesso!");
      }
    } else {
      alert("A plataforma ainda não configurou o sistema de pagamentos. Tente novamente mais tarde.");
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista Duarte',
      avatar: 'https://picsum.photos/seed/unknown/200',
      vehicleModel: 'Veículo Padrão',
      licensePlate: 'BRA-2025'
    };
  };

  const paymentOptions = [
    { id: PaymentMethod.CARD, label: 'Cartão', icon: 'fa-credit-card', color: 'text-blue-600' },
    { id: PaymentMethod.PIX, label: 'Pix', icon: 'fa-qrcode', color: 'text-teal-500' },
    { id: PaymentMethod.PREPAID, label: `Carteira`, icon: 'fa-wallet', color: 'text-indigo-600' },
    { id: PaymentMethod.CASH, label: 'Dinheiro', icon: 'fa-money-bill-wave', color: 'text-green-600' },
  ];

  const pixKey = "00020126360014BR.GOV.BCB.PIX0114123456789012345204000053039865405" + topUpAmount.replace('.', '') + "5802BR5915DuarteEntregas6009SaoPaulo62070503***6304";

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id}
          messages={activeRide.messages || []}
          currentUserId={rider.id}
          onSendMessage={onSendMessage}
          otherPartyName={findDriverInfo(activeRide.driverId).name}
        />
      )}

      {/* Modal de Recarga de Saldo */}
      {isAddingFunds && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-slate-100 p-10">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-2xl font-black text-indigo-950">Recarregar Carteira</h3>
                 <button onClick={() => { setIsAddingFunds(false); setShowPixKey(false); }} className="text-slate-400 hover:text-red-500"><i className="fas fa-times text-xl"></i></button>
              </div>

              {!showPixKey ? (
                <div className="space-y-6">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor da Recarga (R$)</label>
                    <input 
                      type="number" 
                      value={topUpAmount}
                      onChange={e => setTopUpAmount(e.target.value)}
                      className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none font-bold text-lg"
                    />
                  </div>

                  <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                    <div className="flex items-center space-x-3 text-indigo-950">
                       <i className={`fas ${paymentSettings.provider === 'MercadoPago' ? 'fa-qrcode' : 'fa-credit-card'} text-xl opacity-60`}></i>
                       <p className="text-sm font-bold">Pagar com {paymentSettings.provider}</p>
                    </div>
                    <p className="text-[10px] font-bold text-indigo-400 mt-2 uppercase tracking-tighter">O saldo será liberado imediatamente após a confirmação.</p>
                  </div>

                  <button 
                    onClick={handleTopUp}
                    className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-lg shadow-xl active:scale-95 transition-transform"
                  >
                    CONTINUAR PARA PAGAMENTO
                  </button>
                </div>
              ) : (
                <div className="space-y-8 text-center animate-slide-up">
                   <div className="w-48 h-48 bg-slate-100 mx-auto rounded-3xl flex items-center justify-center border-2 border-dashed border-slate-200">
                      <i className="fas fa-qrcode text-8xl text-indigo-950"></i>
                   </div>
                   <div>
                      <h4 className="font-black text-indigo-950 mb-2">Pague com PIX</h4>
                      <p className="text-sm text-slate-500 px-6">Copie a chave abaixo e utilize o aplicativo do seu banco para pagar.</p>
                   </div>
                   <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center space-x-3 overflow-hidden">
                      <code className="flex-1 text-[10px] font-mono truncate text-slate-600">{pixKey}</code>
                      <button 
                        onClick={() => { navigator.clipboard.writeText(pixKey); alert('Copiado!'); }}
                        className="bg-white p-2 rounded-lg border border-slate-200 text-indigo-600 hover:bg-indigo-50"
                      >
                         <i className="fas fa-copy"></i>
                      </button>
                   </div>
                   <button 
                    onClick={() => { onUpdateBalance(rider.id, parseFloat(topUpAmount)); setIsAddingFunds(false); setShowPixKey(false); alert("Recarga confirmada!"); }}
                    className="w-full bg-green-600 text-white py-5 rounded-2xl font-black text-lg"
                   >
                     JÁ REALIZEI O PAGAMENTO
                   </button>
                </div>
              )}
           </div>
        </div>
      )}

      {/* Modal de Recibo */}
      {selectedRideReceipt && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-indigo-950/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-white/20 relative">
            <button 
              onClick={() => setSelectedRideReceipt(null)}
              className="absolute top-6 right-6 w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-500 hover:bg-slate-200"
            >
              <i className="fas fa-times"></i>
            </button>
            <div className="p-8 text-center bg-slate-50 border-b border-slate-100 pt-12">
              <div className="w-16 h-16 bg-white rounded-2xl mx-auto mb-4 flex items-center justify-center shadow-md text-indigo-950 font-black text-2xl">D</div>
              <h4 className="text-xl font-black text-indigo-950">Comprovante de Viagem</h4>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">ID: {selectedRideReceipt.id}</p>
            </div>
            <div className="p-8 space-y-6">
              <div className="flex justify-between items-end">
                <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Valor Total</p><h2 className="text-4xl font-black text-indigo-950">R$ {selectedRideReceipt.price.toFixed(2)}</h2></div>
                <div className="text-right"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Data</p><p className="font-bold text-slate-700">{new Date(selectedRideReceipt.timestamp).toLocaleDateString('pt-BR')}</p></div>
              </div>
              <div className="bg-indigo-50 p-6 rounded-[2rem] flex items-center justify-between">
                 <div className="flex items-center space-x-3">
                    <img src={findDriverInfo(selectedRideReceipt.driverId).avatar} className="w-12 h-12 rounded-xl border-2 border-white shadow-sm" alt="" />
                    <div><p className="text-[9px] font-black text-indigo-400 uppercase">Motorista</p><p className="text-sm font-black text-indigo-950">{findDriverInfo(selectedRideReceipt.driverId).name}</p></div>
                 </div>
                 <div className="text-right"><p className="text-[9px] font-black text-indigo-400 uppercase">Pagamento</p><p className="text-xs font-black text-indigo-950">{selectedRideReceipt.paymentMethod}</p></div>
              </div>
              <button onClick={() => window.print()} className="w-full py-4 border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50">IMPRIMIR</button>
            </div>
          </div>
        </div>
      )}

      {!activeRide && (
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit mx-auto md:mx-0">
          <button onClick={() => setView('request')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'request' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Pedir Agora</button>
          <button onClick={() => setView('history')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Histórico</button>
          <button onClick={() => setView('wallet')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'wallet' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Minha Carteira</button>
        </div>
      )}

      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 relative">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div><h3 className="text-2xl font-black text-indigo-950">Viagem Ativa</h3><p className="text-xs font-bold text-slate-400 uppercase">{activeRide.status}</p></div>
              <span className="text-2xl font-black text-indigo-950">R$ {activeRide.price.toFixed(2)}</span>
           </div>

           <div className="h-96 w-full p-2 bg-slate-50 relative">
              <RealMap className="h-full w-full" riderLocation={userPos} driverLocation={driverPos}/>

              {/* Card flutuante com dados do motorista sobre o mapa */}
              {activeRide.status !== RideStatus.REQUESTED && (
                <div className="absolute top-6 left-6 right-6 z-[10] animate-slide-up">
                   <div className="bg-white/90 backdrop-blur-md p-5 rounded-[2rem] shadow-2xl border border-white flex items-center space-x-4">
                      <div className="relative">
                        <img src={findDriverInfo(activeRide.driverId).avatar} className="w-14 h-14 rounded-2xl border-2 border-indigo-600 shadow-md object-cover" alt="" />
                        <div className="absolute -bottom-1 -right-1 bg-green-500 w-4 h-4 rounded-full border-2 border-white"></div>
                      </div>
                      <div className="flex-1">
                         <div className="flex justify-between items-start">
                            <p className="text-sm font-black text-indigo-950">{findDriverInfo(activeRide.driverId).name}</p>
                            <span className="bg-indigo-950 text-white px-3 py-1 rounded-lg text-[10px] font-black tracking-widest uppercase shadow-sm">
                              {findDriverInfo(activeRide.driverId).licensePlate}
                            </span>
                         </div>
                         <p className="text-[10px] font-bold text-slate-500 uppercase mt-1">
                           <i className="fas fa-car mr-1 text-indigo-400"></i>
                           {findDriverInfo(activeRide.driverId).vehicleModel}
                         </p>
                      </div>
                   </div>
                </div>
              )}
           </div>

           <div className="p-8 bg-indigo-50 border-t border-indigo-100 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className="w-10 h-10 bg-indigo-600 text-white rounded-full flex items-center justify-center text-xs">
                   <i className="fas fa-shield-alt"></i>
                </div>
                <div>
                  <p className="text-[10px] font-black text-indigo-950 uppercase">Identificação Verificada</p>
                  <p className="text-[9px] font-bold text-indigo-400">Segurança Duarte Entregas ativa</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Veículo</p>
                <p className="text-xs font-black text-indigo-950">{findDriverInfo(activeRide.driverId).licensePlate}</p>
              </div>
           </div>
        </div>
      ) : view === 'request' ? (
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
          <h2 className="text-4xl font-black mb-10 text-indigo-950 tracking-tighter">Para onde vamos hoje?</h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rounded-full"></div><input disabled value={userPos ? "Sua Localização GPS" : "Obtendo GPS..."} className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-500 font-bold text-lg" /></div>
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-indigo-600 rounded-full"></div><input autoFocus placeholder="Inserir destino" value={destination} onChange={e => setDestination(e.target.value)} className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300" /></div>
              {destination && (
                <div className="space-y-6 pt-4 animate-slide-up">
                  <div className="grid gap-3">{(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (<button key={service} onClick={() => setSelectedService(service)} className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-indigo-950 bg-indigo-50 shadow-md' : 'border-slate-100'}`}><span className={`font-black text-lg ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>{service}</span><span className={`font-black text-xl ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>R$ {pricing[service].toFixed(2)}</span></button>))}</div>
                  <div className="grid grid-cols-2 gap-3">{paymentOptions.map(opt => (<button key={opt.id} onClick={() => setSelectedPayment(opt.id)} className={`flex items-center space-x-3 p-4 rounded-xl border-2 transition-all ${selectedPayment === opt.id ? 'border-indigo-950 bg-indigo-50' : 'border-slate-100'}`}><i className={`fas ${opt.icon} ${opt.color}`}></i><span className={`text-[10px] font-black uppercase tracking-tight ${selectedPayment === opt.id ? 'text-indigo-950' : 'text-slate-400'}`}>{opt.label}</span></button>))}</div>
                  <button onClick={handleConfirmRide} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl hover:bg-indigo-900 transition-all shadow-2xl mt-4 active:scale-95">SOLICITAR AGORA</button>
                </div>
              )}
            </div>
            <div className="hidden md:block h-full min-h-[400px]"><RealMap className="h-full w-full" riderLocation={userPos} /></div>
          </div>
        </div>
      ) : view === 'history' ? (
        <div className="space-y-4">
          <h2 className="text-3xl font-black text-indigo-950 px-2 tracking-tighter">Minhas Viagens</h2>
          <div className="grid gap-4">
            {completedRides.map(ride => {
              const drv = findDriverInfo(ride.driverId);
              return (
                <div key={ride.id} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-6 hover:shadow-md transition-shadow group cursor-pointer" onClick={() => setSelectedRideReceipt(ride)}>
                  <div className="flex items-center space-x-4">
                    <img src={drv.avatar} className="w-16 h-16 rounded-2xl object-cover shadow-sm border border-slate-100" alt="" />
                    <div><h4 className="font-black text-indigo-950 group-hover:text-indigo-600">{drv.name}</h4><p className="text-[10px] font-bold text-slate-400 uppercase">{drv.vehicleModel} • {drv.licensePlate}</p><p className="text-[10px] font-bold text-indigo-500 mt-1">{new Date(ride.timestamp).toLocaleDateString('pt-BR')}</p></div>
                  </div>
                  <div className="flex items-center justify-between md:text-right border-t md:border-t-0 pt-4 md:pt-0">
                    <div className="md:mr-8"><p className="text-[10px] font-black text-slate-300 uppercase">Valor Pago</p><p className="text-xl font-black text-indigo-950">R$ {ride.price.toFixed(2)}</p></div>
                    <div className="w-10 h-10 rounded-full border border-slate-100 flex items-center justify-center text-slate-300 group-hover:text-indigo-600 transition-all"><i className="fas fa-file-invoice"></i></div>
