          </div>
        </div>
      ) : (
        <div className="space-y-6 animate-fade-in">
           <div className="bg-indigo-950 p-10 rounded-[2.5rem] text-white flex flex-col md:flex-row justify-between items-center shadow-2xl border border-white/10">
              <div>
                 <p className="text-indigo-300 font-black uppercase text-[10px] tracking-widest mb-1">Saldo em Carteira</p>
                 <h2 className="text-6xl font-black">R$ {rider.walletBalance?.toFixed(2) || '0,00'}</h2>
              </div>
              <button 
                onClick={() => setIsAddingFunds(true)}
                className="mt-6 md:mt-0 bg-white text-indigo-950 px-10 py-5 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl hover:bg-indigo-50 transition-colors"
              >
                <i className="fas fa-plus mr-2"></i> Recarregar
              </button>
           </div>

           <div className="bg-white p-8 rounded-[2rem] border border-slate-200">
              <h4 className="font-black text-indigo-950 mb-6 flex items-center">
                 <i className="fas fa-history mr-3 text-slate-400"></i>
                 Últimas Transações
              </h4>
              <div className="space-y-4">
                 {rider.walletBalance && rider.walletBalance > 0 ? (
                   <div className="flex items-center justify-between py-4 border-b border-slate-50">
                      <div className="flex items-center space-x-4">
                         <div className="w-10 h-10 bg-green-50 text-green-600 rounded-xl flex items-center justify-center"><i className="fas fa-arrow-down"></i></div>
                         <div>
                            <p className="font-bold text-slate-700">Recarga de Saldo</p>
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Via {paymentSettings.provider}</p>
                         </div>
                      </div>
                      <p className="font-black text-green-600">+ R$ {rider.walletBalance.toFixed(2)}</p>
                   </div>
                 ) : (
                   <div className="py-12 text-center text-slate-300">
                      <p className="text-[10px] font-black uppercase tracking-widest">Nenhuma transação encontrada</p>
                   </div>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default RiderDashboard;

export enum UserRole {
  ADMIN = 'ADMIN',
  DRIVER = 'DRIVER',
  RIDER = 'RIDER'
}

export enum VehicleType {
  CAR = 'CAR',
  MOTORCYCLE = 'MOTORCYCLE'
}

export enum RideStatus {
  REQUESTED = 'REQUESTED',
  ACCEPTED = 'ACCEPTED',
  PICKUP = 'PICKUP',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum PaymentMethod {
  CARD = 'CARD',
  PIX = 'PIX',
  CASH = 'CASH',
  PREPAID = 'PREPAID'
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
  walletBalance?: number;
  // Driver specific
  licensePlate?: string;
  vehicleModel?: string;
  vehicleType?: VehicleType;
  rating?: number;
  earnings?: number;
  isOnline?: boolean;
}

export interface Location {
  lat: number;
  lng: number;
  address: string;
}

export interface Ride {
  id: string;
  riderId: string;
  driverId?: string;
  origin: Location;
  destination: Location;
  status: RideStatus;
  price: number;
  paymentMethod: PaymentMethod;
  vehicleTypeRequested: VehicleType;
  timestamp: string;
  distance: string;
  ratingToDriver?: number;
  ratingToRider?: number;
  messages?: ChatMessage[];
}

export interface PaymentSettings {
  apiKey: string;
  provider: 'Stripe' | 'MercadoPago' | 'PayPal';
  platformCommission: number; // Porcentagem (ex: 20 para 20%)
}

export interface AppState {
  currentUser: UserProfile | null;
  rides: Ride[];
  users: UserProfile[];
  paymentSettings: PaymentSettings;
}

import React, { useState } from 'react';
import { UserRole, UserProfile, VehicleType } from '../types';

interface LoginProps {
  onLogin: (user: UserProfile) => void;
  onRegister: (data: Partial<UserProfile>) => void;
  onGoToAdmin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister, onGoToAdmin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [role, setRole] = useState<UserRole>(UserRole.RIDER);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    licensePlate: '',
    vehicleModel: '',
    vehicleType: VehicleType.CAR
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (isRegistering) {
      if (role === UserRole.DRIVER) {
        if (!formData.licensePlate.trim() || !formData.vehicleModel.trim()) {
          alert("Atenção: Placa e modelo do veículo são obrigatórios para o cadastro de motoristas.");
          return;
        }
      }

      onRegister({ 
        name: formData.name,
        email: formData.email,
        licensePlate: role === UserRole.DRIVER ? formData.licensePlate : undefined,
        vehicleModel: role === UserRole.DRIVER ? formData.vehicleModel : undefined,
        vehicleType: role === UserRole.DRIVER ? formData.vehicleType : undefined,
        role 
      });
    } else {
      onLogin({
        id: `u-${Date.now()}`,
        name: formData.email.split('@')[0],
        email: formData.email,
        role: role,
        avatar: `https://picsum.photos/seed/${formData.email}/200`
      } as UserProfile);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-6">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-100">
        <div className="p-10 bg-indigo-950 text-white text-center relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16"></div>
          <div className="w-20 h-20 bg-white rounded-3xl mx-auto mb-6 flex items-center justify-center shadow-lg transform -rotate-6 transition-transform hover:rotate-0">
            <span className="text-indigo-950 font-black text-5xl">D</span>
          </div>
          <h2 className="text-3xl font-black tracking-tight">Duarte Entregas</h2>
          <p className="text-indigo-300/60 mt-2 font-medium">Selecione seu perfil de acesso</p>
        </div>

        <form onSubmit={handleSubmit} className="p-10 space-y-6">
          <div className="grid grid-cols-2 gap-2 p-1.5 bg-slate-100 rounded-2xl mb-4">
            {[
              { id: UserRole.RIDER, label: 'Passageiro', icon: 'fa-user' },
              { id: UserRole.DRIVER, label: 'Motorista', icon: 'fa-car' }
            ].map(r => (
              <button
                key={r.id}
                type="button"
                onClick={() => setRole(r.id)}
                className={`flex flex-col items-center justify-center py-3 px-1 rounded-xl transition-all ${role === r.id ? 'bg-white shadow-md text-indigo-950' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <i className={`fas ${r.icon} text-sm mb-1`}></i>
                <span className="text-[10px] font-black uppercase tracking-widest">{r.label}</span>
              </button>
            ))}
          </div>

          <div className="space-y-4">
            {isRegistering && (
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Nome Completo</label>
                <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" placeholder="Seu Nome" />
              </div>
            )}

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Email</label>
              <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" placeholder="seu@email.com" />
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Senha</label>
              <input required type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none transition-all font-bold" placeholder="••••••••" />
            </div>

            {isRegistering && role === UserRole.DRIVER && (
              <div className="space-y-4 animate-slide-up bg-indigo-50/50 p-6 rounded-3xl border border-indigo-100">
                <label className="block text-[10px] font-black text-indigo-900 uppercase tracking-widest mb-2">Tipo de Veículo</label>
                <div className="grid grid-cols-2 gap-3 mb-4">
                  <button 
                    type="button" 
                    onClick={() => setFormData({...formData, vehicleType: VehicleType.CAR})}
                    className={`flex items-center justify-center space-x-2 p-3 rounded-xl border-2 transition-all ${formData.vehicleType === VehicleType.CAR ? 'bg-indigo-950 text-white border-indigo-950' : 'bg-white text-indigo-950 border-slate-200'}`}
                  >
                    <i className="fas fa-car"></i>
                    <span className="text-[10px] font-black uppercase">Carro</span>
                  </button>
                  <button 
                    type="button" 
                    onClick={() => setFormData({...formData, vehicleType: VehicleType.MOTORCYCLE})}
                    className={`flex items-center justify-center space-x-2 p-3 rounded-xl border-2 transition-all ${formData.vehicleType === VehicleType.MOTORCYCLE ? 'bg-indigo-950 text-white border-indigo-950' : 'bg-white text-indigo-950 border-slate-200'}`}
                  >
                    <i className="fas fa-motorcycle"></i>
                    <span className="text-[10px] font-black uppercase">Moto</span>
                  </button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-indigo-900 uppercase tracking-widest mb-2">Placa</label>
                    <input required type="text" value={formData.licensePlate} onChange={e => setFormData({...formData, licensePlate: e.target.value.toUpperCase()})} className="w-full px-4 py-3 bg-white border-2 border-slate-100 rounded-xl focus:border-indigo-600 outline-none font-bold" placeholder="ABC-1234" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-indigo-900 uppercase tracking-widest mb-2">Modelo</label>
                    <input required type="text" value={formData.vehicleModel} onChange={e => setFormData({...formData, vehicleModel: e.target.value})} className="w-full px-4 py-3 bg-white border-2 border-slate-100 rounded-xl focus:border-indigo-600 outline-none font-bold" placeholder="Honda/Preta" />
                  </div>
                </div>
              </div>
            )}
          </div>

          <button type="submit" className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl hover:bg-indigo-900 transition-all shadow-2xl active:scale-95">
            {isRegistering ? 'CRIAR MINHA CONTA' : 'ACESSAR CONTA'}
          </button>

          <p className="text-center text-sm font-bold text-slate-400">
            {isRegistering ? 'Já possui acesso?' : 'Não possui conta?'}
            <button type="button" onClick={() => setIsRegistering(!isRegistering)} className="ml-2 text-indigo-950 font-black hover:underline">
              {isRegistering ? 'Login' : 'Cadastre-se'}
            </button>
          </p>
        </form>
      </div>
      <button onClick={onGoToAdmin} className="mt-8 text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] hover:text-indigo-950">Portal de Gestão Duarte Entregas</button>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, availableDrivers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings 
}) => {
  const [view, setView] = useState<'request' | 'history' | 'wallet'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleType>(VehicleType.CAR);
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [selectedRideReceipt, setSelectedRideReceipt] = useState<Ride | null>(null);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('20.00');
  const [showPixKey, setShowPixKey] = useState(false);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  // Preços dinâmicos baseados no tipo de veículo
  const getPrice = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
    const basePrices = { UberX: 18.50, UberComfort: 24.90, UberBlack: 42.00 };
    const multiplier = selectedVehicle === VehicleType.MOTORCYCLE ? 0.6 : 1.0;
    return basePrices[service] * multiplier;
  };

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => {
          setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude });
        },
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const targetLat = userPos.lat;
          const targetLng = userPos.lng;
          if (!prev) return { lat: targetLat + 0.01, lng: targetLng + 0.01 };
          const step = 0.0001;
          const dLat = targetLat - prev.lat;
          const dLng = targetLng - prev.lng;
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;
          return { lat: prev.lat + (dLat > 0 ? step : -step), lng: prev.lng + (dLng > 0 ? step : -step) };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
  }, [activeRide?.status, userPos]);

  const handleConfirmRide = () => {
    if (!destination || !userPos) return;

    if (selectedPayment === PaymentMethod.PREPAID) {
      const cost = getPrice(selectedService);
      if ((rider.walletBalance || 0) < cost) {
        alert("Saldo insuficiente na carteira.");
        return;
      }
    }

    onRequestRide({
      riderId: rider.id,
      origin: { lat: userPos.lat, lng: userPos.lng, address: origin },
      destination: { lat: userPos.lat + 0.02, lng: userPos.lng + 0.02, address: destination },
      price: getPrice(selectedService),
      paymentMethod: selectedPayment,
      vehicleTypeRequested: selectedVehicle,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const handleTopUp = () => {
    if (paymentSettings.apiKey) {
      if (paymentSettings.provider === 'MercadoPago') {
        setShowPixKey(true);
      } else {
        onUpdateBalance(rider.id, parseFloat(topUpAmount));
        setIsAddingFunds(false);
        alert("Recarga efetuada!");
      }
    } else {
      alert("Sistema de pagamentos não configurado.");
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista Parceiro',
      avatar: 'https://picsum.photos/seed/unknown/200',
      vehicleModel: 'Veículo Padrão',
      licensePlate: 'BRA-2025',
      vehicleType: selectedVehicle
    };
  };

  const paymentOptions = [
    { id: PaymentMethod.CARD, label: 'Cartão', icon: 'fa-credit-card', color: 'text-blue-600' },
    { id: PaymentMethod.PIX, label: 'Pix', icon: 'fa-qrcode', color: 'text-teal-500' },
    { id: PaymentMethod.PREPAID, label: `Carteira`, icon: 'fa-wallet', color: 'text-indigo-600' },
    { id: PaymentMethod.CASH, label: 'Dinheiro', icon: 'fa-money-bill-wave', color: 'text-green-600' },
  ];

  const pixKey = "00020126360014BR.GOV.BCB.PIX0114123456789012345204000053039865405" + topUpAmount.replace('.', '') + "5802BR5915DuarteEntregas6009SaoPaulo62070503***6304";

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id}
          messages={activeRide.messages || []}
          currentUserId={rider.id}
          onSendMessage={onSendMessage}
          otherPartyName={findDriverInfo(activeRide.driverId).name}
        />
      )}

      {/* Modal de Recarga */}
      {isAddingFunds && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-slate-100 p-10">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-2xl font-black text-indigo-950">Recarregar Carteira</h3>
                 <button onClick={() => { setIsAddingFunds(false); setShowPixKey(false); }} className="text-slate-400 hover:text-red-500"><i className="fas fa-times text-xl"></i></button>
              </div>
              {!showPixKey ? (
                <div className="space-y-6">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor (R$)</label>
                    <input type="number" value={topUpAmount} onChange={e => setTopUpAmount(e.target.value)} className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none font-bold text-lg" />
                  </div>
                  <button onClick={handleTopUp} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-lg shadow-xl active:scale-95 transition-transform">CONTINUAR PARA PAGAMENTO</button>
                </div>
              ) : (
                <div className="space-y-8 text-center animate-slide-up">
                   <div className="w-48 h-48 bg-slate-100 mx-auto rounded-3xl flex items-center justify-center border-2 border-dashed border-slate-200">
                      <i className="fas fa-qrcode text-8xl text-indigo-950"></i>
                   </div>
                   <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center space-x-3 overflow-hidden">
                      <code className="flex-1 text-[10px] font-mono truncate text-slate-600">{pixKey}</code>
                      <button onClick={() => { navigator.clipboard.writeText(pixKey); alert('Copiado!'); }} className="bg-white p-2 rounded-lg border border-slate-200 text-indigo-600"><i className="fas fa-copy"></i></button>
                   </div>
                   <button onClick={() => { onUpdateBalance(rider.id, parseFloat(topUpAmount)); setIsAddingFunds(false); setShowPixKey(false); alert("Recarga confirmada!"); }} className="w-full bg-green-600 text-white py-5 rounded-2xl font-black text-lg">JÁ PAGUEI</button>
                </div>
              )}
           </div>
        </div>
      )}

      {/* Modal de Recibo */}
      {selectedRideReceipt && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-indigo-950/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-white/20 relative">
            <button onClick={() => setSelectedRideReceipt(null)} className="absolute top-6 right-6 w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-500"><i className="fas fa-times"></i></button>
            <div className="p-8 text-center bg-slate-50 border-b border-slate-100 pt-12">
              <div className="w-16 h-16 bg-white rounded-2xl mx-auto mb-4 flex items-center justify-center shadow-md text-indigo-950 font-black text-2xl">D</div>
              <h4 className="text-xl font-black text-indigo-950">Comprovante de Viagem</h4>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">ID: {selectedRideReceipt.id}</p>
            </div>
            <div className="p-8 space-y-6">
              <div className="flex justify-between items-end">
                <div><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Valor Total</p><h2 className="text-4xl font-black text-indigo-950">R$ {selectedRideReceipt.price.toFixed(2)}</h2></div>
                <div className="text-right">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Veículo</p>
                  <p className="font-bold text-slate-700 uppercase text-xs">{selectedRideReceipt.vehicleTypeRequested === VehicleType.MOTORCYCLE ? 'MOTO' : 'CARRO'}</p>
                </div>
              </div>
              <div className="bg-indigo-50 p-6 rounded-[2rem] flex items-center justify-between">
                 <div className="flex items-center space-x-3">
                    <img src={findDriverInfo(selectedRideReceipt.driverId).avatar} className="w-12 h-12 rounded-xl border-2 border-white shadow-sm" alt="" />
                    <div><p className="text-[9px] font-black text-indigo-400 uppercase">Motorista</p><p className="text-sm font-black text-indigo-950">{findDriverInfo(selectedRideReceipt.driverId).name}</p></div>
                 </div>
                 <div className="text-right"><p className="text-[9px] font-black text-indigo-400 uppercase">Pagamento</p><p className="text-xs font-black text-indigo-950">{selectedRideReceipt.paymentMethod}</p></div>
              </div>
              <button onClick={() => window.print()} className="w-full py-4 border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-400">IMPRIMIR</button>
            </div>
          </div>
        </div>
      )}

      {!activeRide && (
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
            <button onClick={() => setView('request')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'request' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Pedir</button>
            <button onClick={() => setView('history')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Histórico</button>
            <button onClick={() => setView('wallet')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'wallet' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Carteira</button>
          </div>

          {view === 'request' && !activeRide && (
            <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
              <button 
                onClick={() => setSelectedVehicle(VehicleType.CAR)}
                className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.CAR ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                <i className="fas fa-car text-xs"></i>
                <span className="text-[10px] font-black uppercase tracking-widest">Carro</span>
              </button>
              <button 
                onClick={() => setSelectedVehicle(VehicleType.MOTORCYCLE)}
                className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.MOTORCYCLE ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
              >
                <i className="fas fa-motorcycle text-xs"></i>
                <span className="text-[10px] font-black uppercase tracking-widest">Moto</span>
              </button>
            </div>
          )}
        </div>
      )}

      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 relative">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div><h3 className="text-2xl font-black text-indigo-950">Viagem Ativa</h3><p className="text-xs font-bold text-slate-400 uppercase">{activeRide.status}</p></div>
              <span className="text-2xl font-black text-indigo-950">R$ {activeRide.price.toFixed(2)}</span>
           </div>

           <div className="h-96 w-full p-2 bg-slate-50 relative">
              <RealMap className="h-full w-full" riderLocation={userPos} driverLocation={driverPos}/>
              {activeRide.status !== RideStatus.REQUESTED && (
                <div className="absolute top-6 left-6 right-6 z-[10] animate-slide-up">
