import React, { useState } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, VehicleType } from '../types';
import MapMock from '../components/MapMock';
import ChatWidget from '../components/ChatWidget';

interface DriverDashboardProps {
  driver: UserProfile;
  rides: Ride[];
  platformCommission: number;
  onUpdateStatus: (rideId: string, status: RideStatus, driverId: string) => void;
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
}

const DriverDashboard: React.FC<DriverDashboardProps> = ({ driver, rides, platformCommission, onUpdateStatus, onRateRide, onSendMessage }) => {
  const [isOnline, setIsOnline] = useState(driver.isOnline || false);
  const [rideToAccept, setRideToAccept] = useState<Ride | null>(null);

  // O motorista só recebe pedidos que correspondam ao seu tipo de veículo
  const pendingRides = rides.filter(r => 
    r.status === RideStatus.REQUESTED && 
    r.vehicleTypeRequested === driver.vehicleType
  );

  const myActiveRide = rides.find(r => r.driverId === driver.id && r.status !== RideStatus.COMPLETED);

  const calculateGain = (total: number) => total * (1 - (platformCommission / 100));

  const handleConfirmAccept = () => {
    if (rideToAccept) {
      onUpdateStatus(rideToAccept.id, RideStatus.ACCEPTED, driver.id);
      setRideToAccept(null);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-5xl mx-auto pb-20">
      {myActiveRide && (
        <ChatWidget 
          rideId={myActiveRide.id}
          messages={myActiveRide.messages || []}
          currentUserId={driver.id}
          onSendMessage={onSendMessage}
          otherPartyName="Passageiro"
        />
      )}

      {rideToAccept && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-indigo-950/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-white/20">
            <div className="p-8 text-center bg-indigo-50 border-b border-indigo-100">
              <div className="w-16 h-16 bg-white rounded-2xl mx-auto mb-4 flex items-center justify-center shadow-lg">
                <i className={`fas ${driver.vehicleType === VehicleType.MOTORCYCLE ? 'fa-motorcycle' : 'fa-car-side'} text-indigo-600 text-2xl`}></i>
              </div>
              <h4 className="text-xl font-black text-indigo-950">Confirmar Chamada?</h4>
              <p className="text-xs font-bold text-slate-400 uppercase mt-1">Categoria: {driver.vehicleType === VehicleType.MOTORCYCLE ? 'MOTO' : 'CARRO'}</p>
            </div>
            <div className="p-8 space-y-4">
              <div className="flex justify-between items-center py-2 border-b border-slate-50">
                <span className="text-[10px] font-black text-slate-400 uppercase">Seu Ganho</span>
                <span className="text-xl font-black text-green-600">R$ {calculateGain(rideToAccept.price).toFixed(2)}</span>
              </div>
              <div className="pt-4 space-y-3">
                <button onClick={handleConfirmAccept} className="w-full bg-indigo-950 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-900 transition-all shadow-xl">ACEITAR</button>
                <button onClick={() => setRideToAccept(null)} className="w-full bg-white text-slate-400 py-4 rounded-2xl font-black text-[10px] uppercase">IGNORAR</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center space-x-5">
          <div className="w-16 h-16 bg-indigo-50 rounded-[1.5rem] flex items-center justify-center text-indigo-600 shadow-inner">
             <i className={`fas ${driver.vehicleType === VehicleType.MOTORCYCLE ? 'fa-motorcycle' : 'fa-car'} text-2xl`}></i>
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Ganhos em Carteira</p>
            <h3 className="text-4xl font-black text-indigo-950">R$ {driver.earnings?.toFixed(2)}</h3>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={() => setIsOnline(!isOnline)} className={`px-10 py-5 rounded-2xl font-black text-sm uppercase transition-all shadow-xl ${isOnline ? 'bg-red-50 text-red-600' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}>
            {isOnline ? 'Ficar Offline' : 'Ficar Online'}
          </button>
        </div>
      </div>

      {!isOnline ? (
        <div className="py-24 text-center text-slate-300">
           <i className="fas fa-moon text-6xl mb-4 opacity-20"></i>
           <p className="font-black uppercase tracking-[0.2em]">Você está offline</p>
        </div>
      ) : myActiveRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-xl overflow-hidden border border-slate-200 animate-slide-up">
           <div className="p-8 bg-indigo-950 text-white flex justify-between items-center">
              <div>
                 <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Ganhos desta corrida</p>
                 <h4 className="text-4xl font-black">R$ {calculateGain(myActiveRide.price).toFixed(2)}</h4>
              </div>
              <div className="text-right">
                 <p className="text-[10px] font-black uppercase opacity-60">Veículo</p>
                 <span className="font-bold text-xs bg-indigo-600/30 px-3 py-1 rounded-full uppercase">{driver.vehicleType === VehicleType.MOTORCYCLE ? 'MOTO' : 'CARRO'}</span>
              </div>
           </div>
           <div className="p-8 space-y-6">
              <MapMock className="h-72" />
              <button onClick={() => onUpdateStatus(myActiveRide.id, RideStatus.COMPLETED, driver.id)} className="w-full bg-green-600 text-white py-6 rounded-2xl font-black text-xl shadow-lg hover:bg-green-700">FINALIZAR VIAGEM</button>
           </div>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h4 className="font-black text-xl text-indigo-950">Chamadas de {driver.vehicleType === VehicleType.MOTORCYCLE ? 'Moto' : 'Carro'}</h4>
            <div className="flex items-center text-xs font-black text-indigo-500 bg-indigo-50 px-3 py-1 rounded-full">
              <span className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-pulse mr-2"></span>
              RADAR ATIVO
            </div>
          </div>
          {pendingRides.length === 0 ? (
            <div className="p-16 text-center bg-white rounded-[2.5rem] border border-slate-200">
              <i className="fas fa-radar animate-ping text-indigo-100 text-4xl mb-4"></i>
              <p className="text-slate-400 font-bold uppercase text-xs">Aguardando corridas compatíveis...</p>
            </div>
          ) : (
            pendingRides.map(ride => (
              <div key={ride.id} className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 flex items-center justify-between hover:border-indigo-600 transition-all">
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Lucro Líquido</p>
                   <h3 className="text-2xl font-black text-indigo-600">R$ {calculateGain(ride.price).toFixed(2)}</h3>
                   <p className="text-xs font-bold text-slate-500 mt-1">{ride.distance} • Pagamento via {ride.paymentMethod}</p>
                </div>
                <button onClick={() => setRideToAccept(ride)} className="bg-indigo-950 text-white px-8 py-4 rounded-xl font-black uppercase text-xs shadow-lg active:scale-95">Aceitar</button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default DriverDashboard;

import React, { useState, useEffect } from 'react';
import { UserProfile, Ride, UserRole, RideStatus, PaymentSettings, VehicleType } from '../types';
import { getAdminBriefing } from '../services/geminiService';

interface AdminDashboardProps {
  users: UserProfile[];
  rides: Ride[];
  paymentSettings: PaymentSettings;
  onUpdateSettings: (settings: PaymentSettings) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, rides, paymentSettings, onUpdateSettings }) => {
  const [aiBriefing, setAiBriefing] = useState("Analisando operações...");
  const [view, setView] = useState<'overview' | 'users' | 'rides' | 'settings'>('overview');
  const [tempSettings, setTempSettings] = useState(paymentSettings);
  const [selectedRideDetail, setSelectedRideDetail] = useState<Ride | null>(null);

  const drivers = users.filter(u => u.role === UserRole.DRIVER);
  const riders = users.filter(u => u.role === UserRole.RIDER);
  const activeRides = rides.filter(r => r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);
  const totalRevenue = rides.reduce((acc, r) => acc + r.price, 0);
  const platformEarnings = rides.filter(r => r.status === RideStatus.COMPLETED).reduce((acc, r) => acc + (r.price * (paymentSettings.platformCommission / 100)), 0);

  useEffect(() => {
    const fetchBriefing = async () => {
      const briefing = await getAdminBriefing(activeRides.length, totalRevenue);
      setAiBriefing(briefing);
    };
    fetchBriefing();
  }, [activeRides.length, totalRevenue]);

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings(tempSettings);
    alert('Configurações de pagamento atualizadas com sucesso! O sistema de Pré-pago está agora habilitado para os usuários.');
  };

  const getDriverRideCount = (driverId: string) => {
    return rides.filter(r => r.driverId === driverId && r.status === RideStatus.COMPLETED).length;
