  const getStatusColor = (status: RideStatus) => {
    switch (status) {
      case RideStatus.COMPLETED: return 'bg-green-100 text-green-600';
      case RideStatus.CANCELLED: return 'bg-red-100 text-red-600';
      case RideStatus.REQUESTED: return 'bg-blue-100 text-blue-600';
      case RideStatus.ACCEPTED:
      case RideStatus.PICKUP:
      case RideStatus.IN_PROGRESS: return 'bg-amber-100 text-amber-600';
      default: return 'bg-slate-100 text-slate-600';
