            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {/* Cards de Passageiro e Motorista */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-blue-50/50 p-6 rounded-3xl border border-blue-100">
                  <p className="text-[9px] font-black text-blue-400 uppercase tracking-widest mb-4">Passageiro</p>
                  {(() => {
                    const r = getUserById(selectedRideDetail.riderId);
                    return (
                      <div className="flex items-center space-x-4">
                        <img src={r?.avatar} className="w-12 h-12 rounded-2xl border-2 border-white shadow-sm" alt="" />
                        <div>
                          <p className="font-black text-indigo-950 text-sm">{r?.name || 'Usuário Removido'}</p>
                          <p className="text-[10px] text-slate-500 font-bold">{r?.email}</p>
