import React, { useEffect, useRef, useState } from 'react';

declare const L: any;

interface RealMapProps {
  className?: string;
  driverLocation?: { lat: number, lng: number };
  riderLocation?: { lat: number, lng: number };
}

const RealMap: React.FC<RealMapProps> = ({ className, driverLocation, riderLocation }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const riderMarkerRef = useRef<any>(null);
  const driverMarkerRef = useRef<any>(null);
  const historyLineRef = useRef<any>(null);
  const approachLineRef = useRef<any>(null);
  const pathHistoryRef = useRef<Array<[number, number]>>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    if (!mapRef.current) {
      mapRef.current = L.map(mapContainerRef.current, {
        zoomControl: false,
        attributionControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([-23.5505, -46.6333], 13);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19,
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Gerenciar Localização do Passageiro
  useEffect(() => {
    if (!mapRef.current) return;

    if (riderLocation) {
      const pos = [riderLocation.lat, riderLocation.lng];
      if (!riderMarkerRef.current) {
        const icon = L.divIcon({
          className: 'custom-div-icon',
          html: `
            <div class="relative flex items-center justify-center">
              <div class="absolute w-12 h-12 bg-blue-500/20 rounded-full animate-ping"></div>
              <div class="absolute w-8 h-8 bg-blue-500/40 rounded-full animate-pulse"></div>
              <div class="w-6 h-6 bg-blue-600 rounded-full border-4 border-white shadow-lg flex items-center justify-center text-white text-[10px] relative z-10">
                <i class="fas fa-user"></i>
              </div>
            </div>
          `,
          iconSize: [48, 48],
          iconAnchor: [24, 24]
        });
        riderMarkerRef.current = L.marker(pos, { icon }).addTo(mapRef.current);
        mapRef.current.panTo(pos, { animate: true, duration: 1 });
      } else {
        riderMarkerRef.current.setLatLng(pos);
      }
    }
  }, [riderLocation]);

  // Gerenciar Localização do Motorista e Rota de Aproximação
  useEffect(() => {
    if (!mapRef.current) return;

    if (!driverLocation) {
      // Limpeza completa ao remover motorista
      [historyLineRef, approachLineRef, driverMarkerRef].forEach(ref => {
        if (ref.current) {
          mapRef.current.removeLayer(ref.current);
          ref.current = null;
        }
      });
      pathHistoryRef.current = [];
      return;
    }

    const dPos: [number, number] = [driverLocation.lat, driverLocation.lng];
    pathHistoryRef.current = [...pathHistoryRef.current, dPos];

    // 1. Atualizar Marcador do Motorista com rotação dinâmica (simulada)
    if (!driverMarkerRef.current) {
      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div class="driver-marker-container">
            <div class="driver-glow"></div>
            <div class="w-10 h-10 bg-indigo-950 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white text-sm relative z-20">
              <i class="fas fa-car-side"></i>
            </div>
          </div>
        `,
        iconSize: [40, 40],
        iconAnchor: [20, 20]
      });
      driverMarkerRef.current = L.marker(dPos, { icon }).addTo(mapRef.current);
    } else {
      driverMarkerRef.current.setLatLng(dPos);
    }

    // 2. Linha de Histórico (Rastro do que já foi percorrido)
    if (!historyLineRef.current) {
      historyLineRef.current = L.polyline(pathHistoryRef.current, {
        color: '#94a3b8',
        weight: 3,
        opacity: 0.4,
        lineJoin: 'round'
      }).addTo(mapRef.current);
    } else {
      historyLineRef.current.setLatLngs(pathHistoryRef.current);
    }

    // 3. Linha de Aproximação (Driver -> Rider) - A "ANIMAÇÃO DE ROTA"
    if (riderLocation) {
      const rPos: [number, number] = [riderLocation.lat, riderLocation.lng];
      const approachPoints = [dPos, rPos];

      if (!approachLineRef.current) {
        approachLineRef.current = L.polyline(approachPoints, {
          color: '#4f46e5',
          weight: 5,
          opacity: 0.8,
          dashArray: '10, 15',
          lineJoin: 'round',
          className: 'animate-route-flow'
        }).addTo(mapRef.current);
      } else {
        approachLineRef.current.setLatLngs(approachPoints);
      }

      // Ajuste inteligente de câmera
      const bounds = L.latLngBounds([dPos, rPos]);
      mapRef.current.fitBounds(bounds, { 
        padding: [60, 60],
        animate: true,
        duration: 0.5
      });
    }
  }, [driverLocation, riderLocation]);

  return (
    <div className={`relative overflow-hidden rounded-[2.5rem] border border-slate-200 shadow-inner ${className}`}>
      <style>{`
        @keyframes routeFlow {
          from { stroke-dashoffset: 50; }
          to { stroke-dashoffset: 0; }
        }
        .animate-route-flow {
          animation: routeFlow 1s linear infinite;
          filter: drop-shadow(0 0 5px rgba(79, 70, 229, 0.5));
        }
        .driver-marker-container {
          position: relative;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .driver-glow {
          position: absolute;
          width: 50px;
          height: 50px;
          background: radial-gradient(circle, rgba(79, 70, 229, 0.4) 0%, transparent 70%);
          animation: markerPulse 2s ease-out infinite;
          z-index: 10;
        }
        @keyframes markerPulse {
          0% { transform: scale(0.8); opacity: 1; }
          100% { transform: scale(1.5); opacity: 0; }
        }
      `}</style>
      <div ref={mapContainerRef} className="w-full h-full" />

      <div className="absolute top-4 right-4 z-[1000] flex flex-col space-y-2">
        <div className="bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest text-indigo-600 border border-indigo-100 shadow-xl flex items-center">
          <i className="fas fa-location-arrow mr-2 animate-bounce"></i>
          Rastreamento em Tempo Real
        </div>
      </div>

      <div className="absolute bottom-4 left-4 z-[1000] bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 border border-slate-200 shadow-xl flex items-center">
        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse mr-2"></div>
        Conexão P2P Estável
      </div>
    </div>
  );
};

export default RealMap;

export enum UserRole {
  ADMIN = 'ADMIN',
  DRIVER = 'DRIVER',
  RIDER = 'RIDER'
}

export enum VehicleType {
  CAR = 'CAR',
  MOTORCYCLE = 'MOTORCYCLE'
}

export enum RideStatus {
  REQUESTED = 'REQUESTED',
  ACCEPTED = 'ACCEPTED',
  PICKUP = 'PICKUP',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum PaymentMethod {
  CARD = 'CARD',
  PIX = 'PIX',
  CASH = 'CASH',
  PREPAID = 'PREPAID'
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
  walletBalance?: number;
  // Driver specific
  licensePlate?: string;
  vehicleModel?: string;
  vehicleType?: VehicleType;
  rating?: number;
  earnings?: number;
  isOnline?: boolean;
}

export interface Location {
  lat: number;
  lng: number;
  address: string;
}

export interface Ride {
  id: string;
  riderId: string;
  driverId?: string;
  origin: Location;
  destination: Location;
  status: RideStatus;
  price: number;
  paymentMethod: PaymentMethod;
  vehicleTypeRequested: VehicleType;
  timestamp: string;
  distance: string;
  ratingToDriver?: number;
  ratingToRider?: number;
  messages?: ChatMessage[];
}

export interface PricingRule {
  id: string;
  regionName: string; // Ex: "Centro", "Bairro X"
  basePrice: number;  // Valor da bandeirada
  pricePerKm: number; // Valor por KM rodado
  active: boolean;
}

export interface PaymentSettings {
  apiKey: string;
  provider: 'Stripe' | 'MercadoPago' | 'PayPal';
  platformCommission: number; // Porcentagem
  pricingRules: PricingRule[];
}

export interface AppState {
  currentUser: UserProfile | null;
  rides: Ride[];
  users: UserProfile[];
  paymentSettings: PaymentSettings;
}

import React, { useState, useCallback, useMemo } from 'react';
import { UserRole, UserProfile, Ride, RideStatus, PaymentMethod, PaymentSettings, ChatMessage, PricingRule } from './types';
import Login from './pages/Login';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';
import Layout from './components/Layout';

const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true, vehicleType: 0 }, // VehicleType.CAR usually maps to 0 in some setups, but using enum is safer
];

// Corrigindo inicialização de tipos
MOCK_DRIVERS[0].vehicleType = 0 as any; // Trick for Car

const DEFAULT_PRICING: PricingRule[] = [
  { id: 'default', regionName: 'Geral (Padrão)', basePrice: 5.00, pricePerKm: 2.50, active: true },
  { id: 'center', regionName: 'Centro Histórico', basePrice: 8.00, pricePerKm: 3.50, active: true },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isAdminPortal, setIsAdminPortal] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>(() => {
    return [...MOCK_DRIVERS, { id: 'r1', name: 'João Paulo', email: 'joao@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200', walletBalance: 150.00 }];
  });
  const [rides, setRides] = useState<Ride[]>([]);
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    apiKey: '', 
    provider: 'Stripe',
    platformCommission: 15,
    pricingRules: DEFAULT_PRICING
  });

  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
      messages: []
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleSendMessage = useCallback((rideId: string, text: string) => {
    if (!currentUser) return;
    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      senderId: currentUser.id,
      text,
      timestamp: new Date().toISOString()
    };
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, messages: [...(ride.messages || []), newMessage] } : ride
    ));
  }, [currentUser]);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prevRides => {
      const rideIndex = prevRides.findIndex(r => r.id === rideId);
      if (rideIndex === -1) return prevRides;

      const updatedRides = [...prevRides];
      const targetRide = { 
        ...updatedRides[rideIndex], 
        status: newStatus, 
        driverId: driverId || updatedRides[rideIndex].driverId 
      };
      updatedRides[rideIndex] = targetRide;

      if (newStatus === RideStatus.COMPLETED) {
        const commission = paymentSettings.platformCommission / 100;
        const totalAmount = targetRide.price;
        const driverShare = totalAmount * (1 - commission);

        setUsers(prevUsers => prevUsers.map(user => {
          if (user.id === targetRide.driverId) {
            return { ...user, earnings: (user.earnings || 0) + driverShare };
          }
          if (user.id === targetRide.riderId && targetRide.paymentMethod === PaymentMethod.PREPAID) {
            const currentBalance = user.walletBalance || 0;
            return { ...user, walletBalance: currentBalance - totalAmount };
          }
          return user;
        }));
      }

      return updatedRides;
    });
  }, [paymentSettings.platformCommission]);

  const handleRateRide = useCallback((rideId: string, rating: number, role: UserRole) => {
    setRides(prev => prev.map(ride => {
      if (ride.id === rideId) {
        return role === UserRole.RIDER 
          ? { ...ride, ratingToDriver: rating } 
          : { ...ride, ratingToRider: rating };
      }
      return ride;
    }));
  }, []);

  const handleUpdateBalance = useCallback((userId: string, amount: number) => {
    setUsers(prev => prev.map(u => 
      u.id === userId ? { ...u, walletBalance: (u.walletBalance || 0) + amount } : u
    ));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      walletBalance: 0,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAdminPortal(false);
  };

  const driverRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.DRIVER) return [];
    return rides.filter(r => r.status === RideStatus.REQUESTED || r.driverId === currentUser.id);
  }, [rides, currentUser]);

  const riderRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.RIDER) return [];
    return rides.filter(r => r.riderId === currentUser.id);
  }, [rides, currentUser]);

  const availableDrivers = useMemo(() => 
    users.filter(u => u.role === UserRole.DRIVER && u.isOnline), 
    [users]
  );

  const currentUserWithLatestData = useMemo(() => {
    if (!currentUser) return null;
    return users.find(u => u.id === currentUser.id) || currentUser;
  }, [users, currentUser]);

  if (!currentUserWithLatestData) {
    if (isAdminPortal) {
      return <AdminLogin onLogin={setCurrentUser} onBackToPublic={() => setIsAdminPortal(false)} />;
    }
    return <Login onLogin={setCurrentUser} onRegister={handleRegister} onGoToAdmin={() => setIsAdminPortal(true)} />;
  }

  return (
    <Layout user={currentUserWithLatestData} onLogout={handleLogout}>
      {currentUserWithLatestData.role === UserRole.ADMIN && (
        <AdminDashboard 
          users={users} 
          rides={rides} 
          paymentSettings={paymentSettings}
          onUpdateSettings={setPaymentSettings}
        />
      )}

      {currentUserWithLatestData.role === UserRole.DRIVER && (
        <DriverDashboard 
          driver={currentUserWithLatestData} 
          rides={driverRides} 
          platformCommission={paymentSettings.platformCommission}
          onUpdateStatus={handleUpdateRideStatus}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}

      {currentUserWithLatestData.role === UserRole.RIDER && (
        <RiderDashboard 
          rider={currentUserWithLatestData} 
          rides={riderRides} 
          onRequestRide={handleRequestRide}
          availableDrivers={availableDrivers}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
          onUpdateBalance={handleUpdateBalance}
          paymentSettings={paymentSettings}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserProfile, Ride, UserRole, RideStatus, PaymentSettings, VehicleType, PricingRule } from '../types';
import { getAdminBriefing } from '../services/geminiService';

interface AdminDashboardProps {
  users: UserProfile[];
  rides: Ride[];
  paymentSettings: PaymentSettings;
  onUpdateSettings: (settings: PaymentSettings) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, rides, paymentSettings, onUpdateSettings }) => {
  const [aiBriefing, setAiBriefing] = useState("Analisando operações...");
  const [view, setView] = useState<'overview' | 'users' | 'rides' | 'pricing' | 'settings'>('overview');
  const [tempSettings, setTempSettings] = useState(paymentSettings);
  const [selectedRideDetail, setSelectedRideDetail] = useState<Ride | null>(null);

  const [newRule, setNewRule] = useState<Omit<PricingRule, 'id'>>({
    regionName: '',
    basePrice: 0,
    pricePerKm: 0,
    active: true
  });

  const drivers = users.filter(u => u.role === UserRole.DRIVER);
  const riders = users.filter(u => u.role === UserRole.RIDER);
  const activeRides = rides.filter(r => r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);
  const totalRevenue = rides.reduce((acc, r) => acc + r.price, 0);
  const platformEarnings = rides.filter(r => r.status === RideStatus.COMPLETED).reduce((acc, r) => acc + (r.price * (paymentSettings.platformCommission / 100)), 0);

  useEffect(() => {
    const fetchBriefing = async () => {
      const briefing = await getAdminBriefing(activeRides.length, totalRevenue);
      setAiBriefing(briefing);
    };
    fetchBriefing();
  }, [activeRides.length, totalRevenue]);

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    onUpdateSettings(tempSettings);
    alert('Configurações atualizadas com sucesso!');
  };

  const handleAddPricingRule = () => {
    if (!newRule.regionName) return;
    const rule: PricingRule = { ...newRule, id: `rule-${Date.now()}` };
    const updatedSettings = { ...tempSettings, pricingRules: [...tempSettings.pricingRules, rule] };
    setTempSettings(updatedSettings);
    onUpdateSettings(updatedSettings);
    setNewRule({ regionName: '', basePrice: 0, pricePerKm: 0, active: true });
