};

export default RiderDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { UserProfile, Ride, UserRole, RideStatus, PaymentSettings, VehicleType, PricingRule } from '../types';
import { getAdminBriefing } from '../services/geminiService';

interface AdminDashboardProps {
  users: UserProfile[];
  rides: Ride[];
  paymentSettings: PaymentSettings;
  onUpdateSettings: (settings: PaymentSettings) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, rides, paymentSettings, onUpdateSettings }) => {
  const [aiBriefing, setAiBriefing] = useState("Analisando operações...");
  const [view, setView] = useState<'overview' | 'users' | 'rides' | 'pricing' | 'transactions' | 'settings'>('overview');
  const [tempSettings, setTempSettings] = useState(paymentSettings);
  const [selectedRideDetail, setSelectedRideDetail] = useState<Ride | null>(null);

  // Estados para Filtros e Ordenação de Viagens
  const [ridesSearch, setRidesSearch] = useState('');
  const [ridesStatusFilter, setRidesStatusFilter] = useState<RideStatus | 'ALL'>('ALL');
  const [ridesSortConfig, setRidesSortConfig] = useState<{ key: 'timestamp' | 'price' | 'riderName', direction: 'asc' | 'desc' }>({ key: 'timestamp', direction: 'desc' });

  const [newRule, setNewRule] = useState<Omit<PricingRule, 'id'>>({
    regionName: '', basePrice: 0, pricePerKm: 0, active: true
  });

  const getUserById = (id?: string) => users.find(u => u.id === id);

  // Lógica de Filtragem e Ordenação das Viagens
  const filteredAndSortedRides = useMemo(() => {
    let result = [...rides];

    // Busca
    if (ridesSearch.trim()) {
      const search = ridesSearch.toLowerCase();
      result = result.filter(r => {
        const rider = getUserById(r.riderId);
        return rider?.name.toLowerCase().includes(search) || r.id.toLowerCase().includes(search);
      });
    }

    // Status
    if (ridesStatusFilter !== 'ALL') {
      result = result.filter(r => r.status === ridesStatusFilter);
    }

    // Ordenação
    result.sort((a, b) => {
      let valA: any = a[ridesSortConfig.key as keyof Ride] || '';
      let valB: any = b[ridesSortConfig.key as keyof Ride] || '';

      if (ridesSortConfig.key === 'riderName') {
        valA = getUserById(a.riderId)?.name || '';
        valB = getUserById(b.riderId)?.name || '';
      }

      if (valA < valB) return ridesSortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return ridesSortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [rides, ridesSearch, ridesStatusFilter, ridesSortConfig, users]);

  const drivers = users.filter(u => u.role === UserRole.DRIVER);
  const ridersCount = users.filter(u => u.role === UserRole.RIDER).length;
  const activeRides = rides.filter(r => r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);
  const completedRides = useMemo(() => rides.filter(r => r.status === RideStatus.COMPLETED), [rides]);

  const totalRevenue = rides.reduce((acc, r) => acc + r.price, 0);
  const platformEarnings = completedRides.reduce((acc, r) => acc + (r.price * (paymentSettings.platformCommission / 100)), 0);
  const driverPayouts = completedRides.reduce((acc, r) => acc + (r.price * (1 - paymentSettings.platformCommission / 100)), 0);

  useEffect(() => {
    const fetchBriefing = async () => {
      const briefing = await getAdminBriefing(activeRides.length, totalRevenue);
      setAiBriefing(briefing);
    };
    fetchBriefing();
  }, [activeRides.length, totalRevenue]);

  const toggleSort = (key: 'timestamp' | 'price' | 'riderName') => {
    setRidesSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const getStatusColor = (status: RideStatus) => {
    switch (status) {
      case RideStatus.COMPLETED: return 'bg-green-100 text-green-600';
      case RideStatus.CANCELLED: return 'bg-red-100 text-red-600';
      case RideStatus.REQUESTED: return 'bg-blue-100 text-blue-600';
      case RideStatus.ACCEPTED:
      case RideStatus.PICKUP:
      case RideStatus.IN_PROGRESS: return 'bg-amber-100 text-amber-600';
      default: return 'bg-slate-100 text-slate-600';
    }
  };

  const handleAddPricingRule = () => {
    if (!newRule.regionName) return;
    const rule: PricingRule = { ...newRule, id: `rule-${Date.now()}` };
    const updatedSettings = { ...tempSettings, pricingRules: [...tempSettings.pricingRules, rule] };
    setTempSettings(updatedSettings);
    onUpdateSettings(updatedSettings);
    setNewRule({ regionName: '', basePrice: 0, pricePerKm: 0, active: true });
  };

  return (
    <div className="space-y-8 animate-fade-in pb-12">
      {selectedRideDetail && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 md:p-6 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
           <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-xl font-black text-indigo-950 uppercase">Detalhes da Corrida</h3>
                <button onClick={() => setSelectedRideDetail(null)} className="text-slate-400 hover:text-red-500 transition-colors"><i className="fas fa-times text-xl"></i></button>
              </div>
              <div className="flex-1 overflow-y-auto p-8 space-y-4">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-2xl">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Passageiro</p>
                       <p className="font-bold">{getUserById(selectedRideDetail.riderId)?.name}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-2xl">
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Motorista</p>
                       <p className="font-bold">{getUserById(selectedRideDetail.driverId)?.name || 'Nenhum'}</p>
                    </div>
                 </div>
                 <div className="bg-slate-50 p-4 rounded-2xl">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Endereço Destino</p>
                    <p className="font-bold text-sm">{selectedRideDetail.destination.address}</p>
                 </div>
                 <div className="flex justify-between items-center bg-indigo-50 p-4 rounded-2xl">
                    <p className="font-black text-indigo-950 uppercase">Preço Total</p>
                    <p className="text-2xl font-black text-indigo-600">R$ {selectedRideDetail.price.toFixed(2)}</p>
                 </div>
              </div>
           </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Portal do Administrador</h2>
          <p className="text-slate-500 font-medium">Controle total do ecossistema Duarte Entregas.</p>
        </div>
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto no-scrollbar">
          {(['overview', 'users', 'rides', 'pricing', 'transactions', 'settings'] as const).map(v => (
            <button 
              key={v}
              onClick={() => setView(v)}
              className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shrink-0 ${view === v ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              {v === 'overview' ? 'Geral' : v === 'users' ? 'Usuários' : v === 'rides' ? 'Viagens' : v === 'pricing' ? 'Tarifas' : v === 'transactions' ? 'Finanças' : 'Config'}
            </button>
          ))}
        </div>
      </div>

      {view === 'overview' && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { icon: 'fa-users', label: 'Base de Usuários', val: users.length, diff: `${ridersCount} Passageiros` },
            { icon: 'fa-car', label: 'Frota de Parceiros', val: drivers.length, diff: `${drivers.filter(d => d.isOnline).length} Online` },
            { icon: 'fa-route', label: 'Tráfego do Dia', val: rides.length, diff: `${activeRides.length} em curso` },
            { icon: 'fa-wallet', label: 'Lucro Plataforma', val: `R$ ${platformEarnings.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, diff: `${paymentSettings.platformCommission}% de taxa` }
          ].map((stat, i) => (
            <div key={i} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
              <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center mb-4"><i className={`fas ${stat.icon} text-xl`}></i></div>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</p>
              <h3 className="text-2xl font-black text-slate-900 mt-1">{stat.val}</h3>
              <p className="text-indigo-600 text-[10px] font-bold mt-2">{stat.diff}</p>
            </div>
          ))}
        </div>
      )}

      {view === 'rides' && (
        <div className="space-y-4 animate-slide-up">
           {/* Barra de Filtros */}
           <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center">
              <div className="flex-1 w-full relative">
                 <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                 <input 
                   type="text" 
                   placeholder="Buscar por passageiro ou ID..." 
                   className="w-full pl-12 pr-4 py-3 bg-slate-50 rounded-xl font-bold text-sm outline-none focus:ring-2 ring-indigo-500/10"
                   value={ridesSearch}
                   onChange={e => setRidesSearch(e.target.value)}
                 />
              </div>
              <div className="w-full md:w-48">
                 <select 
                   className="w-full px-4 py-3 bg-slate-50 rounded-xl font-black text-[10px] uppercase tracking-widest outline-none cursor-pointer"
                   value={ridesStatusFilter}
                   onChange={e => setRidesStatusFilter(e.target.value as any)}
                 >
                    <option value="ALL">Todos Status</option>
                    {Object.values(RideStatus).map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
              </div>
           </div>

           <div className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                    <tr>
                      <th onClick={() => toggleSort('timestamp')} className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-indigo-600 transition-colors group">
                        Data {ridesSortConfig.key === 'timestamp' && <i className={`fas fa-sort-amount-${ridesSortConfig.direction === 'desc' ? 'down' : 'up'} ml-2`}></i>}
                      </th>
                      <th onClick={() => toggleSort('riderName')} className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest cursor-pointer hover:text-indigo-600 transition-colors group">
                        Passageiro {ridesSortConfig.key === 'riderName' && <i className={`fas fa-sort-amount-${ridesSortConfig.direction === 'desc' ? 'down' : 'up'} ml-2`}></i>}
                      </th>
                      <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                      <th onClick={() => toggleSort('price')} className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right cursor-pointer hover:text-indigo-600 transition-colors group">
                        Valor {ridesSortConfig.key === 'price' && <i className={`fas fa-sort-amount-${ridesSortConfig.direction === 'desc' ? 'down' : 'up'} ml-2`}></i>}
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredAndSortedRides.length === 0 ? (
                      <tr><td colSpan={4} className="px-8 py-20 text-center text-slate-400 font-bold uppercase text-xs">Nenhuma viagem encontrada para os filtros aplicados.</td></tr>
                    ) : (
                      filteredAndSortedRides.map(r => (
                        <tr key={r.id} onClick={() => setSelectedRideDetail(r)} className="hover:bg-slate-50 cursor-pointer transition-colors group">
                          <td className="px-8 py-4">
                            <div className="text-xs font-black text-indigo-950">#{r.id.split('-')[1]}</div>
                            <div className="text-[9px] text-slate-400 font-bold">{new Date(r.timestamp).toLocaleString()}</div>
                          </td>
                          <td className="px-8 py-4">
                            <div className="text-xs font-bold text-slate-600">{getUserById(r.riderId)?.name}</div>
                          </td>
                          <td className="px-8 py-4">
                            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${getStatusColor(r.status)}`}>{r.status}</span>
                          </td>
                          <td className="px-8 py-4 text-right">
                            <span className="font-black text-indigo-950 text-xs group-hover:text-indigo-600">R$ {r.price.toFixed(2)}</span>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
           </div>
        </div>
      )}

      {/* Resto das views (transactions, users, settings, pricing) permanecem conforme implementações anteriores */}
      {view === 'overview' && (
        <div className="bg-indigo-600 rounded-[2rem] p-8 text-white flex flex-col md:flex-row items-start md:items-center space-y-4 md:space-y-0 md:space-x-6 shadow-xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 rotate-12 transition-transform group-hover:scale-110"><i className="fas fa-brain text-9xl"></i></div>
          <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center shrink-0 backdrop-blur-md"><i className="fas fa-robot text-2xl"></i></div>
          <div className="relative z-10"><h4 className="font-black text-xl tracking-tight mb-1">Análise Estratégica Duarte AI</h4><p className="opacity-90 leading-relaxed max-w-2xl font-medium">{aiBriefing}</p></div>
        </div>
      )}
    </div>
  );
};

