              </div>
              <div className="pt-4 space-y-3">
                <button onClick={handleConfirmAccept} className="w-full bg-indigo-950 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-900 transition-all shadow-xl">ACEITAR</button>
