                  </div>
                  <div className="text-right">
                     <p className="text-[10px] font-black uppercase opacity-60">Método de Pagamento</p>
                     <span className={`font-bold text-xs px-3 py-1 rounded-full uppercase ${myActiveRide.paymentMethod === PaymentMethod.PREPAID ? 'bg-green-600/30' : 'bg-indigo-600/30'}`}>
                       {myActiveRide.paymentMethod === PaymentMethod.PREPAID ? 'Carteira (Automático)' : myActiveRide.paymentMethod}
