            <div className="h-[300px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis 
                    dataKey="name" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} 
                  />
                  <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} 
                  />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }}
                    contentStyle={{ 
                      borderRadius: '16px', 
                      border: 'none', 
                      boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)',
                      fontSize: '12px',
                      fontWeight: 'bold'
                    }}
                  />
                  <Bar dataKey="bruto" fill="#e2e8f0" radius={[4, 4, 0, 0]} barSize={20} />
                  <Bar dataKey="liquido" fill="#4f46e5" radius={[4, 4, 0, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm">
            <div className="p-6 border-b border-slate-50 flex justify-between items-center">
              <h4 className="font-black text-indigo-950 uppercase text-xs tracking-widest">Últimos Ganhos</h4>
              <span className="text-[9px] font-black text-slate-400 uppercase">{completedRides.length} Corridas</span>
            </div>
            <div className="divide-y divide-slate-50">
              {completedRides.length === 0 ? (
                <div className="p-12 text-center text-slate-300 font-bold uppercase text-[10px]">Sem histórico recente</div>
              ) : (
                completedRides.map(ride => (
                  <div key={ride.id} className="p-6 flex justify-between items-center hover:bg-slate-50 transition-colors">
                    <div>
                      <p className="text-xs font-black text-indigo-950 uppercase">{ride.destination.address}</p>
                      <p className="text-[9px] text-slate-400 font-bold uppercase">{new Date(ride.timestamp).toLocaleDateString()} • {ride.paymentMethod}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-black text-green-600">+ R$ {calculateGain(ride.price).toFixed(2)}</p>
                      <p className="text-[8px] text-slate-300 font-black uppercase">Bruto: R$ {ride.price.toFixed(2)}</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

