                >
                  SIM, CANCELAR
                </button>
                <button 
                  onClick={() => setShowCancelConfirmation(false)}
                  className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-slate-200 transition-all"
                >
                  MANTER VIAGEM
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id}
          messages={activeRide.messages || []}
          currentUserId={rider.id}
          onSendMessage={onSendMessage}
