import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';

interface ChatWidgetProps {
  rideId: string;
  messages: ChatMessage[];
  currentUserId: string;
  onSendMessage: (rideId: string, text: string) => void;
  otherPartyName: string;
  isOpen?: boolean;
  onToggle?: (open: boolean) => void;
  isOtherTyping?: boolean; // Nova prop para o indicador de digitação
}

const ChatWidget: React.FC<ChatWidgetProps> = ({ 
  rideId, messages, currentUserId, onSendMessage, otherPartyName,
  isOpen: externalOpen, onToggle, isOtherTyping = false
}) => {
  const [internalOpen, setInternalOpen] = useState(false);
  const [text, setText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const isOpen = externalOpen !== undefined ? externalOpen : internalOpen;

  useEffect(() => {
    if (scrollRef.current && isOpen) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen, isOtherTyping]);

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onSendMessage(rideId, text.trim());
      setText('');
    }
  };

  const toggleChat = () => {
    if (onToggle) onToggle(!isOpen);
    else setInternalOpen(!isOpen);
  };

  return (
    <div className="fixed bottom-24 right-6 z-[100] md:bottom-8 md:right-8">
      <style>{`
        @keyframes typingBounce {
          0%, 60%, 100% { transform: translateY(0); }
          30% { transform: translateY(-4px); }
        }
        .typing-dot {
          animation: typingBounce 1.4s infinite ease-in-out;
        }
        .typing-dot:nth-child(2) { animation-delay: 0.2s; }
        .typing-dot:nth-child(3) { animation-delay: 0.4s; }
      `}</style>

      {isOpen ? (
        <div className="bg-white w-[320px] h-[450px] rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-scale-up">
          <div className="p-5 bg-indigo-950 text-white flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <div className="relative">
                <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                  <i className="fas fa-comment-alt text-xs"></i>
                </div>
                {isOtherTyping && (
                  <span className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-indigo-950 rounded-full animate-pulse"></span>
                )}
              </div>
              <div className="flex flex-col">
                <span className="font-black text-xs uppercase tracking-widest leading-none">{otherPartyName}</span>
                {isOtherTyping && <span className="text-[8px] font-bold text-indigo-300 uppercase tracking-tighter mt-1">Digitando...</span>}
              </div>
            </div>
            <button onClick={toggleChat} className="opacity-60 hover:opacity-100 transition-opacity p-2">
              <i className="fas fa-times"></i>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
            {messages.length === 0 && !isOtherTyping ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-300">
                <i className="fas fa-comments text-4xl mb-2 opacity-20"></i>
                <p className="text-[10px] font-black uppercase tracking-widest">Sem mensagens ainda</p>
              </div>
            ) : (
              <>
                {messages.map(msg => (
                  <div key={msg.id} className={`flex ${msg.senderId === currentUserId ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                      msg.senderId === currentUserId 
                        ? 'bg-indigo-600 text-white rounded-br-none' 
                        : 'bg-white border border-slate-200 text-slate-700 rounded-bl-none shadow-sm'
                    }`}>
                      <p className="leading-relaxed">{msg.text}</p>
                      <p className={`text-[8px] mt-1 font-bold uppercase ${msg.senderId === currentUserId ? 'text-indigo-200' : 'text-slate-400'}`}>
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </p>
                    </div>
                  </div>
                ))}

                {isOtherTyping && (
                  <div className="flex justify-start animate-fade-in">
                    <div className="bg-white border border-slate-200 px-4 py-3 rounded-2xl rounded-bl-none shadow-sm flex items-center space-x-1">
                      <div className="typing-dot w-1.5 h-1.5 bg-slate-300 rounded-full"></div>
                      <div className="typing-dot w-1.5 h-1.5 bg-slate-300 rounded-full"></div>
                      <div className="typing-dot w-1.5 h-1.5 bg-slate-300 rounded-full"></div>
                    </div>
                  </div>
                )}
              </>
            )}
          </div>

          <form onSubmit={handleSend} className="p-4 bg-white border-t border-slate-100 flex items-center space-x-2">
            <input 
              type="text" 
              value={text}
              onChange={e => setText(e.target.value)}
              placeholder="Escreva uma mensagem..." 
              className="flex-1 bg-slate-50 px-4 py-2.5 rounded-xl text-sm focus:outline-none border border-transparent focus:border-indigo-100 transition-all placeholder:text-slate-300 font-medium"
            />
            <button type="submit" disabled={!text.trim()} className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-lg transition-all active:scale-95 ${text.trim() ? 'bg-indigo-950 text-white' : 'bg-slate-100 text-slate-300'}`}>
              <i className="fas fa-paper-plane text-xs"></i>
            </button>
          </form>
        </div>
      ) : (
        <button 
          onClick={toggleChat}
          className="w-16 h-16 bg-indigo-950 text-white rounded-full flex items-center justify-center shadow-2xl hover:scale-105 transition-transform relative group"
        >
          <i className="fas fa-comment-dots text-2xl"></i>
          {(messages.length > 0 || isOtherTyping) && (
            <span className={`absolute -top-1 -right-1 ${isOtherTyping ? 'bg-green-500 animate-pulse' : 'bg-red-500'} text-white w-6 h-6 rounded-full border-4 border-white text-[10px] font-black flex items-center justify-center shadow-sm`}>
              {isOtherTyping ? <i className="fas fa-ellipsis-h"></i> : messages.length}
            </span>
          )}
          <span className="absolute right-20 bg-indigo-950 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap shadow-xl">
            {isOtherTyping ? `${otherPartyName} digitando...` : `Falar com ${otherPartyName}`}
          </span>
        </button>
      )}
    </div>
  );
};

export default ChatWidget;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType, PricingRule } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  onUpdateStatus: (rideId: string, status: RideStatus) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, onUpdateStatus, availableDrivers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings 
}) => {
  const [view, setView] = useState<'request' | 'history' | 'wallet'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleType>(VehicleType.CAR);
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [selectedRideReceipt, setSelectedRideReceipt] = useState<Ride | null>(null);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('20.00');
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showCancelConfirmation, setShowCancelConfirmation] = useState(false);
  const [isDriverTyping, setIsDriverTyping] = useState(false);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  // Simulação de digitação do motorista quando a corrida é aceita
  useEffect(() => {
    if (activeRide?.status === RideStatus.ACCEPTED) {
      const timeout = setTimeout(() => setIsDriverTyping(true), 3000);
      const stopTimeout = setTimeout(() => setIsDriverTyping(false), 8000);
      return () => { clearTimeout(timeout); clearTimeout(stopTimeout); };
    }
    setIsDriverTyping(false);
  }, [activeRide?.status]);

  const pricingData = useMemo(() => {
    const rules = paymentSettings.pricingRules;
    const destLower = destination.toLowerCase();

    let activeRule = rules.find(r => destLower.includes(r.regionName.toLowerCase())) || rules.find(r => r.id === 'default');
    if (!activeRule) activeRule = { id: 'fallback', regionName: 'Padrão', basePrice: 5, pricePerKm: 2, active: true };

    const estimatedDistKm = 4.8;
    const calculateForService = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
      const multipliers = { UberX: 1.0, UberComfort: 1.3, UberBlack: 1.8 };
      const vehicleMult = selectedVehicle === VehicleType.MOTORCYCLE ? 0.65 : 1.0;
      const price = (activeRule!.basePrice + (activeRule!.pricePerKm * estimatedDistKm)) * multipliers[service] * vehicleMult;
      return price;
    };

    return {
      ruleName: activeRule.regionName,
      prices: { UberX: calculateForService('UberX'), UberComfort: calculateForService('UberComfort'), UberBlack: calculateForService('UberBlack') }
    };
  }, [destination, selectedVehicle, paymentSettings.pricingRules]);

  const currentPrice = pricingData.prices[selectedService];

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude }),
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const targetLat = userPos.lat;
          const targetLng = userPos.lng;
          if (!prev) return { lat: targetLat + 0.01, lng: targetLng + 0.01 };
          const step = 0.0001;
          const dLat = targetLat - prev.lat;
          const dLng = targetLng - prev.lng;
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;
          return { lat: prev.lat + (dLat > 0 ? step : -step), lng: prev.lng + (dLng > 0 ? step : -step) };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
  }, [activeRide?.status, userPos]);

  const handleConfirmRide = () => {
    if (!destination || !userPos) return;
    if (selectedPayment === PaymentMethod.PREPAID && (rider.walletBalance || 0) < currentPrice) {
      alert("Saldo insuficiente na carteira.");
      return;
    }
    onRequestRide({
      riderId: rider.id,
      origin: { lat: userPos.lat, lng: userPos.lng, address: origin },
      destination: { lat: userPos.lat + 0.02, lng: userPos.lng + 0.02, address: destination },
      price: currentPrice,
      paymentMethod: selectedPayment,
      vehicleTypeRequested: selectedVehicle,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const handleCancelRide = () => {
    if (activeRide) {
      onUpdateStatus(activeRide.id, RideStatus.CANCELLED);
      setShowCancelConfirmation(false);
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista Parceiro',
      avatar: 'https://picsum.photos/seed/unknown/200',
      vehicleModel: 'Veículo Padrão',
      licensePlate: 'BRA-2025',
      vehicleType: selectedVehicle
    };
  };

  const paymentOptions = [
    { id: PaymentMethod.CARD, label: 'Cartão', icon: 'fa-credit-card', color: 'text-blue-600' },
    { id: PaymentMethod.PIX, label: 'Pix', icon: 'fa-qrcode', color: 'text-teal-500' },
    { id: PaymentMethod.PREPAID, label: `Carteira`, icon: 'fa-wallet', color: 'text-indigo-600' },
    { id: PaymentMethod.CASH, label: 'Dinheiro', icon: 'fa-money-bill-wave', color: 'text-green-600' },
  ];

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {/* Modal de Confirmação de Cancelamento */}
      {showCancelConfirmation && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-slate-100">
            <div className="p-10 text-center">
              <div className="w-20 h-20 bg-red-50 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-6 text-3xl shadow-inner">
                <i className="fas fa-exclamation-triangle"></i>
              </div>
              <h3 className="text-2xl font-black text-indigo-950 tracking-tight">Cancelar Corrida?</h3>
              <p className="text-slate-500 font-medium mt-3 leading-relaxed">Tem certeza que deseja cancelar esta viagem? Taxas podem ser aplicadas.</p>

              <div className="mt-10 space-y-3">
                <button 
                  onClick={handleCancelRide}
                  className="w-full bg-red-600 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-red-700 transition-all shadow-xl shadow-red-200"
                >
                  SIM, CANCELAR
                </button>
                <button 
                  onClick={() => setShowCancelConfirmation(false)}
                  className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-slate-200 transition-all"
                >
                  MANTER VIAGEM
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id}
          messages={activeRide.messages || []}
          currentUserId={rider.id}
          onSendMessage={onSendMessage}
          otherPartyName={findDriverInfo(activeRide.driverId).name}
          isOpen={isChatOpen}
          onToggle={setIsChatOpen}
          isOtherTyping={isDriverTyping}
        />
      )}

      {!activeRide && (
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
            <button onClick={() => setView('request')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'request' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Pedir</button>
            <button onClick={() => setView('history')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Histórico</button>
            <button onClick={() => setView('wallet')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'wallet' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Carteira</button>
          </div>

          {view === 'request' && (
            <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
              <button onClick={() => setSelectedVehicle(VehicleType.CAR)} className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.CAR ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
                <i className="fas fa-car text-xs"></i><span className="text-[10px] font-black uppercase tracking-widest">Carro</span>
              </button>
              <button onClick={() => setSelectedVehicle(VehicleType.MOTORCYCLE)} className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.MOTORCYCLE ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
                <i className="fas fa-motorcycle text-xs"></i><span className="text-[10px] font-black uppercase tracking-widest">Moto</span>
              </button>
            </div>
          )}
        </div>
      )}

      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 relative group">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div className="flex items-center space-x-4">
                <div>
                  <h3 className="text-2xl font-black text-indigo-950 tracking-tight">Viagem Ativa</h3>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{activeRide.status}</p>
                </div>
              </div>
              <div className="flex items-center space-x-4">
                <button 
                  onClick={() => setIsChatOpen(prev => !prev)}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-lg ${isChatOpen ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-indigo-950 hover:bg-indigo-50'}`}
                  title="Chat com Motorista"
                >
                  <i className={`fas ${isChatOpen ? 'fa-times' : 'fa-comment-dots'} text-lg`}></i>
                </button>
                <div className="h-10 w-px bg-slate-100 hidden sm:block"></div>
                <div className="text-right">
                  <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Total</span>
                  <span className="text-2xl font-black text-indigo-950">R$ {activeRide.price.toFixed(2)}</span>
                </div>
              </div>
           </div>

           <div className="h-[500px] w-full p-2 bg-slate-50 relative">
              <RealMap className="h-full w-full" riderLocation={userPos} driverLocation={driverPos}/>

              <div className="absolute top-4 left-4 z-[1000] flex flex-col space-y-3 pointer-events-none">
                <div className="bg-white/95 backdrop-blur shadow-2xl rounded-[2rem] p-5 border border-slate-200 pointer-events-auto animate-slide-up max-w-[220px]">
                  <div className="flex items-center space-x-3 mb-4">
                    <img src={findDriverInfo(activeRide.driverId).avatar} className="w-12 h-12 rounded-2xl border-2 border-slate-100 shadow-sm object-cover" />
                    <div>
                      <p className="text-[10px] font-black text-indigo-950 uppercase tracking-tight truncate">{findDriverInfo(activeRide.driverId).name}</p>
                      <div className="flex items-center text-[8px] font-bold text-slate-400 uppercase mt-0.5">
                        <i className="fas fa-star text-amber-400 mr-1"></i> 4.9 • {findDriverInfo(activeRide.driverId).licensePlate}
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 gap-2">
                    <button 
                      onClick={() => setIsChatOpen(true)}
                      className="w-full bg-indigo-950 text-white py-3 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-900 transition-colors shadow-lg shadow-indigo-100"
                    >
                      Mandar Mensagem
                    </button>
                    <button 
                      onClick={() => setShowCancelConfirmation(true)}
                      className="w-full bg-white text-red-500 border border-red-100 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-50 transition-colors"
                    >
                      Cancelar Corrida
                    </button>
                  </div>
                </div>
              </div>

              {/* Atração Visual para Cancelamento em Mobile */}
              <div className="md:hidden absolute bottom-24 left-1/2 -translate-x-1/2 z-[1000] pointer-events-auto">
                <button 
                  onClick={() => setShowCancelConfirmation(true)}
                  className="bg-white/90 backdrop-blur-md px-6 py-3 rounded-full border border-red-100 shadow-2xl text-[10px] font-black text-red-600 uppercase tracking-widest flex items-center space-x-2"
                >
                  <i className="fas fa-times-circle"></i>
                  <span>Cancelar Viagem</span>
                </button>
              </div>
           </div>
        </div>
      ) : view === 'request' ? (
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
          <h2 className="text-4xl font-black mb-10 text-indigo-950 tracking-tighter">Para onde vamos hoje?</h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rounded-full"></div><input disabled value={userPos ? "Sua Localização GPS" : "Obtendo GPS..."} className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-500 font-bold text-lg" /></div>
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-indigo-600 rounded-full"></div><input autoFocus placeholder="Inserir destino (Ex: Centro)" value={destination} onChange={e => setDestination(e.target.value)} className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none transition-all" /></div>
              {destination && (
                <div className="space-y-6 pt-4 animate-slide-up">
                  <div className="bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black text-indigo-600 uppercase flex items-center"><i className="fas fa-tag mr-2"></i> Tarifa aplicada: {pricingData.ruleName}</div>
                  <div className="grid gap-3">{(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                      <button key={service} onClick={() => setSelectedService(service)} className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-indigo-950 bg-indigo-50 shadow-md' : 'border-slate-100'}`}>
                        <div className="flex items-center space-x-3"><i className={`fas ${selectedVehicle === VehicleType.MOTORCYCLE ? 'fa-motorcycle' : 'fa-car-side'} ${selectedService === service ? 'text-indigo-950' : 'text-slate-400'}`}></i><span className={`font-black text-lg ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>{selectedVehicle === VehicleType.MOTORCYCLE ? `Moto ${service.replace('Uber', '')}` : service}</span></div>
                        <span className={`font-black text-xl ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>R$ {pricingData.prices[service].toFixed(2)}</span>
                      </button>
                    ))}</div>
                  <div className="grid grid-cols-2 gap-3">{paymentOptions.map(opt => (<button key={opt.id} onClick={() => setSelectedPayment(opt.id)} className={`flex items-center space-x-3 p-4 rounded-xl border-2 transition-all ${selectedPayment === opt.id ? 'border-indigo-950 bg-indigo-50' : 'border-slate-100'}`}><i className={`fas ${opt.icon} ${opt.color}`}></i><span className={`text-[10px] font-black uppercase tracking-tight ${selectedPayment === opt.id ? 'text-indigo-950' : 'text-slate-400'}`}>{opt.label}</span></button>))}</div>
                  <button onClick={handleConfirmRide} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl hover:bg-indigo-900 transition-all shadow-2xl mt-4 active:scale-95">SOLICITAR AGORA</button>
                </div>
              )}
            </div>
            <div className="hidden md:block h-full min-h-[400px]"><RealMap className="h-full w-full" riderLocation={userPos} /></div>
          </div>
        </div>
      ) : view === 'history' ? (
        <div className="space-y-4">
          <h2 className="text-3xl font-black text-indigo-950 px-2 tracking-tighter">Minhas Viagens</h2>
          <div className="grid gap-4">{completedRides.map(ride => (
              <div key={ride.id} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm flex justify-between items-center group cursor-pointer" onClick={() => setSelectedRideReceipt(ride)}>
                <div className="flex items-center space-x-4"><div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-900"><i className="fas fa-history"></i></div><div><h4 className="font-black text-indigo-950 group-hover:text-indigo-600">Viagem em {new Date(ride.timestamp).toLocaleDateString()}</h4><p className="text-[10px] font-bold text-slate-400 uppercase">{ride.destination.address}</p></div></div>
                <div className="text-right"><p className="text-xl font-black text-indigo-950">R$ {ride.price.toFixed(2)}</p></div>
              </div>
            ))}</div>
        </div>
      ) : (
        <div className="space-y-6 animate-fade-in">
           <div className="bg-indigo-950 p-10 rounded-[2.5rem] text-white flex flex-col md:flex-row justify-between items-center shadow-2xl border border-white/10">
              <div><p className="text-indigo-300 font-black uppercase text-[10px] tracking-widest mb-1">Saldo em Carteira</p><h2 className="text-6xl font-black">R$ {rider.walletBalance?.toFixed(2) || '0,00'}</h2></div>
              <button onClick={() => setIsAddingFunds(true)} className="mt-6 md:mt-0 bg-white text-indigo-950 px-10 py-5 rounded-2xl font-black text-sm uppercase shadow-xl hover:bg-indigo-50">Recarregar</button>
           </div>
        </div>
      )}
    </div>
  );
};

