import React, { useState, useCallback, useMemo } from 'react';
import { UserRole, UserProfile, Ride, RideStatus, PaymentMethod, PaymentSettings, ChatMessage, PricingRule, VehicleType } from './types';
import Login from './pages/Login';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';
import Layout from './components/Layout';

const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true, vehicleType: VehicleType.CAR },
];

const DEFAULT_PRICING: PricingRule[] = [
  { id: 'default', regionName: 'Geral (Padrão)', basePrice: 5.00, pricePerKm: 2.50, active: true },
  { id: 'center', regionName: 'Centro Histórico', basePrice: 8.00, pricePerKm: 3.50, active: true },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isAdminPortal, setIsAdminPortal] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>(() => {
    return [...MOCK_DRIVERS, { id: 'r1', name: 'João Paulo', email: 'joao@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200', walletBalance: 150.00 }];
  });
  const [rides, setRides] = useState<Ride[]>([]);
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    apiKey: '', 
    provider: 'Stripe',
    platformCommission: 15,
    pricingRules: DEFAULT_PRICING
  });

  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
      messages: []
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleSendMessage = useCallback((rideId: string, text: string) => {
    if (!currentUser) return;
    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      senderId: currentUser.id,
      text,
      timestamp: new Date().toISOString()
    };
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, messages: [...(ride.messages || []), newMessage] } : ride
    ));
  }, [currentUser]);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prevRides => {
      const rideIndex = prevRides.findIndex(r => r.id === rideId);
      if (rideIndex === -1) return prevRides;

      const updatedRides = [...prevRides];
      const targetRide = { 
        ...updatedRides[rideIndex], 
        status: newStatus, 
        driverId: driverId || updatedRides[rideIndex].driverId 
      };
      updatedRides[rideIndex] = targetRide;

      if (newStatus === RideStatus.COMPLETED) {
        const commission = paymentSettings.platformCommission / 100;
        const totalAmount = targetRide.price;
        const driverShare = totalAmount * (1 - commission);

        setUsers(prevUsers => prevUsers.map(user => {
          if (user.id === targetRide.driverId) {
            return { ...user, earnings: (user.earnings || 0) + driverShare };
          }
          if (user.id === targetRide.riderId && targetRide.paymentMethod === PaymentMethod.PREPAID) {
            const currentBalance = user.walletBalance || 0;
            return { ...user, walletBalance: currentBalance - totalAmount };
          }
          return user;
        }));
      }

      return updatedRides;
    });
  }, [paymentSettings.platformCommission]);

  const handleRateRide = useCallback((rideId: string, rating: number, role: UserRole) => {
    setRides(prev => prev.map(ride => {
      if (ride.id === rideId) {
        return role === UserRole.RIDER 
          ? { ...ride, ratingToDriver: rating } 
          : { ...ride, ratingToRider: rating };
      }
      return ride;
    }));
  }, []);

  const handleUpdateBalance = useCallback((userId: string, amount: number) => {
    setUsers(prev => prev.map(u => 
      u.id === userId ? { ...u, walletBalance: (u.walletBalance || 0) + amount } : u
    ));
  }, []);

  const handleUpdateUser = useCallback((userId: string, updates: Partial<UserProfile>) => {
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, ...updates } : u));
  }, []);

  const handleDeleteUser = useCallback((userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      walletBalance: 0,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAdminPortal(false);
  };

  const driverRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.DRIVER) return [];
    return rides.filter(r => r.status === RideStatus.REQUESTED || r.driverId === currentUser.id);
  }, [rides, currentUser]);

  const riderRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.RIDER) return [];
    return rides.filter(r => r.riderId === currentUser.id);
  }, [rides, currentUser]);

  const availableDrivers = useMemo(() => 
    users.filter(u => u.role === UserRole.DRIVER && u.isOnline), 
    [users]
  );

  const currentUserWithLatestData = useMemo(() => {
    if (!currentUser) return null;
    return users.find(u => u.id === currentUser.id) || currentUser;
  }, [users, currentUser]);

  if (!currentUserWithLatestData) {
    if (isAdminPortal) {
      return <AdminLogin onLogin={setCurrentUser} onBackToPublic={() => setIsAdminPortal(false)} />;
    }
    return <Login onLogin={setCurrentUser} onRegister={handleRegister} onGoToAdmin={() => setIsAdminPortal(true)} />;
  }

  return (
    <Layout user={currentUserWithLatestData} onLogout={handleLogout}>
      {currentUserWithLatestData.role === UserRole.ADMIN && (
        <AdminDashboard 
          users={users} 
          rides={rides} 
          paymentSettings={paymentSettings}
          onUpdateSettings={setPaymentSettings}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
        />
      )}

      {currentUserWithLatestData.role === UserRole.DRIVER && (
        <DriverDashboard 
          driver={currentUserWithLatestData} 
          rides={driverRides} 
          platformCommission={paymentSettings.platformCommission}
          onUpdateStatus={handleUpdateRideStatus}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}

      {currentUserWithLatestData.role === UserRole.RIDER && (
        <RiderDashboard 
          rider={currentUserWithLatestData} 
          rides={riderRides} 
          onRequestRide={handleRequestRide}
          onUpdateStatus={handleUpdateRideStatus}
          availableDrivers={availableDrivers}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
          onUpdateBalance={handleUpdateBalance}
          paymentSettings={paymentSettings}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { UserProfile, Ride, UserRole, RideStatus, PaymentSettings, VehicleType, PricingRule, PaymentMethod } from '../types';
import { getAdminBriefing } from '../services/geminiService';

interface AdminDashboardProps {
  users: UserProfile[];
  rides: Ride[];
  paymentSettings: PaymentSettings;
  onUpdateSettings: (settings: PaymentSettings) => void;
  onUpdateUser: (userId: string, updates: Partial<UserProfile>) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, rides, paymentSettings, onUpdateSettings, onUpdateUser, onDeleteUser }) => {
  const [aiBriefing, setAiBriefing] = useState("Analisando operações...");
  const [view, setView] = useState<'overview' | 'users' | 'rides' | 'pricing' | 'finance' | 'settings'>('overview');

  // Estados para edição
  const [newRule, setNewRule] = useState<Omit<PricingRule, 'id'>>({
    regionName: '', basePrice: 0, pricePerKm: 0, active: true
  });

  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [newPassword, setNewPassword] = useState('');

  const getUserById = (id?: string) => users.find(u => u.id === id);

  // Estatísticas de Usuários
  const userStats = useMemo(() => {
    const riders = users.filter(u => u.role === UserRole.RIDER).length;
    const drivers = users.filter(u => u.role === UserRole.DRIVER).length;
    return { riders, drivers, total: users.length };
  }, [users]);

  // Estatísticas Financeiras Agregadas por Motorista
  const driversPerformance = useMemo(() => {
    return users.filter(u => u.role === UserRole.DRIVER).map(driver => {
      const driverRides = rides.filter(r => r.driverId === driver.id && r.status === RideStatus.COMPLETED);
      const totalBruto = driverRides.reduce((acc, r) => acc + r.price, 0);
      const totalLiquido = totalBruto * (1 - paymentSettings.platformCommission / 100);
      return {
        ...driver,
        totalRides: driverRides.length,
        totalEarnings: totalLiquido
      };
    });
  }, [users, rides, paymentSettings.platformCommission]);

  // Extrato Individual de Corridas
  const detailedRideRevenue = useMemo(() => {
    return rides.filter(r => r.status === RideStatus.COMPLETED).map(ride => {
      const driver = getUserById(ride.driverId);
      const rider = getUserById(ride.riderId);
      const commission = paymentSettings.platformCommission / 100;
      const platformCut = ride.price * commission;
      const driverCut = ride.price - platformCut;

      return {
        id: ride.id,
        timestamp: ride.timestamp,
        driverName: driver?.name || 'Desconhecido',
        riderName: rider?.name || 'Desconhecido',
        total: ride.price,
        driverCut,
        platformCut
      };
    });
  }, [rides, users, paymentSettings.platformCommission]);

  const completedRides = useMemo(() => rides.filter(r => r.status === RideStatus.COMPLETED), [rides]);
  const totalRevenue = rides.reduce((acc, r) => acc + r.price, 0);
  const platformEarnings = completedRides.reduce((acc, r) => acc + (r.price * (paymentSettings.platformCommission / 100)), 0);

  useEffect(() => {
    const fetchBriefing = async () => {
      const activeRides = rides.filter(r => r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED).length;
      const briefing = await getAdminBriefing(activeRides, totalRevenue);
      setAiBriefing(briefing);
    };
    fetchBriefing();
  }, [rides, totalRevenue]);

  const handleAddPricingRule = () => {
    if (!newRule.regionName || newRule.basePrice <= 0 || newRule.pricePerKm <= 0) {
      alert("Preencha todos os campos da tarifa corretamente.");
      return;
    }
    const rule: PricingRule = { ...newRule, id: `rule-${Date.now()}` };
    onUpdateSettings({
      ...paymentSettings,
      pricingRules: [...paymentSettings.pricingRules, rule]
    });
    setNewRule({ regionName: '', basePrice: 0, pricePerKm: 0, active: true });
  };

  const handleDeleteRule = (id: string) => {
    onUpdateSettings({
      ...paymentSettings,
      pricingRules: paymentSettings.pricingRules.filter(r => r.id !== id)
    });
  };

  const handleChangePassword = (userId: string) => {
    if (!newPassword) return;
    onUpdateUser(userId, { name: users.find(u => u.id === userId)?.name }); // Simulação de atualização (a senha seria campo no objeto user)
    alert(`Senha do usuário alterada com sucesso!`);
    setEditingUserId(null);
    setNewPassword('');
  };

  const confirmDeleteUser = (userId: string) => {
    if (window.confirm("Tem certeza que deseja excluir este usuário? Esta ação não pode ser desfeita.")) {
      onDeleteUser(userId);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Portal do Administrador</h2>
          <p className="text-slate-500 font-medium">Controle de tarifas, finanças e usuários.</p>
        </div>
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto no-scrollbar">
          {[
            { id: 'overview', label: 'Geral', icon: 'fa-home' },
            { id: 'finance', label: 'Finanças', icon: 'fa-wallet' },
            { id: 'pricing', label: 'Tarifas', icon: 'fa-tags' },
            { id: 'users', label: 'Usuários', icon: 'fa-users' },
            { id: 'settings', label: 'Configurações', icon: 'fa-cog' }
          ].map(v => (
            <button 
              key={v.id}
              onClick={() => setView(v.id as any)}
              className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shrink-0 flex items-center space-x-2 ${view === v.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <i className={`fas ${v.icon}`}></i>
              <span>{v.label}</span>
            </button>
          ))}
        </div>
      </div>

      {view === 'overview' && (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
