export default RiderDashboard;

import React, { useEffect, useRef, useState } from 'react';

declare const L: any;

interface RealMapProps {
  className?: string;
  driverLocation?: { lat: number, lng: number };
  riderLocation?: { lat: number, lng: number };
  destinationLocation?: { lat: number, lng: number };
  rideStatus?: string;
}

const RealMap: React.FC<RealMapProps> = ({ 
  className, 
  driverLocation, 
  riderLocation, 
  destinationLocation,
  rideStatus 
}) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const riderMarkerRef = useRef<any>(null);
  const driverMarkerRef = useRef<any>(null);
  const destinationMarkerRef = useRef<any>(null);
  const approachLineRef = useRef<any>(null);
  const approachGlowRef = useRef<any>(null);
  const destinationLineRef = useRef<any>(null);
  const pathHistoryRef = useRef<Array<[number, number]>>([]);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    if (!mapRef.current) {
      mapRef.current = L.map(mapContainerRef.current, {
        zoomControl: false,
        attributionControl: false,
        fadeAnimation: true,
        markerZoomAnimation: true
      }).setView([-23.5505, -46.6333], 13);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19,
      }).addTo(mapRef.current);

      L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Marcador do Passageiro (Ponto de Embarque)
  useEffect(() => {
    if (!mapRef.current || !riderLocation) return;
    const pos: [number, number] = [riderLocation.lat, riderLocation.lng];

    if (!riderMarkerRef.current) {
      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div class="relative flex items-center justify-center">
            <div class="absolute w-10 h-10 bg-blue-500/20 rounded-full animate-ping"></div>
            <div class="w-6 h-6 bg-blue-600 rounded-full border-4 border-white shadow-lg flex items-center justify-center text-white text-[10px] relative z-10">
              <i class="fas fa-user"></i>
            </div>
          </div>
        `,
        iconSize: [40, 40],
        iconAnchor: [20, 20]
      });
      riderMarkerRef.current = L.marker(pos, { icon }).addTo(mapRef.current);
    } else {
      riderMarkerRef.current.setLatLng(pos);
    }
  }, [riderLocation]);

  // Marcador de Destino Final
  useEffect(() => {
    if (!mapRef.current || !destinationLocation) {
      if (destinationMarkerRef.current) {
        mapRef.current.removeLayer(destinationMarkerRef.current);
        destinationMarkerRef.current = null;
      }
      return;
    }
    const pos: [number, number] = [destinationLocation.lat, destinationLocation.lng];

    if (!destinationMarkerRef.current) {
      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div class="relative flex items-center justify-center">
            <div class="w-8 h-8 bg-indigo-950 rounded-lg border-2 border-white shadow-xl flex items-center justify-center text-white text-xs">
              <i class="fas fa-flag-checkered"></i>
            </div>
          </div>
        `,
        iconSize: [32, 32],
        iconAnchor: [16, 16]
      });
      destinationMarkerRef.current = L.marker(pos, { icon }).addTo(mapRef.current);
    } else {
      destinationMarkerRef.current.setLatLng(pos);
    }
  }, [destinationLocation]);

  // Lógica de Trajeto e Recálculo (Motorista -> Alvo)
  useEffect(() => {
    if (!mapRef.current || !driverLocation) {
      [approachLineRef, approachGlowRef, destinationLineRef, driverMarkerRef].forEach(ref => {
        if (ref.current) {
          mapRef.current.removeLayer(ref.current);
          ref.current = null;
        }
      });
      return;
    }

    const dPos: [number, number] = [driverLocation.lat, driverLocation.lng];

    // 1. Atualizar Marcador do Motorista
    if (!driverMarkerRef.current) {
      const icon = L.divIcon({
        className: 'custom-div-icon',
        html: `
          <div class="driver-marker-container">
            <div class="driver-glow"></div>
            <div class="w-10 h-10 bg-indigo-950 rounded-2xl border-2 border-white shadow-2xl flex items-center justify-center text-white text-sm relative z-20">
              <i class="fas fa-car-side"></i>
            </div>
          </div>
        `,
        iconSize: [40, 40],
        iconAnchor: [20, 20]
      });
      driverMarkerRef.current = L.marker(dPos, { icon }).addTo(mapRef.current);
    } else {
      driverMarkerRef.current.setLatLng(dPos);
    }

    // 2. Determinar o Alvo Atual (Embarque ou Destino)
    const isEnRoute = rideStatus === 'IN_PROGRESS';
    const targetLocation = isEnRoute ? destinationLocation : riderLocation;

    if (targetLocation) {
      const tPos: [number, number] = [targetLocation.lat, targetLocation.lng];
      const routePoints = [dPos, tPos];

      // Limpeza de linhas antigas se mudou de fase
      if (isEnRoute && approachLineRef.current) {
        mapRef.current.removeLayer(approachLineRef.current);
        mapRef.current.removeLayer(approachGlowRef.current);
        approachLineRef.current = null;
        approachGlowRef.current = null;
      }

      // Linha de Trajeto (Recalculada em tempo real conforme o driver se move)
      const lineRef = isEnRoute ? destinationLineRef : approachLineRef;
      const glowRef = isEnRoute ? null : approachGlowRef; // Glow apenas na aproximação para destaque
      const color = isEnRoute ? '#10b981' : '#4f46e5'; // Verde para em curso, Azul para busca

      if (!lineRef.current) {
        lineRef.current = L.polyline(routePoints, {
          color: color,
          weight: 6,
          opacity: 0.8,
          dashArray: isEnRoute ? 'none' : '10, 15',
          lineCap: 'round',
          lineJoin: 'round',
          className: isEnRoute ? 'animate-pulse' : 'animate-route-flow'
        }).addTo(mapRef.current);

        if (!isEnRoute && !approachGlowRef.current) {
          approachGlowRef.current = L.polyline(routePoints, {
            color: color,
            weight: 12,
            opacity: 0.15,
            lineJoin: 'round',
            className: 'approach-glow-line'
          }).addTo(mapRef.current);
        }
      } else {
        lineRef.current.setLatLngs(routePoints);
        if (approachGlowRef.current) approachGlowRef.current.setLatLngs(routePoints);
      }

      // Ajuste de Câmera Automático
      const bounds = L.latLngBounds([dPos, tPos]);
      mapRef.current.fitBounds(bounds, { 
        padding: [100, 100],
        animate: true,
        duration: 0.5
      });
    }
  }, [driverLocation, riderLocation, destinationLocation, rideStatus]);

  return (
    <div className={`relative overflow-hidden rounded-[2.5rem] border border-slate-200 shadow-inner ${className}`}>
      <style>{`
        @keyframes routeFlow {
          0% { stroke-dashoffset: 160; }
          100% { stroke-dashoffset: 0; }
        }
        .animate-route-flow {
          animation: routeFlow 3s linear infinite;
          filter: drop-shadow(0 0 5px rgba(79, 70, 229, 0.4));
        }
        .driver-marker-container {
          position: relative;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .driver-glow {
          position: absolute;
          width: 50px;
          height: 50px;
          background: radial-gradient(circle, rgba(79, 70, 229, 0.2) 0%, transparent 70%);
          animation: markerPulse 2s ease-out infinite;
        }
        @keyframes markerPulse {
          0% { transform: scale(0.8); opacity: 1; }
          100% { transform: scale(1.5); opacity: 0; }
        }
      `}</style>
      <div ref={mapContainerRef} className="w-full h-full" />

      {/* HUD de Navegação */}
      <div className="absolute top-4 right-4 z-[1000] flex flex-col space-y-2">
        <div className="bg-white/95 backdrop-blur-md px-4 py-2 rounded-2xl text-[9px] font-black uppercase tracking-widest text-indigo-600 border border-indigo-100 shadow-xl flex items-center">
          <i className="fas fa-location-arrow mr-2 animate-bounce"></i>
          Rota Estimada
        </div>
      </div>
    </div>
  );
};

export default RealMap;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType, PricingRule } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  onUpdateStatus: (rideId: string, status: RideStatus) => void;
  availableDrivers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, onUpdateStatus, availableDrivers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings 
}) => {
  const [view, setView] = useState<'request' | 'history' | 'wallet'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleType>(VehicleType.CAR);
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('');
  const [isProcessingDeposit, setIsProcessingDeposit] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showCancelConfirmation, setShowCancelConfirmation] = useState(false);
  const [isDriverTyping, setIsDriverTyping] = useState(false);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  useEffect(() => {
    if (activeRide?.status === RideStatus.ACCEPTED) {
      const timeout = setTimeout(() => setIsDriverTyping(true), 3000);
      const stopTimeout = setTimeout(() => setIsDriverTyping(false), 8000);
      return () => { clearTimeout(timeout); clearTimeout(stopTimeout); };
    }
    setIsDriverTyping(false);
  }, [activeRide?.status]);

  const pricingData = useMemo(() => {
    const rules = paymentSettings.pricingRules;
    const destLower = destination.toLowerCase();

    let activeRule = rules.find(r => destLower.includes(r.regionName.toLowerCase())) || rules.find(r => r.id === 'default');
    if (!activeRule) activeRule = { id: 'fallback', regionName: 'Padrão', basePrice: 5, pricePerKm: 2, active: true };

    const estimatedDistKm = 4.8;
    const calculateForService = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
      const multipliers = { UberX: 1.0, UberComfort: 1.3, UberBlack: 1.8 };
      const vehicleMult = selectedVehicle === VehicleType.MOTORCYCLE ? 0.65 : 1.0;
      const price = (activeRule!.basePrice + (activeRule!.pricePerKm * estimatedDistKm)) * multipliers[service] * vehicleMult;
      return price;
    };

    return {
      ruleName: activeRule.regionName,
      prices: { UberX: calculateForService('UberX'), UberComfort: calculateForService('UberComfort'), UberBlack: calculateForService('UberBlack') }
    };
  }, [destination, selectedVehicle, paymentSettings.pricingRules]);

  const currentPrice = pricingData.prices[selectedService];

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude }),
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  // Simulação de Movimento Dinâmico do Motorista com Recálculo de Rota
  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          // Determina o destino atual do motorista baseado no status da corrida
          // Se ACCEPTED ou PICKUP -> Vai até o passageiro
          // Se IN_PROGRESS -> Vai até o destino final
          const isEnRoute = activeRide.status === RideStatus.IN_PROGRESS;
          const target = isEnRoute ? activeRide.destination : { lat: userPos.lat, lng: userPos.lng };

          if (!prev) return { lat: target.lat + 0.005, lng: target.lng + 0.005 };

          const step = 0.00015; // Velocidade da simulação
          const dLat = target.lat - prev.lat;
          const dLng = target.lng - prev.lng;

          // Se já chegou no passageiro, aguarda o status mudar
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) {
             // Caso tenha chegado no embarque e ainda não iniciou, simula a espera
             if (activeRide.status === RideStatus.ACCEPTED) {
               // Em um sistema real, o motorista confirmaria o embarque
               // Aqui apenas mantemos a posição
               return prev;
             }
             return prev;
          }

          return { 
            lat: prev.lat + (dLat > 0 ? step : -step), 
            lng: prev.lng + (dLng > 0 ? step : -step) 
          };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
  }, [activeRide?.status, activeRide?.destination, userPos]);

  const handleConfirmRide = () => {
    if (!destination || !userPos) return;
    if (selectedPayment === PaymentMethod.PREPAID && (rider.walletBalance || 0) < currentPrice) {
      alert("Saldo insuficiente na carteira. Por favor, recarregue.");
      setView('wallet');
      return;
    }
    onRequestRide({
      riderId: rider.id,
      origin: { lat: userPos.lat, lng: userPos.lng, address: origin },
      destination: { lat: userPos.lat + 0.015, lng: userPos.lng + 0.015, address: destination },
      price: currentPrice,
      paymentMethod: selectedPayment,
      vehicleTypeRequested: selectedVehicle,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(topUpAmount);
    if (isNaN(amount) || amount <= 0) {
      alert("Insira um valor válido para depósito.");
      return;
    }

    if (!paymentSettings.apiKey) {
      alert("O sistema de pagamentos não está configurado. Entre em contato com o administrador.");
      return;
    }

    setIsProcessingDeposit(true);
    setTimeout(() => {
      onUpdateBalance(rider.id, amount);
      setIsProcessingDeposit(false);
      setIsAddingFunds(false);
      setTopUpAmount('');
      alert(`Depósito de R$ ${amount.toFixed(2)} realizado com sucesso via ${paymentSettings.provider}!`);
    }, 2000);
  };

  const handleCancelRide = () => {
    if (activeRide) {
      onUpdateStatus(activeRide.id, RideStatus.CANCELLED);
      setShowCancelConfirmation(false);
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista Parceiro',
      avatar: 'https://picsum.photos/seed/unknown/200',
      vehicleModel: 'Veículo Padrão',
      licensePlate: 'BRA-2025',
      vehicleType: selectedVehicle
    };
  };

  const paymentOptions = [
    { id: PaymentMethod.CARD, label: 'Cartão', icon: 'fa-credit-card', color: 'text-blue-600' },
    { id: PaymentMethod.PIX, label: 'Pix', icon: 'fa-qrcode', color: 'text-teal-500' },
    { id: PaymentMethod.PREPAID, label: `Carteira`, icon: 'fa-wallet', color: 'text-indigo-600' },
    { id: PaymentMethod.CASH, label: 'Dinheiro', icon: 'fa-money-bill-wave', color: 'text-green-600' },
  ];

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {/* Modal de Recarga */}
      {isAddingFunds && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-slate-100">
            <div className="p-8 bg-indigo-950 text-white text-center">
              <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mx-auto mb-4">
                <i className="fas fa-wallet text-2xl"></i>
              </div>
              <h3 className="text-xl font-black uppercase tracking-tight">Adicionar Saldo</h3>
              <p className="text-indigo-300 text-[10px] font-bold uppercase tracking-widest mt-1">Gateway: {paymentSettings.provider}</p>
            </div>
            <form onSubmit={handleDeposit} className="p-8 space-y-6">
              {!paymentSettings.apiKey ? (
                <div className="bg-red-50 p-4 rounded-2xl border border-red-100 text-center">
                  <i className="fas fa-exclamation-circle text-red-500 mb-2"></i>
                  <p className="text-[10px] font-black text-red-600 uppercase leading-tight">Pagamentos temporariamente indisponíveis.</p>
                </div>
              ) : (
                <>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2 ml-1">Valor do Depósito (R$)</label>
                    <div className="relative">
                      <span className="absolute left-6 top-1/2 -translate-y-1/2 font-black text-slate-400 text-lg">R$</span>
                      <input 
                        autoFocus required type="number" step="0.01" min="1"
                        value={topUpAmount} onChange={e => setTopUpAmount(e.target.value)}
                        placeholder="0,00"
                        className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl focus:border-indigo-600 outline-none transition-all font-black text-2xl"
                      />
                    </div>
                  </div>
                  <button type="submit" disabled={isProcessingDeposit} className={`w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl transition-all ${isProcessingDeposit ? 'bg-slate-200 text-slate-400' : 'bg-indigo-950 text-white hover:bg-indigo-900'}`}>
                    {isProcessingDeposit ? <i className="fas fa-circle-notch fa-spin mr-3"></i> : 'Confirmar Depósito'}
                  </button>
                  <button type="button" onClick={() => setIsAddingFunds(false)} className="w-full text-slate-400 font-black text-[10px] uppercase py-2">Cancelar</button>
                </>
              )}
            </form>
          </div>
        </div>
      )}

      {/* Confirmação de Cancelamento */}
      {showCancelConfirmation && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up border border-slate-100">
            <div className="p-10 text-center">
              <div className="w-20 h-20 bg-red-50 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-6 text-3xl shadow-inner"><i className="fas fa-exclamation-triangle"></i></div>
              <h3 className="text-2xl font-black text-indigo-950 tracking-tight">Cancelar Corrida?</h3>
              <p className="text-slate-500 font-medium mt-3">Tem certeza que deseja cancelar esta viagem?</p>
              <div className="mt-10 space-y-3">
                <button onClick={handleCancelRide} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-red-700 shadow-xl">SIM, CANCELAR</button>
                <button onClick={() => setShowCancelConfirmation(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-black text-[10px] uppercase">MANTER VIAGEM</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id} messages={activeRide.messages || []} currentUserId={rider.id}
          onSendMessage={onSendMessage} otherPartyName={findDriverInfo(activeRide.driverId).name}
          isOpen={isChatOpen} onToggle={setIsChatOpen} isOtherTyping={isDriverTyping}
        />
      )}

      {!activeRide && (
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
            <button onClick={() => setView('request')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'request' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Pedir</button>
            <button onClick={() => setView('history')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Histórico</button>
            <button onClick={() => setView('wallet')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${view === 'wallet' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Carteira</button>
          </div>
          {view === 'request' && (
            <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 w-fit">
              <button onClick={() => setSelectedVehicle(VehicleType.CAR)} className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.CAR ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
                <i className="fas fa-car text-xs"></i><span className="text-[10px] font-black uppercase">Carro</span>
              </button>
              <button onClick={() => setSelectedVehicle(VehicleType.MOTORCYCLE)} className={`flex items-center space-x-2 px-6 py-2 rounded-xl transition-all ${selectedVehicle === VehicleType.MOTORCYCLE ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
                <i className="fas fa-motorcycle text-xs"></i><span className="text-[10px] font-black uppercase">Moto</span>
              </button>
            </div>
          )}
        </div>
      )}

      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 relative">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-indigo-950 tracking-tight">Viagem Ativa</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{activeRide.status}</p>
              </div>
              <div className="text-right">
                <span className="block text-[9px] font-black text-slate-400 uppercase">Total</span>
                <span className="text-2xl font-black text-indigo-950">R$ {activeRide.price.toFixed(2)}</span>
              </div>
           </div>

           <div className="h-[500px] w-full p-2 bg-slate-50 relative">
              <RealMap 
                className="h-full w-full" 
                riderLocation={userPos} 
                driverLocation={driverPos}
                destinationLocation={activeRide.destination}
                rideStatus={activeRide.status}
              />
              <div className="absolute top-4 left-4 z-[1000] flex flex-col space-y-3 pointer-events-none">
                <div className="bg-white/95 backdrop-blur shadow-2xl rounded-[2rem] p-5 border border-slate-200 pointer-events-auto animate-slide-up max-w-[220px]">
                  <div className="flex items-center space-x-3 mb-4">
                    <img src={findDriverInfo(activeRide.driverId).avatar} className="w-12 h-12 rounded-2xl border-2 border-slate-100 shadow-sm object-cover" />
                    <div>
                      <p className="text-[10px] font-black text-indigo-950 uppercase tracking-tight truncate">{findDriverInfo(activeRide.driverId).name}</p>
                      <div className="flex items-center text-[8px] font-bold text-slate-400 uppercase mt-0.5">
                        <i className="fas fa-star text-amber-400 mr-1"></i> 4.9 • {findDriverInfo(activeRide.driverId).licensePlate}
                      </div>
                    </div>
                  </div>
                  {activeRide.status !== RideStatus.IN_PROGRESS && (
                    <button onClick={() => setShowCancelConfirmation(true)} className="w-full bg-white text-red-500 border border-red-100 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-50">Cancelar Corrida</button>
                  )}
                </div>
              </div>
           </div>
        </div>
      ) : view === 'request' ? (
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
          <h2 className="text-4xl font-black mb-10 text-indigo-950 tracking-tighter">Para onde vamos hoje?</h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rounded-full"></div><input disabled value={userPos ? "Sua Localização GPS" : "Obtendo GPS..."} className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-500 font-bold text-lg" /></div>
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-indigo-600 rounded-full"></div><input autoFocus placeholder="Inserir destino (Ex: Centro)" value={destination} onChange={e => setDestination(e.target.value)} className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none transition-all" /></div>
              {destination && (
                <div className="space-y-6 pt-4 animate-slide-up">
                  <div className="bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black text-indigo-600 uppercase flex items-center"><i className="fas fa-tag mr-2"></i> Tarifa: {pricingData.ruleName}</div>
                  <div className="grid gap-3">{(['UberX', 'UberComfort', 'UberBlack'] as const).map(service => (
                      <button key={service} onClick={() => setSelectedService(service)} className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-indigo-950 bg-indigo-50 shadow-md' : 'border-slate-100'}`}>
                        <div className="flex items-center space-x-3 font-black text-lg text-slate-600"><span className={selectedService === service ? 'text-indigo-950' : ''}>{service}</span></div>
                        <span className={`font-black text-xl ${selectedService === service ? 'text-indigo-950' : 'text-slate-600'}`}>R$ {pricingData.prices[service].toFixed(2)}</span>
                      </button>
                    ))}</div>
                  <div className="grid grid-cols-2 gap-3">{paymentOptions.map(opt => (<button key={opt.id} onClick={() => setSelectedPayment(opt.id)} className={`flex items-center space-x-3 p-4 rounded-xl border-2 transition-all ${selectedPayment === opt.id ? 'border-indigo-950 bg-indigo-50' : 'border-slate-100'}`}><i className={`fas ${opt.icon} ${opt.color}`}></i><span className={`text-[10px] font-black uppercase tracking-tight ${selectedPayment === opt.id ? 'text-indigo-950' : 'text-slate-400'}`}>{opt.label}</span></button>))}</div>
                  <button onClick={handleConfirmRide} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl hover:bg-indigo-900 transition-all shadow-2xl mt-4 active:scale-95 text-center">SOLICITAR AGORA</button>
                </div>
              )}
            </div>
            <div className="hidden md:block h-full min-h-[400px]"><RealMap className="h-full w-full" riderLocation={userPos} /></div>
          </div>
        </div>
      ) : view === 'history' ? (
        <div className="space-y-4">
          <h2 className="text-3xl font-black text-indigo-950 px-2 tracking-tighter">Minhas Viagens</h2>
          <div className="grid gap-4">{completedRides.map(ride => (
              <div key={ride.id} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm flex justify-between items-center">
                <div className="flex items-center space-x-4"><div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-900"><i className="fas fa-history"></i></div><div><h4 className="font-black text-indigo-950">Viagem em {new Date(ride.timestamp).toLocaleDateString()}</h4><p className="text-[10px] font-bold text-slate-400 uppercase">{ride.destination.address}</p></div></div>
                <div className="text-right"><p className="text-xl font-black text-indigo-950">R$ {ride.price.toFixed(2)}</p></div>
              </div>
            ))}</div>
        </div>
      ) : (
        <div className="space-y-6 animate-fade-in">
           <div className="bg-indigo-950 p-10 rounded-[2.5rem] text-white flex flex-col md:flex-row justify-between items-center shadow-2xl border border-white/10 relative overflow-hidden">
