import React, { useState, useCallback, useMemo } from 'react';
import { UserRole, UserProfile, Ride, RideStatus, PaymentMethod, PaymentSettings, ChatMessage, PricingRule, VehicleType } from './types';
import Login from './pages/Login';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';
import Layout from './components/Layout';

const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true, vehicleType: VehicleType.CAR },
];

const DEFAULT_PRICING: PricingRule[] = [
  { id: 'default', regionName: 'Geral (Padrão)', basePrice: 5.00, pricePerKm: 2.50, active: true },
  { id: 'center', regionName: 'Centro Histórico', basePrice: 8.00, pricePerKm: 3.50, active: true },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isAdminPortal, setIsAdminPortal] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>(() => {
    return [...MOCK_DRIVERS, { id: 'r1', name: 'João Paulo', email: 'joao@user.com', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200', walletBalance: 150.00 }];
  });
  const [rides, setRides] = useState<Ride[]>([]);
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    apiKey: '', 
    provider: 'Stripe',
    platformCommission: 15,
    pricingRules: DEFAULT_PRICING
  });

  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
      messages: []
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleSendMessage = useCallback((rideId: string, text: string) => {
    if (!currentUser) return;
    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      senderId: currentUser.id,
      text,
      timestamp: new Date().toISOString()
    };
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, messages: [...(ride.messages || []), newMessage] } : ride
    ));
  }, [currentUser]);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prevRides => {
      const rideIndex = prevRides.findIndex(r => r.id === rideId);
      if (rideIndex === -1) return prevRides;

      const updatedRides = [...prevRides];
      const targetRide = { 
        ...updatedRides[rideIndex], 
        status: newStatus, 
        driverId: driverId || updatedRides[rideIndex].driverId 
      };
      updatedRides[rideIndex] = targetRide;

      if (newStatus === RideStatus.COMPLETED) {
        const commission = paymentSettings.platformCommission / 100;
        const totalAmount = targetRide.price;
        const driverShare = totalAmount * (1 - commission);

        setUsers(prevUsers => prevUsers.map(user => {
          if (user.id === targetRide.driverId) {
            return { ...user, earnings: (user.earnings || 0) + driverShare };
          }
          if (user.id === targetRide.riderId && targetRide.paymentMethod === PaymentMethod.PREPAID) {
            const currentBalance = user.walletBalance || 0;
            return { ...user, walletBalance: currentBalance - totalAmount };
          }
          return user;
        }));
      }

      return updatedRides;
    });
  }, [paymentSettings.platformCommission]);

  const handleRateRide = useCallback((rideId: string, rating: number, role: UserRole) => {
    setRides(prev => prev.map(ride => {
      if (ride.id === rideId) {
        return role === UserRole.RIDER 
          ? { ...ride, ratingToDriver: rating } 
          : { ...ride, ratingToRider: rating };
      }
      return ride;
    }));
  }, []);

  const handleUpdateBalance = useCallback((userId: string, amount: number) => {
    setUsers(prev => prev.map(u => 
      u.id === userId ? { ...u, walletBalance: (u.walletBalance || 0) + amount } : u
    ));
  }, []);

  const handleUpdateUser = useCallback((userId: string, updates: Partial<UserProfile>) => {
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, ...updates } : u));
  }, []);

  const handleDeleteUser = useCallback((userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      walletBalance: 0,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAdminPortal(false);
  };

  const driverRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.DRIVER) return [];
    return rides.filter(r => r.status === RideStatus.REQUESTED || r.driverId === currentUser.id);
  }, [rides, currentUser]);

  const riderRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.RIDER) return [];
    return rides.filter(r => r.riderId === currentUser.id);
  }, [rides, currentUser]);

  const availableDrivers = useMemo(() => 
    users.filter(u => u.role === UserRole.DRIVER && u.isOnline), 
    [users]
  );

  const currentUserWithLatestData = useMemo(() => {
    if (!currentUser) return null;
    return users.find(u => u.id === currentUser.id) || currentUser;
  }, [users, currentUser]);

  if (!currentUserWithLatestData) {
    if (isAdminPortal) {
      return <AdminLogin onLogin={setCurrentUser} onBackToPublic={() => setIsAdminPortal(false)} />;
    }
    return <Login onLogin={setCurrentUser} onRegister={handleRegister} onGoToAdmin={() => setIsAdminPortal(true)} />;
  }

  return (
    <Layout user={currentUserWithLatestData} onLogout={handleLogout}>
      {currentUserWithLatestData.role === UserRole.ADMIN && (
        <AdminDashboard 
          users={users} 
          rides={rides} 
          paymentSettings={paymentSettings}
          onUpdateSettings={setPaymentSettings}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
        />
      )}

      {currentUserWithLatestData.role === UserRole.DRIVER && (
        <DriverDashboard 
          driver={currentUserWithLatestData} 
          rides={driverRides} 
          platformCommission={paymentSettings.platformCommission}
          onUpdateStatus={handleUpdateRideStatus}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}

      {currentUserWithLatestData.role === UserRole.RIDER && (
        <RiderDashboard 
          rider={currentUserWithLatestData} 
          rides={riderRides} 
          onRequestRide={handleRequestRide}
          onUpdateStatus={handleUpdateRideStatus}
          availableDrivers={availableDrivers}
          allUsers={users}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
          onUpdateBalance={handleUpdateBalance}
          paymentSettings={paymentSettings}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType, PricingRule } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  onUpdateStatus: (rideId: string, status: RideStatus) => void;
  availableDrivers: UserProfile[];
  allUsers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, onUpdateStatus, availableDrivers, allUsers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings 
}) => {
  const [view, setView] = useState<'request' | 'history' | 'wallet'>('request');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleType>(VehicleType.CAR);
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('');
  const [isProcessingDeposit, setIsProcessingDeposit] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showCancelConfirmation, setShowCancelConfirmation] = useState(false);
  const [isDriverTyping, setIsDriverTyping] = useState(false);
  const [selectedRideForReceipt, setSelectedRideForReceipt] = useState<Ride | null>(null);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  useEffect(() => {
    if (activeRide?.status === RideStatus.ACCEPTED) {
      const timeout = setTimeout(() => setIsDriverTyping(true), 3000);
      const stopTimeout = setTimeout(() => setIsDriverTyping(false), 8000);
      return () => { clearTimeout(timeout); clearTimeout(stopTimeout); };
    }
    setIsDriverTyping(false);
  }, [activeRide?.status]);

  const pricingData = useMemo(() => {
    const rules = paymentSettings.pricingRules;
    const destLower = destination.toLowerCase();

    let activeRule = rules.find(r => destLower.includes(r.regionName.toLowerCase())) || rules.find(r => r.id === 'default');
    if (!activeRule) activeRule = { id: 'fallback', regionName: 'Padrão', basePrice: 5, pricePerKm: 2, active: true };

    const estimatedDistKm = 4.8;
    const calculateForService = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
      const multipliers = { UberX: 1.0, UberComfort: 1.3, UberBlack: 1.8 };
      const vehicleMult = selectedVehicle === VehicleType.MOTORCYCLE ? 0.65 : 1.0;
      const price = (activeRule!.basePrice + (activeRule!.pricePerKm * estimatedDistKm)) * multipliers[service] * vehicleMult;
      return price;
    };

    return {
      ruleName: activeRule.regionName,
      prices: { UberX: calculateForService('UberX'), UberComfort: calculateForService('UberComfort'), UberBlack: calculateForService('UberBlack') }
    };
  }, [destination, selectedVehicle, paymentSettings.pricingRules]);

  const currentPrice = pricingData.prices[selectedService];

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude }),
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const isEnRoute = activeRide.status === RideStatus.IN_PROGRESS;
          const target = isEnRoute ? activeRide.destination : { lat: userPos.lat, lng: userPos.lng };

          if (!prev) return { lat: target.lat + 0.005, lng: target.lng + 0.005 };

          const step = 0.00015;
          const dLat = target.lat - prev.lat;
          const dLng = target.lng - prev.lng;

          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;

          return { 
            lat: prev.lat + (dLat > 0 ? step : -step), 
            lng: prev.lng + (dLng > 0 ? step : -step) 
          };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
