export default Layout;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType, PricingRule } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { getRideInsight } from '../services/geminiService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  onUpdateStatus: (rideId: string, status: RideStatus) => void;
  availableDrivers: UserProfile[];
  allUsers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
  externalActiveTab?: string;
  onTabChange?: (tab: string) => void;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, onUpdateStatus, availableDrivers, allUsers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings,
  externalActiveTab, onTabChange
}) => {
  const [internalView, setInternalView] = useState<'home' | 'history' | 'wallet'>('home');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleType>(VehicleType.CAR);
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('');
  const [isProcessingDeposit, setIsProcessingDeposit] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showCancelConfirmation, setShowCancelConfirmation] = useState(false);
  const [isDriverTyping, setIsDriverTyping] = useState(false);
  const [selectedRideForReceipt, setSelectedRideForReceipt] = useState<Ride | null>(null);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  // Sincronizar visão interna com tab externa
  const currentView = (externalActiveTab === 'history' || externalActiveTab === 'wallet' || externalActiveTab === 'home') 
    ? externalActiveTab 
    : internalView;

  const setView = (v: 'home' | 'history' | 'wallet') => {
    if (onTabChange) onTabChange(v);
    else setInternalView(v);
  };

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  useEffect(() => {
    if (activeRide?.status === RideStatus.ACCEPTED) {
      const timeout = setTimeout(() => setIsDriverTyping(true), 3000);
      const stopTimeout = setTimeout(() => setIsDriverTyping(false), 8000);
      return () => { clearTimeout(timeout); clearTimeout(stopTimeout); };
    }
    setIsDriverTyping(false);
  }, [activeRide?.status]);

  const pricingData = useMemo(() => {
    const rules = paymentSettings.pricingRules;
    const destLower = destination.toLowerCase();

    let activeRule = rules.find(r => destLower.includes(r.regionName.toLowerCase())) || rules.find(r => r.id === 'default');
    if (!activeRule) activeRule = { id: 'fallback', regionName: 'Padrão', basePrice: 5, pricePerKm: 2, active: true };

    const estimatedDistKm = 4.8;
    const calculateForService = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
      const multipliers = { UberX: 1.0, UberComfort: 1.3, UberBlack: 1.8 };
      const vehicleMult = selectedVehicle === VehicleType.MOTORCYCLE ? 0.65 : 1.0;
      return (activeRule!.basePrice + (activeRule!.pricePerKm * estimatedDistKm)) * multipliers[service] * vehicleMult;
    };

    return {
      ruleName: activeRule.regionName,
      prices: { UberX: calculateForService('UberX'), UberComfort: calculateForService('UberComfort'), UberBlack: calculateForService('UberBlack') }
    };
  }, [destination, selectedVehicle, paymentSettings.pricingRules]);

  const currentPrice = pricingData.prices[selectedService];

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude }),
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  useEffect(() => {
    if (activeRide && activeRide.status !== RideStatus.REQUESTED && userPos) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const isEnRoute = activeRide.status === RideStatus.IN_PROGRESS;
          const target = isEnRoute ? activeRide.destination : { lat: userPos.lat, lng: userPos.lng };
          if (!prev) return { lat: target.lat + 0.005, lng: target.lng + 0.005 };
          const step = 0.00015;
          const dLat = target.lat - prev.lat;
          const dLng = target.lng - prev.lng;
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;
          return { lat: prev.lat + (dLat > 0 ? step : -step), lng: prev.lng + (dLng > 0 ? step : -step) };
        });
      }, 1000);
      return () => clearInterval(interval);
    } else {
      setDriverPos(undefined);
    }
  }, [activeRide?.status, activeRide?.destination, userPos]);

  const handleConfirmRide = () => {
    if (!destination || !userPos) return;
    if (selectedPayment === PaymentMethod.PREPAID && (rider.walletBalance || 0) < currentPrice) {
      alert("Saldo insuficiente na carteira.");
      setView('wallet');
      return;
    }
    onRequestRide({
      riderId: rider.id,
      origin: { lat: userPos.lat, lng: userPos.lng, address: origin },
      destination: { lat: userPos.lat + 0.015, lng: userPos.lng + 0.015, address: destination },
      price: currentPrice,
      paymentMethod: selectedPayment,
      vehicleTypeRequested: selectedVehicle,
      distance: '4.8 km'
    });
    setDestination('');
  };

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(topUpAmount);
    if (isNaN(amount) || amount <= 0 || !paymentSettings.apiKey) return;
    setIsProcessingDeposit(true);
    setTimeout(() => {
      onUpdateBalance(rider.id, amount);
      setIsProcessingDeposit(false);
      setIsAddingFunds(false);
      setTopUpAmount('');
    }, 2000);
  };

  const handleCancelRide = () => {
    if (activeRide) {
      onUpdateStatus(activeRide.id, RideStatus.CANCELLED);
      setShowCancelConfirmation(false);
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return allUsers.find(d => d.id === driverId) || availableDrivers.find(d => d.id === driverId) || {
      name: 'Motorista',
      licensePlate: 'ABC-1234',
      avatar: 'https://picsum.photos/seed/driver/200'
    };
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {/* Recibo Modal */}
      {selectedRideForReceipt && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl p-8 animate-scale-up">
            <h3 className="text-xl font-black text-center mb-6 uppercase">Recibo Duarte</h3>
            <div className="space-y-4 mb-8">
              <div className="flex justify-between"><span className="text-xs font-bold text-slate-400">Total</span><span className="font-black">R$ {selectedRideForReceipt.price.toFixed(2)}</span></div>
              <div className="flex justify-between"><span className="text-xs font-bold text-slate-400">Data</span><span className="font-bold">{new Date(selectedRideForReceipt.timestamp).toLocaleDateString()}</span></div>
              <div className="flex justify-between"><span className="text-xs font-bold text-slate-400">Motorista</span><span className="font-bold">{findDriverInfo(selectedRideForReceipt.driverId).name}</span></div>
            </div>
            <button onClick={() => setSelectedRideForReceipt(null)} className="w-full bg-indigo-950 text-white py-4 rounded-xl font-black">FECHAR</button>
          </div>
        </div>
      )}

      {/* Recarga Modal */}
      {isAddingFunds && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 animate-scale-up">
             <h3 className="text-xl font-black mb-6 uppercase">Adicionar Saldo</h3>
             <form onSubmit={handleDeposit} className="space-y-4">
               <input required type="number" step="0.01" value={topUpAmount} onChange={e => setTopUpAmount(e.target.value)} placeholder="R$ 0,00" className="w-full px-6 py-5 bg-slate-50 rounded-2xl font-black text-2xl focus:border-indigo-600 outline-none" />
               <button type="submit" disabled={isProcessingDeposit} className="w-full py-5 bg-indigo-950 text-white rounded-2xl font-black">{isProcessingDeposit ? '...' : 'CONFIRMAR'}</button>
               <button type="button" onClick={() => setIsAddingFunds(false)} className="w-full text-slate-400 font-bold text-[10px] uppercase">CANCELAR</button>
             </form>
          </div>
        </div>
      )}

      {/* Cancelamento Modal */}
      {showCancelConfirmation && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 text-center animate-scale-up">
            <h3 className="text-2xl font-black text-indigo-950 mb-8">Cancelar Corrida?</h3>
            <div className="space-y-3">
              <button onClick={handleCancelRide} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black">SIM, CANCELAR</button>
              <button onClick={() => setShowCancelConfirmation(false)} className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-black">VOLTAR</button>
            </div>
          </div>
        </div>
      )}

      {/* Chat Widget para Passageiro */}
      {activeRide && activeRide.status !== RideStatus.REQUESTED && (
        <ChatWidget 
          rideId={activeRide.id} messages={activeRide.messages || []} currentUserId={rider.id}
          onSendMessage={onSendMessage} otherPartyName={findDriverInfo(activeRide.driverId).name}
          isOpen={isChatOpen} onToggle={setIsChatOpen} isOtherTyping={isDriverTyping}
        />
      )}

      {/* Navegação Interna do Dashboard (Sempre visível se não estiver em corrida ativa) */}
      {!activeRide && (
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200">
            <button onClick={() => setView('home')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${currentView === 'home' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Pedir</button>
            <button onClick={() => setView('history')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${currentView === 'history' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Histórico</button>
            <button onClick={() => setView('wallet')} className={`px-6 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${currentView === 'wallet' ? 'bg-indigo-950 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>Carteira</button>
          </div>
        </div>
      )}

      {/* View de Corrida Ativa (Prioritária) */}
      {activeRide ? (
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 relative animate-slide-up">
           <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div><h3 className="text-2xl font-black text-indigo-950">Viagem Ativa</h3><p className="text-xs font-bold text-slate-400 uppercase">{activeRide.status}</p></div>
              <div className="text-right"><span className="block text-[9px] font-black text-slate-400">Total</span><span className="text-2xl font-black">R$ {activeRide.price.toFixed(2)}</span></div>
           </div>
           <div className="h-[500px] w-full p-2 bg-slate-50 relative">
              <RealMap 
                className="h-full w-full" 
                riderLocation={userPos} 
                driverLocation={driverPos} 
                destinationLocation={activeRide.destination} 
                rideStatus={activeRide.status}
                driverInfo={{ name: findDriverInfo(activeRide.driverId).name, plate: findDriverInfo(activeRide.driverId).licensePlate }}
                riderInfo={{ name: rider.name }}
              />
              <div className="absolute top-4 left-4 z-[1000] flex flex-col space-y-3 pointer-events-none">
                <div className="bg-white/95 backdrop-blur shadow-2xl rounded-[2rem] p-5 border border-slate-200 pointer-events-auto max-w-[220px]">
                  <div className="flex items-center space-x-3 mb-4">
                    <img src={findDriverInfo(activeRide.driverId).avatar} className="w-12 h-12 rounded-2xl object-cover" />
                    <div>
                      <p className="text-[10px] font-black text-indigo-950 truncate">{findDriverInfo(activeRide.driverId).name}</p>
                      <p className="text-[8px] font-bold text-slate-400 uppercase">{findDriverInfo(activeRide.driverId).licensePlate}</p>
                    </div>
                  </div>
                  {/* Botão de Chat visível diretamente no HUD */}
                  <button onClick={() => setIsChatOpen(true)} className="w-full bg-indigo-950 text-white py-3 rounded-xl text-[9px] font-black uppercase mb-2 flex items-center justify-center">
                    <i className="fas fa-comments mr-2"></i> ABRIR CHAT
                  </button>
                  {activeRide.status !== RideStatus.IN_PROGRESS && <button onClick={() => setShowCancelConfirmation(true)} className="w-full bg-white text-red-500 border border-red-100 py-3 rounded-xl text-[9px] font-black uppercase">CANCELAR CORRIDA</button>}
                </div>
              </div>
           </div>
        </div>
      ) : currentView === 'home' ? (
        <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl border border-slate-200">
          <h2 className="text-4xl font-black mb-10 text-indigo-950 tracking-tighter">Para onde vamos hoje?</h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-blue-500 rounded-full"></div><input disabled value={userPos ? "Sua Localização GPS" : "Obtendo GPS..."} className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-500 font-bold" /></div>
              <div className="relative"><div className="absolute left-6 top-1/2 -translate-y-1/2 w-2 h-2 bg-indigo-600 rounded-full"></div><input autoFocus placeholder="Destino" value={destination} onChange={e => setDestination(e.target.value)} className="w-full pl-12 pr-4 py-5 bg-white border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none" /></div>
              {destination && (
                <div className="space-y-4 pt-4 animate-slide-up">
                  <div className="grid gap-2">{(['UberX', 'UberComfort'] as const).map(service => (
                    <button key={service} onClick={() => setSelectedService(service as any)} className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all ${selectedService === service ? 'border-indigo-950 bg-indigo-50' : 'border-slate-100'}`}>
                      <span className="font-black">{service}</span>
                      <span className="font-black text-xl">R$ {pricingData.prices[service as 'UberX'].toFixed(2)}</span>
                    </button>
                  ))}</div>
                  <button onClick={handleConfirmRide} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl shadow-2xl mt-4">SOLICITAR AGORA</button>
                </div>
              )}
            </div>
            <div className="hidden md:block h-full min-h-[400px]"><RealMap className="h-full w-full" riderLocation={userPos} /></div>
          </div>
        </div>
      ) : currentView === 'history' ? (
        <div className="space-y-4 animate-slide-up">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-3xl font-black text-indigo-950 tracking-tighter">Histórico de Viagens</h2>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{completedRides.length} viagens</span>
          </div>

          <div className="grid gap-4">
            {completedRides.length === 0 ? (
              <div className="bg-white p-20 rounded-[2.5rem] border border-slate-200 text-center">
                <i className="fas fa-history text-slate-200 text-5xl mb-4"></i>
                <p className="text-slate-400 font-bold uppercase text-xs">Nenhuma viagem registrada ainda.</p>
              </div>
            ) : (
              completedRides.map(ride => (
                <div key={ride.id} onClick={() => setSelectedRideForReceipt(ride)} className="bg-white p-6 rounded-[2rem] border border-slate-200 flex flex-col md:flex-row justify-between items-center cursor-pointer hover:border-indigo-600 hover:shadow-lg transition-all group">
                  <div className="flex items-center space-x-4 w-full md:w-auto">
                    <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-900 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                      <i className="fas fa-map-marker-alt"></i>
                    </div>
                    <div>
                      <h4 className="font-black text-sm text-indigo-950">{ride.destination.address}</h4>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(ride.timestamp).toLocaleDateString('pt-BR')} às {new Date(ride.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                    </div>
                  </div>
                  <div className="flex items-center justify-between md:justify-end w-full md:w-auto mt-4 md:mt-0 space-x-6">
                    <div className="text-right">
                      <p className="text-xl font-black text-indigo-950">R$ {ride.price.toFixed(2)}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{ride.paymentMethod}</p>
                    </div>
                    <div className="bg-slate-50 w-8 h-8 rounded-full flex items-center justify-center text-slate-300 group-hover:text-indigo-600 transition-colors">
                      <i className="fas fa-chevron-right text-xs"></i>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      ) : (
        <div className="space-y-6 animate-slide-up">
          <div className="bg-indigo-950 p-10 rounded-[2.5rem] text-white flex justify-between items-center shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
              <p className="text-indigo-300 font-black uppercase text-[10px] mb-1 tracking-widest">Saldo Duarte Pay</p>
              <h2 className="text-6xl font-black">R$ {rider.walletBalance?.toFixed(2) || '0,00'}</h2>
            </div>
            <button onClick={() => setIsAddingFunds(true)} className="bg-white text-indigo-950 px-10 py-5 rounded-2xl font-black uppercase shadow-xl hover:bg-indigo-50 transition-all active:scale-95 z-10">Recarregar</button>
            <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-32 -mt-32"></div>
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200">
            <h4 className="font-black text-indigo-950 text-xs uppercase tracking-widest mb-6">Métodos de Pagamento</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="p-6 rounded-2xl border border-slate-100 flex items-center space-x-4">
                <i className="fas fa-credit-card text-blue-600 text-xl"></i>
                <div>
                  <p className="font-black text-sm">Cartão de Crédito</p>
                  <p className="text-[10px] font-bold text-slate-400">Final 4432 • Exp 12/28</p>
                </div>
              </div>
              <div className="p-6 rounded-2xl border border-indigo-600 bg-indigo-50 flex items-center space-x-4">
                <i className="fas fa-wallet text-indigo-600 text-xl"></i>
                <div>
                  <p className="font-black text-sm">Carteira Duarte</p>
                  <p className="text-[10px] font-bold text-indigo-400 uppercase">Padrão para uso</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RiderDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, VehicleType, PaymentMethod } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

interface DriverDashboardProps {
  driver: UserProfile;
  rides: Ride[];
  allUsers: UserProfile[];
  platformCommission: number;
  onUpdateStatus: (rideId: string, status: RideStatus, driverId: string) => void;
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
}

const DriverDashboard: React.FC<DriverDashboardProps> = ({ driver, rides, allUsers, platformCommission, onUpdateStatus, onRateRide, onSendMessage }) => {
  const [isOnline, setIsOnline] = useState(driver.isOnline || false);
  const [rideToAccept, setRideToAccept] = useState<Ride | null>(null);
  const [activeTab, setActiveTab] = useState<'status' | 'earnings'>('status');
  const [isChatOpen, setIsChatOpen] = useState(false);

  // Simulação de posição do motorista (para o mapa)
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number }>({ lat: -23.5505, lng: -46.6333 });

  const pendingRides = rides.filter(r => 
    r.status === RideStatus.REQUESTED && 
    r.vehicleTypeRequested === driver.vehicleType
  );

  const myActiveRide = rides.find(r => r.driverId === driver.id && r.status !== RideStatus.COMPLETED && r.status !== RideStatus.CANCELLED);

  const riderInfo = useMemo(() => {
    if (!myActiveRide) return { name: 'Passageiro' };
    return allUsers.find(u => u.id === myActiveRide.riderId) || { name: 'Passageiro' };
  }, [myActiveRide, allUsers]);

  const completedRides = useMemo(() => rides.filter(r => r.driverId === driver.id && r.status === RideStatus.COMPLETED), [rides, driver.id]);

  useEffect(() => {
    if (myActiveRide && isOnline) {
      const interval = setInterval(() => {
        setDriverPos(prev => {
          const isEnRoute = myActiveRide.status === RideStatus.IN_PROGRESS;
          const target = isEnRoute ? myActiveRide.destination : myActiveRide.origin;
          const step = 0.0001;
          const dLat = target.lat - prev.lat;
          const dLng = target.lng - prev.lng;
          if (Math.abs(dLat) < step && Math.abs(dLng) < step) return prev;
          return { lat: prev.lat + (dLat > 0 ? step : -step), lng: prev.lng + (dLng > 0 ? step : -step) };
        });
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [myActiveRide?.status, isOnline]);

  const calculateGain = (total: number) => total * (1 - (platformCommission / 100));

  const chartData = useMemo(() => {
    const days = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    const data = days.map(day => ({ name: day, bruto: 0, liquido: 0 }));
    completedRides.forEach(ride => {
      const date = new Date(ride.timestamp);
      data[date.getDay()].bruto += ride.price;
      data[date.getDay()].liquido += calculateGain(ride.price);
    });
    return data;
  }, [completedRides, platformCommission]);

  const stats = useMemo(() => {
    const totalBruto = completedRides.reduce((acc, r) => acc + r.price, 0);
    const totalLiquido = completedRides.reduce((acc, r) => acc + calculateGain(r.price), 0);

    // Cálculos de datas
    const now = new Date();
    const todayStr = now.toDateString();

    // Início da semana (Domingo)
    const weekStart = new Date(now);
    weekStart.setDate(now.getDate() - now.getDay());
    weekStart.setHours(0, 0, 0, 0);

    // Início do mês
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

    const ridesToday = completedRides.filter(r => new Date(r.timestamp).toDateString() === todayStr).length;
    const ridesWeek = completedRides.filter(r => new Date(r.timestamp) >= weekStart).length;
    const ridesMonth = completedRides.filter(r => new Date(r.timestamp) >= monthStart).length;

    return { 
      totalBruto, 
      totalLiquido, 
      totalComissao: totalBruto - totalLiquido,
      ridesToday,
      ridesWeek,
      ridesMonth
    };
  }, [completedRides, platformCommission]);

  const handleConfirmAccept = () => {
    if (rideToAccept) {
      onUpdateStatus(rideToAccept.id, RideStatus.ACCEPTED, driver.id);
      setRideToAccept(null);
    }
  };

  const handleFinishRide = () => {
    if (myActiveRide) {
      onUpdateStatus(myActiveRide.id, RideStatus.COMPLETED, driver.id);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-5xl mx-auto pb-20">
      {myActiveRide && (
        <ChatWidget 
          rideId={myActiveRide.id}
          messages={myActiveRide.messages || []}
          currentUserId={driver.id}
          onSendMessage={onSendMessage}
          otherPartyName={riderInfo.name}
          isOpen={isChatOpen}
          onToggle={setIsChatOpen}
        />
      )}

      {rideToAccept && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-indigo-950/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-up">
            <div className="p-8 text-center bg-indigo-50 border-b border-indigo-100">
              <h4 className="text-xl font-black text-indigo-950">Confirmar Chamada?</h4>
              <p className="text-xs font-bold text-slate-400 uppercase mt-1">Ganhos: R$ {calculateGain(rideToAccept.price).toFixed(2)}</p>
            </div>
            <div className="p-8 space-y-3">
              <button onClick={handleConfirmAccept} className="w-full bg-indigo-950 text-white py-5 rounded-2xl font-black uppercase tracking-widest shadow-xl">ACEITAR</button>
              <button onClick={() => setRideToAccept(null)} className="w-full bg-white text-slate-400 py-4 rounded-2xl font-black uppercase">IGNORAR</button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center space-x-5">
          <div className="w-16 h-16 bg-indigo-50 rounded-[1.5rem] flex items-center justify-center text-indigo-600 shadow-inner">
             <i className={`fas ${driver.vehicleType === VehicleType.MOTORCYCLE ? 'fa-motorcycle' : 'fa-car'} text-2xl`}></i>
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Meus Ganhos</p>
            <h3 className="text-4xl font-black text-indigo-950">R$ {driver.earnings?.toFixed(2)}</h3>
          </div>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-2xl">
          <button onClick={() => setActiveTab('status')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'status' ? 'bg-white text-indigo-950 shadow-sm' : 'text-slate-400'}`}>Status</button>
          <button onClick={() => setActiveTab('earnings')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'earnings' ? 'bg-white text-indigo-950 shadow-sm' : 'text-slate-400'}`}>Finanças</button>
        </div>
        <button onClick={() => setIsOnline(!isOnline)} className={`px-10 py-5 rounded-2xl font-black text-sm uppercase shadow-xl ${isOnline ? 'bg-red-50 text-red-600' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}>
          {isOnline ? 'Ficar Offline' : 'Ficar Online'}
        </button>
      </div>

      {activeTab === 'status' ? (
        <>
          {!isOnline ? (
            <div className="py-24 text-center text-slate-300">
               <i className="fas fa-moon text-6xl mb-4 opacity-20"></i>
               <p className="font-black uppercase tracking-widest">Você está offline</p>
            </div>
          ) : myActiveRide ? (
            <div className="bg-white rounded-[2.5rem] shadow-xl overflow-hidden border border-slate-200 animate-slide-up">
               <div className="p-8 bg-indigo-950 text-white flex justify-between items-center">
                  <div>
                     <p className="text-[10px] font-black uppercase opacity-60">Viagem Atual</p>
                     <h4 className="text-xl font-black">Em curso com {riderInfo.name}</h4>
                  </div>
                  <button onClick={() => setIsChatOpen(true)} className="bg-white/10 hover:bg-white/20 p-4 rounded-2xl relative transition-all active:scale-95">
                    <i className="fas fa-comment-dots mr-2"></i>
                    <span className="text-[10px] font-black uppercase">Chat</span>
                    {(myActiveRide.messages?.length || 0) > 0 && <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full border-2 border-indigo-950 flex items-center justify-center text-[8px] font-black">{myActiveRide.messages?.length}</span>}
                  </button>
               </div>
               <div className="p-8 space-y-6">
                  <div className="h-96 relative">
                    <RealMap 
                      className="h-full" 
                      driverLocation={driverPos}
                      riderLocation={myActiveRide.status === RideStatus.IN_PROGRESS ? undefined : myActiveRide.origin}
                      destinationLocation={myActiveRide.destination}
                      rideStatus={myActiveRide.status}
                      driverInfo={{ name: driver.name, plate: driver.licensePlate }}
                      riderInfo={{ name: riderInfo.name }}
                    />
                  </div>
                  <div className="flex space-x-4">
                    {myActiveRide.status === RideStatus.ACCEPTED && (
                      <button onClick={() => onUpdateStatus(myActiveRide.id, RideStatus.IN_PROGRESS, driver.id)} className="flex-1 bg-indigo-600 text-white py-6 rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all uppercase tracking-widest">INICIAR VIAGEM</button>
                    )}
                    {myActiveRide.status === RideStatus.IN_PROGRESS && (
                      <button onClick={handleFinishRide} className="flex-1 bg-green-600 text-white py-6 rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all uppercase tracking-widest">FINALIZAR VIAGEM</button>
                    )}
                  </div>
               </div>
            </div>
          ) : (
            <div className="space-y-4">
              <h4 className="font-black text-xl text-indigo-950 px-2">Radar de Corridas</h4>
              {pendingRides.length === 0 ? (
                <div className="p-16 text-center bg-white rounded-[2.5rem] border border-slate-200">
                  <p className="text-slate-400 font-bold uppercase text-xs">Aguardando corridas...</p>
                </div>
              ) : (
                pendingRides.map(ride => (
                  <div key={ride.id} className="bg-white p-6 rounded-[2rem] border-2 border-slate-100 flex items-center justify-between hover:border-indigo-600 transition-all">
                    <div>
                       <h3 className="text-2xl font-black text-indigo-600">R$ {calculateGain(ride.price).toFixed(2)}</h3>
                       <p className="text-xs font-bold text-slate-500">{ride.distance} • {ride.destination.address}</p>
                    </div>
                    <button onClick={() => setRideToAccept(ride)} className="bg-indigo-950 text-white px-8 py-4 rounded-xl font-black uppercase text-xs shadow-lg active:scale-95 transition-all">Aceitar</button>
                  </div>
                ))
              )}
            </div>
          )}
        </>
      ) : (
        <div className="space-y-6 animate-slide-up">
          {/* Resumo Financeiro */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-[2rem] border border-slate-200">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Volume Bruto</p>
              <h4 className="text-2xl font-black">R$ {stats.totalBruto.toFixed(2)}</h4>
            </div>
            <div className="bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100">
              <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-1">Taxa Sistema</p>
              <h4 className="text-2xl font-black text-indigo-600">- R$ {stats.totalComissao.toFixed(2)}</h4>
            </div>
            <div className="bg-green-50 p-6 rounded-[2rem] border border-green-100">
              <p className="text-[10px] font-black text-green-600 uppercase tracking-widest mb-1">Líquido</p>
              <h4 className="text-2xl font-black text-green-600">R$ {stats.totalLiquido.toFixed(2)}</h4>
            </div>
          </div>

          {/* Resumo de Atividade (Nova seção solicitada) */}
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200">
            <h4 className="font-black text-indigo-950 uppercase text-xs tracking-widest mb-6">Frequência de Viagens</h4>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <div className="bg-slate-50 p-6 rounded-2xl flex flex-col items-center text-center">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Hoje</span>
                <span className="text-4xl font-black text-indigo-950">{stats.ridesToday}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase mt-1">viagens</span>
              </div>
              <div className="bg-slate-50 p-6 rounded-2xl flex flex-col items-center text-center">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Esta Semana</span>
                <span className="text-4xl font-black text-indigo-950">{stats.ridesWeek}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase mt-1">viagens</span>
              </div>
              <div className="bg-slate-50 p-6 rounded-2xl flex flex-col items-center text-center">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Este Mês</span>
                <span className="text-4xl font-black text-indigo-950">{stats.ridesMonth}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase mt-1">viagens</span>
              </div>
            </div>
          </div>

          <div className="h-[300px] w-full bg-white p-8 rounded-[2.5rem] border border-slate-200">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: '#94a3b8' }} />
                <Tooltip />
                <Bar dataKey="liquido" fill="#4f46e5" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}
    </div>
  );
};

export default DriverDashboard;

export enum UserRole {
  ADMIN = 'ADMIN',
  DRIVER = 'DRIVER',
  RIDER = 'RIDER'
}

export enum VehicleType {
  CAR = 'CAR',
  MOTORCYCLE = 'MOTORCYCLE'
}

export enum RideStatus {
  REQUESTED = 'REQUESTED',
  ACCEPTED = 'ACCEPTED',
  PICKUP = 'PICKUP',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum PaymentMethod {
  CARD = 'CARD',
  PIX = 'PIX',
  CASH = 'CASH',
  PREPAID = 'PREPAID'
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: string;
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  phone: string; // Novo campo obrigatório
  role: UserRole;
  avatar: string;
  walletBalance?: number;
  // Driver specific
  licensePlate?: string;
  vehicleModel?: string;
  vehicleType?: VehicleType;
  rating?: number;
  earnings?: number;
  isOnline?: boolean;
}

export interface Location {
  lat: number;
  lng: number;
  address: string;
}

export interface Ride {
  id: string;
  riderId: string;
  driverId?: string;
  origin: Location;
  destination: Location;
  status: RideStatus;
  price: number;
  paymentMethod: PaymentMethod;
  vehicleTypeRequested: VehicleType;
  timestamp: string;
  distance: string;
  ratingToDriver?: number;
  ratingToRider?: number;
  messages?: ChatMessage[];
}

export interface PricingRule {
  id: string;
  regionName: string; // Ex: "Centro", "Bairro X"
  basePrice: number;  // Valor da bandeirada
  pricePerKm: number; // Valor por KM rodado
  active: boolean;
}

export interface PaymentSettings {
  apiKey: string;
  provider: 'Stripe' | 'MercadoPago' | 'PayPal';
  platformCommission: number; // Porcentagem
