                      <td className="px-6 py-4 text-center font-black text-slate-500">{df.totalRides}</td>
                      <td className="px-6 py-4 font-bold text-slate-600">R$ {df.totalBruto.toFixed(2)}</td>
                      <td className="px-6 py-4">
