import React, { useState, useCallback, useMemo } from 'react';
import { UserRole, UserProfile, Ride, RideStatus, PaymentMethod, PaymentSettings, ChatMessage, PricingRule, VehicleType } from './types';
import Login from './pages/Login';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import DriverDashboard from './pages/DriverDashboard';
import RiderDashboard from './pages/RiderDashboard';
import Layout from './components/Layout';

// Fixed: Added missing required 'phone' property
const MOCK_DRIVERS: UserProfile[] = [
  { id: 'd1', name: 'Carlos Silva', email: 'carlos@uber.com', phone: '(11) 98888-7777', role: UserRole.DRIVER, avatar: 'https://picsum.photos/seed/d1/200', licensePlate: 'ABC-1234', vehicleModel: 'Toyota Corolla', earnings: 1250.80, rating: 4.8, isOnline: true, vehicleType: VehicleType.CAR },
];

const DEFAULT_PRICING: PricingRule[] = [
  { id: 'default', regionName: 'Geral (Padrão)', basePrice: 5.00, pricePerKm: 2.50, active: true },
  { id: 'center', regionName: 'Centro Histórico', basePrice: 8.00, pricePerKm: 3.50, active: true },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isAdminPortal, setIsAdminPortal] = useState(false);
  const [activeTab, setActiveTab] = useState<string>('home'); // 'home', 'history', 'wallet', 'settings'
  const [users, setUsers] = useState<UserProfile[]>(() => {
    // Fixed: Added missing required 'phone' property to initial rider data
    return [...MOCK_DRIVERS, { id: 'r1', name: 'João Paulo', email: 'joao@user.com', phone: '(11) 99999-8888', role: UserRole.RIDER, avatar: 'https://picsum.photos/seed/r1/200', walletBalance: 150.00 }];
  });
  const [rides, setRides] = useState<Ride[]>([]);
  const [paymentSettings, setPaymentSettings] = useState<PaymentSettings>({
    apiKey: '', 
    provider: 'Stripe',
    platformCommission: 15,
    pricingRules: DEFAULT_PRICING
  });

  const handleRequestRide = useCallback((rideData: Omit<Ride, 'id' | 'status' | 'timestamp'>) => {
    const newRide: Ride = {
      ...rideData,
      id: `ride-${Date.now()}`,
      status: RideStatus.REQUESTED,
      timestamp: new Date().toISOString(),
      messages: []
    };
    setRides(prev => [newRide, ...prev]);
  }, []);

  const handleSendMessage = useCallback((rideId: string, text: string) => {
    if (!currentUser) return;
    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      senderId: currentUser.id,
      text,
      timestamp: new Date().toISOString()
    };
    setRides(prev => prev.map(ride => 
      ride.id === rideId ? { ...ride, messages: [...(ride.messages || []), newMessage] } : ride
    ));
  }, [currentUser]);

  const handleUpdateRideStatus = useCallback((rideId: string, newStatus: RideStatus, driverId?: string) => {
    setRides(prevRides => {
      const rideIndex = prevRides.findIndex(r => r.id === rideId);
      if (rideIndex === -1) return prevRides;

      const updatedRides = [...prevRides];
      const targetRide = { 
        ...updatedRides[rideIndex], 
        status: newStatus, 
        driverId: driverId || updatedRides[rideIndex].driverId 
      };
      updatedRides[rideIndex] = targetRide;

      // LÓGICA DE FINALIZAÇÃO E DÉBITO AUTOMÁTICO
      if (newStatus === RideStatus.COMPLETED) {
        const commission = paymentSettings.platformCommission / 100;
        const totalAmount = targetRide.price;
        const driverShare = totalAmount * (1 - commission);

        setUsers(prevUsers => prevUsers.map(user => {
          // Crédito para o Motorista
          if (user.id === targetRide.driverId) {
            return { ...user, earnings: (user.earnings || 0) + driverShare };
          }
          // Débito automático do Passageiro (se for Pre-pago/Duarte Pay)
          if (user.id === targetRide.riderId && targetRide.paymentMethod === PaymentMethod.PREPAID) {
            const currentBalance = user.walletBalance || 0;
            return { ...user, walletBalance: currentBalance - totalAmount };
          }
          return user;
        }));
      }

      return updatedRides;
    });
  }, [paymentSettings.platformCommission]);

  const handleRateRide = useCallback((rideId: string, rating: number, role: UserRole) => {
    setRides(prev => prev.map(ride => {
      if (ride.id === rideId) {
        return role === UserRole.RIDER 
          ? { ...ride, ratingToDriver: rating } 
          : { ...ride, ratingToRider: rating };
      }
      return ride;
    }));
  }, []);

  const handleUpdateBalance = useCallback((userId: string, amount: number) => {
    setUsers(prev => prev.map(u => 
      u.id === userId ? { ...u, walletBalance: (u.walletBalance || 0) + amount } : u
    ));
  }, []);

  const handleUpdateUser = useCallback((userId: string, updates: Partial<UserProfile>) => {
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, ...updates } : u));
  }, []);

  const handleDeleteUser = useCallback((userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
  }, []);

  const handleRegister = useCallback((userData: Partial<UserProfile>) => {
    const newUser: UserProfile = {
      id: `u-${Date.now()}`,
      name: userData.name || 'Novo Usuário',
      email: userData.email || '',
      phone: userData.phone || '', // Ensure phone is captured
      role: userData.role || UserRole.RIDER,
      avatar: `https://picsum.photos/seed/${Date.now()}/200`,
      walletBalance: 0,
      ...userData
    } as UserProfile;
    setUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAdminPortal(false);
    setActiveTab('home');
  };

  const driverRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.DRIVER) return [];
    return rides.filter(r => r.status === RideStatus.REQUESTED || r.driverId === currentUser.id);
  }, [rides, currentUser]);

  const riderRides = useMemo(() => {
    if (!currentUser || currentUser.role !== UserRole.RIDER) return [];
    return rides.filter(r => r.riderId === currentUser.id);
  }, [rides, currentUser]);

  const availableDrivers = useMemo(() => 
    users.filter(u => u.role === UserRole.DRIVER && u.isOnline), 
    [users]
  );

  const currentUserWithLatestData = useMemo(() => {
    if (!currentUser) return null;
    return users.find(u => u.id === currentUser.id) || currentUser;
  }, [users, currentUser]);

  if (!currentUserWithLatestData) {
    if (isAdminPortal) {
      return <AdminLogin onLogin={setCurrentUser} onBackToPublic={() => setIsAdminPortal(false)} />;
    }
    return <Login onLogin={setCurrentUser} onRegister={handleRegister} onGoToAdmin={() => setIsAdminPortal(true)} />;
  }

  return (
    <Layout user={currentUserWithLatestData} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      {currentUserWithLatestData.role === UserRole.ADMIN && (
        <AdminDashboard 
          users={users} 
          rides={rides} 
          paymentSettings={paymentSettings}
          onUpdateSettings={setPaymentSettings}
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser}
        />
      )}

      {currentUserWithLatestData.role === UserRole.DRIVER && (
        <DriverDashboard 
          driver={currentUserWithLatestData} 
          rides={driverRides} 
          allUsers={users}
          platformCommission={paymentSettings.platformCommission}
          onUpdateStatus={handleUpdateRideStatus}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
        />
      )}

      {currentUserWithLatestData.role === UserRole.RIDER && (
        <RiderDashboard 
          rider={currentUserWithLatestData} 
          rides={riderRides} 
          onRequestRide={handleRequestRide}
          onUpdateStatus={handleUpdateRideStatus}
          availableDrivers={availableDrivers}
          allUsers={users}
          onRateRide={handleRateRide}
          onSendMessage={handleSendMessage}
          onUpdateBalance={handleUpdateBalance}
          paymentSettings={paymentSettings}
          externalActiveTab={activeTab}
          onTabChange={setActiveTab}
        />
      )}
    </Layout>
  );
};

export default App;

import { PaymentSettings } from '../types';

export interface PaymentResponse {
  success: boolean;
  transactionId?: string;
  errorMessage?: string;
}

/**
 * Simula a integração com Gateways de Pagamento Reais.
 * Em um ambiente de produção, estas funções fariam chamadas fetch/axios para o backend.
 */
export const processExternalPayment = async (
  amount: number, 
  settings: PaymentSettings
): Promise<PaymentResponse> => {
  // Simula latência de rede
  await new Promise(resolve => setTimeout(resolve, 2500));

  // Validação de segurança solicitada: Se a chave estiver ausente ou for "erro", simula falha
  if (!settings.apiKey || settings.apiKey === 'erro') {
    return {
      success: false,
      errorMessage: "Requested entity was not found. Verifique suas configurações de API no painel Admin."
    };
  }

  // Lógica específica por provedor (Simulação de Fluxo de API)
  switch (settings.provider) {
    case 'Stripe':
      console.log(`[Stripe API] Criando PaymentIntent de R$${amount} usando chave ${settings.apiKey.substring(0, 8)}...`);
      break;
    case 'MercadoPago':
      console.log(`[MercadoPago API] Gerando preferência de pagamento com Access Token...`);
      break;
    case 'PayPal':
      console.log(`[PayPal API] Autenticando ClientID para checkout express...`);
      break;
  }

  return {
    success: true,
    transactionId: `TXN-${Math.random().toString(36).substring(2, 11).toUpperCase()}`
  };
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, Ride, RideStatus, UserRole, PaymentMethod, PaymentSettings, VehicleType } from '../types';
import RealMap from '../components/RealMap';
import ChatWidget from '../components/ChatWidget';
import { processExternalPayment } from '../services/paymentService';

interface RiderDashboardProps {
  rider: UserProfile;
  rides: Ride[];
  onRequestRide: (ride: Omit<Ride, 'id' | 'status' | 'timestamp'>) => void;
  onUpdateStatus: (rideId: string, status: RideStatus) => void;
  availableDrivers: UserProfile[];
  allUsers: UserProfile[];
  onRateRide: (rideId: string, rating: number, role: UserRole) => void;
  onSendMessage: (rideId: string, text: string) => void;
  onUpdateBalance: (userId: string, amount: number) => void;
  paymentSettings: PaymentSettings;
  externalActiveTab?: string;
  onTabChange?: (tab: string) => void;
}

const RiderDashboard: React.FC<RiderDashboardProps> = ({ 
  rider, rides, onRequestRide, onUpdateStatus, availableDrivers, allUsers, onRateRide, onSendMessage, onUpdateBalance, paymentSettings,
  externalActiveTab, onTabChange
}) => {
  const [internalView, setInternalView] = useState<'home' | 'history' | 'wallet'>('home');
  const [destination, setDestination] = useState('');
  const [origin] = useState('Minha Localização');
  const [selectedService, setSelectedService] = useState<'UberX' | 'UberComfort' | 'UberBlack'>('UberX');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod>(PaymentMethod.CARD);
  const [isAddingFunds, setIsAddingFunds] = useState(false);
  const [topUpAmount, setTopUpAmount] = useState<string>('');
  const [isProcessingDeposit, setIsProcessingDeposit] = useState(false);
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [isChatOpen, setIsChatOpen] = useState(false);

  const [userPos, setUserPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const [driverPos, setDriverPos] = useState<{ lat: number, lng: number } | undefined>(undefined);
  const watchIdRef = useRef<number | null>(null);

  const isPaymentConfigured = !!paymentSettings.apiKey;

  const currentView = (externalActiveTab === 'history' || externalActiveTab === 'wallet' || externalActiveTab === 'home') 
    ? externalActiveTab 
    : internalView;

  const setView = (v: 'home' | 'history' | 'wallet') => {
    if (onTabChange) onTabChange(v);
    else setInternalView(v);
  };

  const activeRide = rides.find(r => 
    r.riderId === rider.id && 
    r.status !== RideStatus.COMPLETED && 
    r.status !== RideStatus.CANCELLED
  );

  const completedRides = rides.filter(r => r.riderId === rider.id && r.status === RideStatus.COMPLETED);

  useEffect(() => {
    if ("geolocation" in navigator) {
      watchIdRef.current = navigator.geolocation.watchPosition(
        (position) => setUserPos({ lat: position.coords.latitude, lng: position.coords.longitude }),
        (error) => console.error("Error getting location", error),
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, []);

  const pricingData = useMemo(() => {
    const rules = paymentSettings.pricingRules;
    const destLower = destination.toLowerCase();
    let activeRule = rules.find(r => destLower.includes(r.regionName.toLowerCase())) || rules.find(r => r.id === 'default');
    if (!activeRule) activeRule = { id: 'fallback', regionName: 'Padrão', basePrice: 5, pricePerKm: 2, active: true };
    const estimatedDistKm = 4.8;
    const calculateForService = (service: 'UberX' | 'UberComfort' | 'UberBlack') => {
      const multipliers = { UberX: 1.0, UberComfort: 1.3, UberBlack: 1.8 };
      return (activeRule!.basePrice + (activeRule!.pricePerKm * estimatedDistKm)) * multipliers[service];
    };
    return { ruleName: activeRule.regionName, prices: { UberX: calculateForService('UberX'), UberComfort: calculateForService('UberComfort'), UberBlack: calculateForService('UberBlack') } };
  }, [destination, paymentSettings.pricingRules]);

  const currentPrice = pricingData.prices[selectedService];

  const handleDeposit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(topUpAmount);
    if (isNaN(amount) || amount <= 0) return;

    setCheckoutStatus('processing');
    setErrorMessage('');

    const response = await processExternalPayment(amount, paymentSettings);

    if (response.success) {
      setCheckoutStatus('success');
      setTimeout(() => {
        onUpdateBalance(rider.id, amount);
        setIsAddingFunds(false);
        setCheckoutStatus('idle');
        setTopUpAmount('');
      }, 2000);
    } else {
      setCheckoutStatus('error');
      setErrorMessage(response.errorMessage || 'Falha ao processar pagamento.');
    }
  };

  const findDriverInfo = (driverId?: string) => {
    return allUsers.find(d => d.id === driverId) || { name: 'Motorista', licensePlate: 'ABC-1234', avatar: 'https://picsum.photos/seed/driver/200' };
  };

  const getProviderIcon = () => {
    switch (paymentSettings.provider) {
      case 'Stripe': return 'fa-brands fa-stripe';
      case 'MercadoPago': return 'fa-handshake';
      case 'PayPal': return 'fa-brands fa-paypal';
      default: return 'fa-credit-card';
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in pb-12">
      {/* Recarga Modal com Integração de API */}
      {isAddingFunds && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-xl">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 animate-scale-up shadow-[0_0_100px_rgba(79,70,229,0.2)]">
             <div className="text-center mb-8">
                <div className="w-16 h-16 bg-indigo-50 rounded-3xl mx-auto flex items-center justify-center text-indigo-600 mb-4">
                   <i className={`fas ${getProviderIcon()} text-2xl`}></i>
                </div>
                <h3 className="text-xl font-black text-indigo-950 uppercase tracking-tight">Checkout {paymentSettings.provider}</h3>
                <p className="text-slate-400 text-xs font-bold uppercase mt-1">Duarte Pay Digital</p>
             </div>

             {checkoutStatus === 'idle' && (
               <form onSubmit={handleDeposit} className="space-y-6">
                 <div className="relative">
                   <span className="absolute left-6 top-1/2 -translate-y-1/2 font-black text-slate-300">R$</span>
                   <input required type="number" step="0.01" value={topUpAmount} onChange={e => setTopUpAmount(e.target.value)} placeholder="0,00" className="w-full pl-14 pr-6 py-5 bg-slate-50 rounded-2xl font-black text-2xl focus:border-indigo-600 outline-none border-2 border-transparent transition-all" />
                 </div>
                 <button type="submit" className="w-full py-5 bg-indigo-950 text-white rounded-2xl font-black shadow-xl hover:bg-indigo-900 transition-all flex items-center justify-center space-x-3">
                   <span>PAGAR AGORA</span>
                   <i className="fas fa-arrow-right text-xs opacity-50"></i>
                 </button>
                 <button type="button" onClick={() => setIsAddingFunds(false)} className="w-full text-slate-400 font-bold text-[10px] uppercase tracking-widest">CANCELAR</button>
               </form>
             )}

             {checkoutStatus === 'processing' && (
               <div className="py-10 text-center space-y-6 animate-pulse">
                 <div className="relative w-20 h-20 mx-auto">
                    <div className="absolute inset-0 border-4 border-indigo-100 rounded-full"></div>
                    <div className="absolute inset-0 border-4 border-indigo-600 rounded-full border-t-transparent animate-spin"></div>
                 </div>
                 <div>
                    <p className="text-sm font-black text-indigo-950 uppercase">Processando Transação</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Conectando ao gateway {paymentSettings.provider}...</p>
                 </div>
               </div>
             )}

             {checkoutStatus === 'success' && (
               <div className="py-10 text-center space-y-6 animate-scale-up">
                 <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full mx-auto flex items-center justify-center text-3xl">
                    <i className="fas fa-check"></i>
                 </div>
                 <div>
                    <h4 className="text-xl font-black text-indigo-950">Pagamento Aprovado!</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Seu saldo será atualizado em instantes.</p>
