             )}

             {checkoutStatus === 'error' && (
               <div className="py-10 text-center space-y-6 animate-fade-in">
                 <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full mx-auto flex items-center justify-center text-3xl">
