           <div className="space-y-4">
              <input placeholder="Informe o destino" value={destination} onChange={e => setDestination(e.target.value)} className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-lg focus:border-indigo-600 outline-none" />
              {destination && (
                <button onClick={() => onRequestRide({
                  riderId: rider.id,
                  origin: { lat: -23.5505, lng: -46.6333, address: origin },
                  destination: { lat: -23.56, lng: -46.64, address: destination },
                  price: pricingData.prices[selectedService],
                  paymentMethod: selectedPayment,
                  vehicleTypeRequested: VehicleType.CAR,
                  distance: '4.8 km'
                })} className="w-full bg-indigo-950 text-white py-6 rounded-[2rem] font-black text-xl">PEDIR VIAGEM</button>
              )}
           </div>
        </div>
      )}
    </div>
  );
